-- Poems batch 359
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('1a51851c-adec-4b56-bcdf-ea69531fe09b','注十明論','釋德洪','宋','宋诗','song-poetry','','[]','了知無性滅無明，空慧須從戒定生。',32,'全唐诗/poet.song.76000.json','["了知無性滅無明，空慧須從戒定生。", "頻呼小玉元無意，只要檀郎認得聲。"]'),
('25efee91-4f64-49e9-823f-9f4600052090','汾陽十智同真二首  其一','釋德洪','宋','宋诗','song-poetry','','[]','十智同真面目全，於中一智是根源。',32,'全唐诗/poet.song.76000.json','["十智同真面目全，於中一智是根源。", "如今要見汾陽老，劈破三玄作兩邊。"]'),
('c2a26ff9-26d2-4c06-82e5-9c3e7ef13bde','汾陽十智同真二首  其二','釋德洪','宋','宋诗','song-poetry','','[]','十智同真選佛科，汾陽佛法本無多。',32,'全唐诗/poet.song.76000.json','["十智同真選佛科，汾陽佛法本無多。", "愛心竭處尋真智，面目分明會也麽。"]'),
('1c6ba582-3207-4a62-8fae-a0a16d88d421','袁州聞東坡歿於毗陵書精進寺壁三首  其一','釋德洪','宋','宋诗','song-poetry','','[]','濁世肯留竟何意，玉芙蓉出淤泥中。',32,'全唐诗/poet.song.76000.json','["濁世肯留竟何意，玉芙蓉出淤泥中。", "誰謂秋来亦零落，病收衰淚泣西風。"]'),
('0134e48e-8c93-4185-ada5-1bcf7ca1ef76','袁州聞東坡歿於毗陵書精進寺壁三首  其二','釋德洪','宋','宋诗','song-poetry','','[]','姓名自可磨千古，文字收藏付六丁。',32,'全唐诗/poet.song.76000.json','["姓名自可磨千古，文字收藏付六丁。", "唾霧珠消君勿笑，夢回比物鎮長靈。"]'),
('af205292-c048-4908-9f70-d4b98dbfee26','袁州聞東坡歿於毗陵書精進寺壁三首  其三','釋德洪','宋','宋诗','song-poetry','','[]','才疏意廣孔文舉，身健長貧白樂天。',32,'全唐诗/poet.song.76000.json','["才疏意廣孔文舉，身健長貧白樂天。", "一代風流今已矣，三吴雲水固悠然。"]'),
('31c38647-0631-491c-ab95-2de83a3a9021','無盡居士以峡州天寧見邀作此辭免六首  其一','釋德洪','宋','宋诗','song-poetry','','[]','吹毛用了急須磨，鐵脊師兄舌太多。',32,'全唐诗/poet.song.76000.json','["吹毛用了急須磨，鐵脊師兄舌太多。", "祖佛命根俱截斷，笑中驚倒老維摩。"]'),
('95b930e4-27ef-45a0-809f-a2a76c3c2d94','無盡居士以峡州天寧見邀作此辭免六首  其二','釋德洪','宋','宋诗','song-poetry','','[]','維摩願力元無盡，重見真州宰輔身。',32,'全唐诗/poet.song.76000.json','["維摩願力元無盡，重見真州宰輔身。", "舌本雷槌烹佛祖，筆端和氣活生民。"]'),
('ea7152a2-5ddb-4d04-a81b-7cd68fc1b5f6','無盡居士以峡州天寧見邀作此辭免六首  其三','釋德洪','宋','宋诗','song-poetry','','[]','四夷八蠻想風采，竈婦乳兒知姓名。',32,'全唐诗/poet.song.76000.json','["四夷八蠻想風采，竈婦乳兒知姓名。", "寄語袖中調鼎手，未容扶杖獨經行。"]'),
('8bb5dd82-05ed-4928-bd56-ada9494d5eb3','無盡居士以峡州天寧見邀作此辭免六首  其四','釋德洪','宋','宋诗','song-poetry','','[]','五達衢頭梵刹新，著書来喚住山人。',32,'全唐诗/poet.song.76000.json','["五達衢頭梵刹新，著書来喚住山人。", "折松慣掃和雲石，披衲難随沒馬塵。"]'),
('396557c1-9183-4453-91d9-257c54c7d7d0','無盡居士以峡州天寧見邀作此辭免六首  其五','釋德洪','宋','宋诗','song-poetry','','[]','亦欲便随流水出，重惟我法付王臣。',32,'全唐诗/poet.song.76000.json','["亦欲便随流水出，重惟我法付王臣。", "回看坐睡横眠處，折脚鐺兒解笑人。"]'),
('d1b146b0-78b9-47f1-9bec-1e6fb95fa73d','無盡居士以峡州天寧見邀作此辭免六首  其六','釋德洪','宋','宋诗','song-poetry','','[]','龜毛索子衲僧冤，闊角關西亦被穿。',32,'全唐诗/poet.song.76000.json','["龜毛索子衲僧冤，闊角關西亦被穿。", "小犢鼻頭無覓處，聽渠露地且閑眠。"]'),
('6744c623-3a2a-4b8b-af62-e9e38cba24bc','初到善谿慧照菴寄張無盡五首  其一','釋德洪','宋','宋诗','song-poetry','','["\u897f\u6e56"]','明月洲頭一笛風，暮雲滅盡水吞空。',32,'全唐诗/poet.song.76000.json','["明月洲頭一笛風，暮雲滅盡水吞空。", "倚筇笑語無人問，疑是西湖落夢中。"]'),
('a2fb48ab-eb0f-4465-80d3-cb9e38a4dcde','初到善谿慧照菴寄張無盡五首  其二','釋德洪','宋','宋诗','song-poetry','','[]','山勒回流作窟盤，翠蘿綰带結鴛鸞。',32,'全唐诗/poet.song.76000.json','["山勒回流作窟盤，翠蘿綰带結鴛鸞。", "故應此境幽難畫，乞與菴僧自在看。"]'),
('8be417d9-b914-433a-8dbb-7f6f81c4b5e9','初到善谿慧照菴寄張無盡五首  其三','釋德洪','宋','宋诗','song-poetry','','[]','形勝迥分千里遠，地靈還受衆峰朝。',32,'全唐诗/poet.song.76000.json','["形勝迥分千里遠，地靈還受衆峰朝。", "從来慶澤流無盡，異事先看繼八蕭。"]'),
('7effa65f-44f8-40cb-9b16-eeb435eb31c7','初到善谿慧照菴寄張無盡五首  其四','釋德洪','宋','宋诗','song-poetry','','[]','世辯不妨無骨舌，好山難絆自由身。',32,'全唐诗/poet.song.76000.json','["世辯不妨無骨舌，好山難絆自由身。", "從教折脚鐺兒笑，且欲南来識鳳麟。"]'),
('35546f8a-7bd5-422c-b615-544fd629decd','初到善谿慧照菴寄張無盡五首  其五','釋德洪','宋','宋诗','song-poetry','','[]','公有自然台輔望，與民同樂亦同憂。',32,'全唐诗/poet.song.76000.json','["公有自然台輔望，與民同樂亦同憂。", "我慚雅思非支遁，亦伴東山爛熳游。"]'),
('1c66ed0e-92fd-447d-ac5f-7b213e56b5ef','無盡見和復次其韻五首  其一','釋德洪','宋','宋诗','song-poetry','','[]','謾說毗耶問疾風，主賓信手畫虚空。',32,'全唐诗/poet.song.76000.json','["謾說毗耶問疾風，主賓信手畫虚空。", "争如快活月洲老，萬事收藏一笑中。"]'),
('f9ce0d82-e324-412d-bbcd-4886143dc738','無盡見和復次其韻五首  其二','釋德洪','宋','宋诗','song-poetry','','[]','窗外雲閒如去鶴，門前山好似翔鸞。',32,'全唐诗/poet.song.76000.json','["窗外雲閒如去鶴，門前山好似翔鸞。", "此時更有疑情在，試借疑情面目看。"]'),
('b175523d-00bf-423d-9968-df92f9d252c2','無盡見和復次其韻五首  其三','釋德洪','宋','宋诗','song-poetry','','[]','一丘一壑思迢迢，莫把山林較市朝。',32,'全唐诗/poet.song.76000.json','["一丘一壑思迢迢，莫把山林較市朝。", "江上相逢兩無語，夕陽衰草暮蕭蕭。"]'),
('a02dff86-53e1-405c-a494-bf7a5ea13170','無盡見和復次其韻五首  其四','釋德洪','宋','宋诗','song-poetry','','[]','公是睡龍今縮首，我如江月且分身。',32,'全唐诗/poet.song.76000.json','["公是睡龍今縮首，我如江月且分身。", "人間一戲成何事，塚外君看半卧麟。"]'),
('fad00f06-08c5-49a8-949c-2e738cd06a63','無盡見和復次其韻五首  其五','釋德洪','宋','宋诗','song-poetry','','[]','雖然無證復無修，撲破虚空亦可憂。',32,'全唐诗/poet.song.76000.json','["雖然無證復無修，撲破虚空亦可憂。", "欲識老龐端的處，飯餘摩腹且閒游。"]'),
('6d70a21d-50b3-4701-a614-9411b9023672','又次韻答之十首  其一','釋德洪','宋','宋诗','song-poetry','','[]','金篦抉膜去重重，露出當時晦昧空。',32,'全唐诗/poet.song.76000.json','["金篦抉膜去重重，露出當時晦昧空。", "撥轉上頭關棙子，莫教更墮有無中。"]'),
('6bb8d33c-a2f6-4fa8-8b93-80aea061b3f0','又次韻答之十首  其二','釋德洪','宋','宋诗','song-poetry','','[]','晚来妙語逼人寒，逸氣翩翩棲鳳鸞。',32,'全唐诗/poet.song.76000.json','["晚来妙語逼人寒，逸氣翩翩棲鳳鸞。", "珍重平生造物手，十分拈出與人看。"]'),
('56330ddb-8033-4117-bdc8-fa6dfa2570bf','又次韻答之十首  其三','釋德洪','宋','宋诗','song-poetry','','[]','擁衾睡美無人喚，閑憶當年趁早朝。',32,'全唐诗/poet.song.76000.json','["擁衾睡美無人喚，閑憶當年趁早朝。", "今伴赤松聊卒歲，後来功業付曹蕭。"]'),
('dfa8e3be-693c-48f3-8456-b4e45829ca8d','又次韻答之十首  其四','釋德洪','宋','宋诗','song-poetry','','[]','衆生煩惱亂如塵，共現如来智智身。',32,'全唐诗/poet.song.76000.json','["衆生煩惱亂如塵，共現如来智智身。", "自笑露腮狂寶誌，識公天上石麒麟。"]'),
('df805236-4441-487a-9fa2-fcbbd6f6748d','又次韻答之十首  其五','釋德洪','宋','宋诗','song-poetry','','[]','樓閣不勞彈指入，衆魔相顧匆驚憂。',32,'全唐诗/poet.song.76000.json','["樓閣不勞彈指入，衆魔相顧匆驚憂。", "回光却復思初友，從此南詢可罷游。"]'),
('428372a0-7265-4d6b-962e-31c7c63aad76','又次韻答之十首  其六','釋德洪','宋','宋诗','song-poetry','','[]','此法從来妙莫窮，何須癡坐學觀空。',32,'全唐诗/poet.song.76000.json','["此法從来妙莫窮，何須癡坐學觀空。", "劈開結角羅紋處，攝入圓伊三點中。"]'),
('e65eeca1-5adc-4a1d-8ce1-185ae36b9363','又次韻答之十首  其七','釋德洪','宋','宋诗','song-poetry','','[]','法本無差須揀擇，楚雞元不是青鸞。',32,'全唐诗/poet.song.76000.json','["法本無差須揀擇，楚雞元不是青鸞。", "當機一鏃三關破，覿體分明箭後看。"]'),
('2d06702c-06a6-45db-a4f1-334be37a0dea','又次韻答之十首  其八','釋德洪','宋','宋诗','song-poetry','','[]','雲林一塢正寥寥，不把清閒負聖朝。',32,'全唐诗/poet.song.76000.json','["雲林一塢正寥寥，不把清閒負聖朝。", "歲晚追随真可畫，行人明日馬蕭蕭。"]'),
('de3152e4-185f-4040-babd-588dd19858d8','又次韻答之十首  其九','釋德洪','宋','宋诗','song-poetry','','[]','我亦從来徹骨貧，誰知徧界不藏身。',32,'全唐诗/poet.song.76000.json','["我亦從来徹骨貧，誰知徧界不藏身。", "住山鈯斧勞收取，不是青源衆獸麟。"]'),
('20b0fec3-f9af-4c4a-b4c5-2e30b26b9b77','又次韻答之十首  其一○','釋德洪','宋','宋诗','song-poetry','','[]','一笑相看萬事休，公無榮辱我無憂。',32,'全唐诗/poet.song.76000.json','["一笑相看萬事休，公無榮辱我無憂。", "挂名入社非難事，圓寂光中不厭游。"]'),
('57e51e45-f1a7-4d1b-87df-04728eee42ac','孫侯見和復次韻五首  其一','釋德洪','宋','宋诗','song-poetry','','[]','仙郎齒頬嚼松風，吟處晴巒翠倚空。',32,'全唐诗/poet.song.76000.json','["仙郎齒頬嚼松風，吟處晴巒翠倚空。", "佳句興来渾不惜，一時傾出錦囊中。"]'),
('a1b7c789-4424-4e56-a252-18579eeda65d','孫侯見和復次韻五首  其二','釋德洪','宋','宋诗','song-poetry','','[]','我亦聞絃知雅曲，松風聲不類鳴鸞。',32,'全唐诗/poet.song.76000.json','["我亦聞絃知雅曲，松風聲不類鳴鸞。", "相逢意氣須傾寫，一任旁人冷眼看。"]'),
('0177100b-5e4e-4f4b-a32f-11fe5b84c94c','孫侯見和復次韻五首  其三','釋德洪','宋','宋诗','song-poetry','','[]','歷世興亡皆可數，升平不復似今朝。',32,'全唐诗/poet.song.76000.json','["歷世興亡皆可數，升平不復似今朝。", "野居興味應無限，小字明窗拔二蕭。"]'),
('58dadb41-6817-42ec-bdbd-c4b64ee01f82','孫侯見和復次韻五首  其四','釋德洪','宋','宋诗','song-poetry','','[]','未展事功扶聖世，幅巾林下且收身。',32,'全唐诗/poet.song.76000.json','["未展事功扶聖世，幅巾林下且收身。", "善谿廣坐看談笑，駿氣駸駸地上麟。"]'),
('0baa40cb-6a42-4fac-8c79-aa3fce172ea3','孫侯見和復次韻五首  其五','釋德洪','宋','宋诗','song-poetry','','[]','我固浮雲輕俗眼，君真萱草可忘憂。',32,'全唐诗/poet.song.76000.json','["我固浮雲輕俗眼，君真萱草可忘憂。", "婦翁一室藏沙界，興發時来把臂游。"]'),
('09b24fa3-693b-4379-815b-df1196431d84','再和答師復五首  其一','釋德洪','宋','宋诗','song-poetry','','[]','愛君道骨有仙風，人品渾如月在空。',32,'全唐诗/poet.song.76000.json','["愛君道骨有仙風，人品渾如月在空。", "清論不窮霏鋸屑，故應雲夢吐胸中。"]'),
('35da41b4-6a2b-44d8-8f3e-b73a05bd7b21','再和答師復五首  其二','釋德洪','宋','宋诗','song-poetry','','[]','牛渚笑中曾捉月，道山歸去亦乘鸞。',32,'全唐诗/poet.song.76000.json','["牛渚笑中曾捉月，道山歸去亦乘鸞。", "人間尚有餘緣在，又把塵編倒摺看。"]'),
('4b86bd0d-7149-4f3b-be6a-f7b621caa0ca','再和答師復五首  其三','釋德洪','宋','宋诗','song-poetry','','[]','吾道如山欲撼揺，羣兒毀譽漫前朝。',32,'全唐诗/poet.song.76000.json','["吾道如山欲撼揺，羣兒毀譽漫前朝。", "冷看狂罵黄冠奕，却笑辛酸合爪蕭。"]'),
('a22abc27-ad86-4618-aab9-302d09807a36','再和答師復五首  其四','釋德洪','宋','宋诗','song-poetry','','[]','有味新詩名不得，正如仙爪爲爬身。',32,'全唐诗/poet.song.76000.json','["有味新詩名不得，正如仙爪爲爬身。", "此時風味無人會，想見麻姑擗脯麟。"]'),
('37f89fb7-f904-4158-9168-2083d2561d1c','再和答師復五首  其五','釋德洪','宋','宋诗','song-poetry','','[]','八瓊洞口桃花笑，失却塵寰半世憂。',32,'全唐诗/poet.song.76000.json','["八瓊洞口桃花笑，失却塵寰半世憂。", "聞道客亭炊未熟，坐看凍蟻夢中游。"]'),
('1d911ae1-7ef1-49be-81bf-b72082cb9fb2','天覺以雲菴畫像見寄謝之','釋德洪','宋','宋诗','song-poetry','','[]','老師面目無尋處，藏在毗耶文室中。',32,'全唐诗/poet.song.76000.json','["老師面目無尋處，藏在毗耶文室中。", "乞與盤山狂弟子，背抛筋斗撒顛風。"]'),
('d5cb672f-d8b6-4d37-823d-a3acc47181a6','次天覺韻二首  其一','釋德洪','宋','宋诗','song-poetry','','[]','欲振雲菴出格風，直教魔界化成空。',32,'全唐诗/poet.song.76000.json','["欲振雲菴出格風，直教魔界化成空。", "此邦已属張無盡，二佛難同一化中。"]'),
('7fcb9143-a7b7-4990-861b-34cc4cf80d78','次天覺韻二首  其二','釋德洪','宋','宋诗','song-poetry','','[]','百千萬億恒沙佛，正眼觀来縂是空。',32,'全唐诗/poet.song.76000.json','["百千萬億恒沙佛，正眼觀来縂是空。", "縱有毗耶方丈子，爲渠權置睫眉中。"]'),
