('3b7b56d2-59d7-4781-bec6-4c696d752c11','廬山雜興六首  其五','釋德洪','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','白水連空不見村，冥冥細雨濕黄昏。',32,'全唐诗/poet.song.76000.json','["白水連空不見村，冥冥細雨濕黄昏。", "秋山咫尺無由到，須信關人不用門。"]'),
('7daee477-7e5d-4beb-a8d9-f23506849bf5','廬山雜興六首  其六','釋德洪','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','秋山木落見遥村，取次人家只隔雲。',32,'全唐诗/poet.song.76000.json','["秋山木落見遥村，取次人家只隔雲。", "一陣西風雨中過，數聲笑語嶺頭聞。"]'),
('35aac166-f082-4f35-81f3-589b00330b50','道中二首  其一','釋德洪','宋','宋诗','song-poetry','','[]','蒲柳冥冥花已殘，水田南北是青山。',32,'全唐诗/poet.song.76000.json','["蒲柳冥冥花已殘，水田南北是青山。", "晚村歸路聞啼鳥，家住寒雲縹緲間。"]'),
('5e71db6d-c659-4c07-9d80-dedf290445b1','道中二首  其二','釋德洪','宋','宋诗','song-poetry','','[]','元石無塵處處青，一谿花照碧天晴。',32,'全唐诗/poet.song.76000.json','["元石無塵處處青，一谿花照碧天晴。", "山雲亂却来時路，雞犬惟聞洞口聲。"]'),
('c519df0d-4ff3-4f89-adab-f3b4a0299d03','奉要勝軒居實居士三首  其一','釋德洪','宋','宋诗','song-poetry','','[]','漠漠煙雲映碧流，暖風晴日動鳴鳩。',32,'全唐诗/poet.song.76000.json','["漠漠煙雲映碧流，暖風晴日動鳴鳩。", "何當綠葉楓林下，杖屨相追結勝遊。"]'),
('73a4acd8-9791-4ca4-9eea-5d3868fa7243','奉要勝軒居實居士三首  其二','釋德洪','宋','宋诗','song-poetry','','[]','出御未聞歸北闕，角巾長念入西臺。',32,'全唐诗/poet.song.76000.json','["出御未聞歸北闕，角巾長念入西臺。", "林間三月花猶在，第恐春風作惡来。"]'),
('a17d71c8-218e-49bc-9c41-b7563109dc32','奉要勝軒居實居士三首  其三','釋德洪','宋','宋诗','song-poetry','','[]','柘岡陰滿雨初晴，野逕無人獨自行。',32,'全唐诗/poet.song.76000.json','["柘岡陰滿雨初晴，野逕無人獨自行。", "一飯茅齋最瀟灑，香芽如玉待君烹。"]'),
('6dfb8929-3479-4368-b45a-66ebc04c6255','摩陀歌贈乾上人','釋德洪','宋','宋诗','song-poetry','','["\u5e90\u5c71", "\u8861\u5c71"]','處處三門向南開，青山綠水自圍裹。',286,'全唐诗/poet.song.76000.json','["處處三門向南開，青山綠水自圍裹。", "鐘魚鳴時攤鉢盂，精粗随分喫些箇。", "一生受用只如此，何用忙忙脚踏火。", "口閑莫說事，留取吞飯顆。", "眼明穿得針，要自時補破。", "粥後眠一覺，不著溲漲亦不起。", "齋後行數步，不是肚膨也打過。", "我不求世人，世人不求我。", "時時牽衣領，臃腫包頭渦。", "一味怯風吹耳朵，世上許多人。", "枿枿猶如蟻旋磨，團團並頭争什麽。", "一籌輸與摩陀板頭盤脚坐，人言南嶽好。", "奇峰七十朵，廬山更是好。", "瀑布垂天雲，净色不受涴。", "殿閣參差如畫出，萬人圍遶看登坐。", "汝若學道便成佛，汝若不學地獄禍。", "眼看鼻孔也尋常，六月日頭甚熱火。", "一籌輸與摩陀看屋卧，喚渠挽不来，送渠推不可。", "摩陀摩陀，無如之何。", "問著不答，好啞大哥。"]'),
('b821e6cc-3adf-4562-abb7-54cfecea4cfb','讀禪要法','釋德洪','宋','宋诗','song-poetry','','[]','天王如来現于世，文殊思往問法義。',128,'全唐诗/poet.song.76000.json','["天王如来現于世，文殊思往問法義。", "便遭貶向鐵圍山，須臾復攝文殊至。", "文殊拜起依位住，問我此謫坐何過。", "佛言汝自墮艱難，故起現行爲不可。", "佛邊女子名離意，端然入定方七歲。", "又問何以不逐之，佛言此女久無意。", "女以無意逐獲免，十方来衆何不遣。", "如来自在神足禪，有意測之近成遠。"]'),
('bd4df00a-7ad2-49f3-8000-a16c3dea1e1c','送端上人入黄龍','釋德洪','宋','宋诗','song-poetry','','[]','一箇面如楪子大，眼耳鼻舌分疆界。',80,'全唐诗/poet.song.76000.json','["一箇面如楪子大，眼耳鼻舌分疆界。", "髑髏裏面都不言，聽渠外邊争揑怪。", "日用經行坐卧中，一段光明沒遮蓋。", "端上人，會不會，會與不會俱窒礙。", "如見靈源瞌睡翁，石火光中著精彩。"]'),
('5d3482c0-fc1e-41a9-a511-435e9c086a1b','好菩薩','釋德洪','宋','宋诗','song-poetry','','[]','好菩薩，人中来。',80,'全唐诗/poet.song.76000.json','["好菩薩，人中来。", "好菩薩，羊中来。", "女媧弄土飛塵埃，洛陽樓閣非願力。", "衆生業影空崔嵬，苾芻心不在法道，鮮衣美食何爲哉。", "好菩薩，人中来。", "好菩薩，羊中来。", "女媧弄土飛塵埃。"]'),
('e22c1d46-cb20-4beb-a904-108e1bcac42e','慎姪来侍求偈','釋德洪','宋','宋诗','song-poetry','','[]','十方都盧是箇虎，玄沙斫柴見不怖。',96,'全唐诗/poet.song.76000.json','["十方都盧是箇虎，玄沙斫柴見不怖。", "傍却報僧云是汝，言中有響今誰悟。", "華林年少相體解，庵中與之同行住。", "誰會呼作大小空，癡兒見之毛卓竪。", "我居十年無侍者，呼喚應時随指顧。", "有人問著是何宗，萬里無雲霜月苦。"]'),
('07192cd5-62b9-43f2-a5c9-01fb392c5cae','變禪者歸蔣山見佛果乞偈','釋德洪','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','霸陵將軍萬人敵，射虎飲羽馬躃易。',128,'全唐诗/poet.song.76000.json','["霸陵將軍萬人敵，射虎飲羽馬躃易。", "下馬視之輙一笑，寧知虎爲草中石。", "控弦復射又中的，砉然有聲箭不入。", "將軍但知爲石耳，坐令疑虎心相失。", "諸方今誰達此機，蔣山老勤默而識。", "變公心挂蔣山雲，浩然欲歸約不得。", "洞庭青草水粘天，高帆摩空一千尺。", "仰看浪摧碧玉山，此時法界毛端集。"]'),
('df9347c0-97f2-4319-9dfa-d2e14e56cea7','送逸禪者歸荆南見無盡居士','釋德洪','宋','宋诗','song-poetry','','[]','長沙大蟲方肉醉，倚樹痾癢威見尾。',96,'全唐诗/poet.song.76000.json','["長沙大蟲方肉醉，倚樹痾癢威見尾。", "逸禪来展寂子機，舉足欲促適其睡。", "後身荆州張曲江，解鍛佛祖如老龐。", "如聞去作丹霞問，正當一口吸西江。", "西江一口吸得盡，是汝法身應有賸。", "要令川客讀此詩，都作蔣山吞栗硬。"]'),
('99981080-8a6c-4264-ab19-f7c49a226771','警策','釋德洪','宋','宋诗','song-poetry','','[]','汝未辦道業，何能超塵累。',108,'全唐诗/poet.song.76000.json','["汝未辦道業，何能超塵累。", "但觀身精進，則知心猛利。", "日中乃當食，食不敢盡味。", "夜分而後寢，寢不敢熟睡。", "貪入光明想，貪證法明智。", "是名心出家，是名身出世。", "大哉無累神，合此有道器。", "若具所行心，件件俱不是。", "而稱釋氏子，動止是羞愧。"]'),
('31dab7a4-47b0-428f-8a26-ea2b006b9e41','雲菴和尚生辰燒香偈','釋德洪','宋','宋诗','song-poetry','','[]','直心是道無虚假，是牛何曾呼作馬。',96,'全唐诗/poet.song.76000.json','["直心是道無虚假，是牛何曾呼作馬。", "平生日日常一般，但知九旬爲一夏。", "聲色峥嶸争蓋覆，法身散失無尋處。", "因緣時節屬今朝，不用追求全體露。", "七十八年彈指過，元来諸數不曾墮。", "南臺再拜炷爐香，重渠當時不說破。"]'),
('88f5d221-94a3-40e3-b293-a3be79431507','雲菴生日空印設供作偈福嚴南臺萬壽三老與焉次韻','釋德洪','宋','宋诗','song-poetry','','[]','不見叢林老陕西，鐵牛生得石牛兒。',112,'全唐诗/poet.song.76000.json','["不見叢林老陕西，鐵牛生得石牛兒。", "泐潭撲面紅塵起，四海禪流滿地疑。", "溈山作人熱心肺，冷處著火人方知。", "龍山說偈聊戲耳，萬象驚叫天魔悲。", "三生大士視雲漢，和倡四座知爲誰。", "南臺拱讀萬壽笑，生機妙語皆臨時。", "諸方傳誦著精彩，不是龍山唱和詩。"]'),
('6e59f771-dfa5-4b5f-b57d-1e230c1de381','欽禪者乞偈','釋德洪','宋','宋诗','song-poetry','','[]','三世如来所說，開遮或擒或縱。',98,'全唐诗/poet.song.76000.json','["三世如来所說，開遮或擒或縱。", "一切微塵句偈，只明衆生日用。", "譬如一室千燈，其光不雜不共。", "無色天女擊鼓，四大部洲頭痛。", "一切智智清净，開合不成痕縫。", "欽禪一等行脚，莫聽虜子取奉。", "若說有法可傳，但作眼見鼻孔。"]'),
('ab8e5cb8-e878-48e9-88b2-0f61290f2dd7','宣上人天真庵','釋德洪','宋','宋诗','song-poetry','','[]','醉李宣道者，活計太天真。',104,'全唐诗/poet.song.76000.json','["醉李宣道者，活計太天真。", "把茅蓋頭處，只就松樹身。", "樹邊有石兩三塊，便與傾倒爲比鄰。", "眼子崒嵂奇，寂寂亦惺惺。", "却倩松風替說法，而石側耳聽。", "宣公咄云，直饒聽得如器盛水瀉，也是外来之□。", "何如我此横眠坐睡，佛祖一齊喪氣。"]'),
('7e77a8ed-0536-4c1b-8556-64e633f83e8d','題草衣巖','釋德洪','宋','宋诗','song-poetry','','[]','祝融凌寒空，方陟緣雲徑。',72,'全唐诗/poet.song.76000.json','["祝融凌寒空，方陟緣雲徑。", "此山翠被重，有巖如側磬。", "拂石聊枕肱，便覺諸緣静。", "萬瓦粲霜曉，千里增目迥。", "石頭有高弟，衣草却心病。", "千年續燈人，誰接懸絲命。"]'),
('9d7e7afd-88df-41c5-9777-f977806d5045','送先上人親潛菴','釋德洪','宋','宋诗','song-poetry','','[]','潛菴九十一，自是百歲人。',120,'全唐诗/poet.song.76000.json','["潛菴九十一，自是百歲人。", "造物偶遺漏，頓置漳水濱。", "先禪江西来，邈得渠儂真。", "展挂雪色壁，毛髪皆精神。", "三玄合水乳，五位透金塵。", "譬如百衲帔，歲晚思惠新。", "臊僧不肯信，眼肉懸千斤。", "飛兔略燕楚，敏若臂屈伸。", "衲子參活意，擊電飛機輪。", "寧如臊僧徒，蠢蠢粘唾津。"]'),
('368493aa-a14c-49b3-8714-5953e0afc7cc','珪上人兩過吾家既去作此','釋德洪','宋','宋诗','song-poetry','','[]','牛鳴馬不仰，火必就燥地。',72,'全唐诗/poet.song.76000.json','["牛鳴馬不仰，火必就燥地。", "應真隱躭源，寂子一再至。", "至言無緣飾，大道甚簡易。", "三關不却人，見者自擬議。", "法身忽有賸，佛祖俱喪氣。", "君看暮歸人，徑去方掉臂。"]'),
('a6cdaa54-1cd1-4156-89f9-bda60cc0b0d9','送親上人乞食三首  其一','釋德洪','宋','宋诗','song-poetry','','[]','荆簪女，工採桑。',96,'全唐诗/poet.song.76000.json','["荆簪女，工採桑。", "畫鴉女，衣羅紈。", "赤脚人，趁兔鹿。", "著靴人，飽食肉。", "百丈出家不害癡，一日不作一日饑。", "後生十指不點水，得便宜是落便宜。", "親禪學道不檐板，自然公辦私亦辦。", "新年持鉢走衡湘，要令一衆毛孔香。"]'),
('f9ad6899-f3b1-40a8-bafb-4516cb7d60c9','送親上人乞食三首  其二','釋德洪','宋','宋诗','song-poetry','','[]','雖應鋒機，不是語句。',100,'全唐诗/poet.song.76000.json','["雖應鋒機，不是語句。", "鴨寒下水，雞寒上樹。", "不妨辦衆，推究自己。", "一手摸魚，一手戽水。", "推開三玄玉鏁，揩拭同真十智。", "要知天下南臺，口含三十六齒。", "夜歸候門立地笑，眼腦癡憨肚裏峭。", "緣来點鐵成金法，白揣與人人不要。"]'),
('407a1404-3484-4ef4-88c8-13d6fbfade2e','送親上人乞食三首  其三','釋德洪','宋','宋诗','song-poetry','','[]','以有夢幻身，安能軃饑渇。',84,'全唐诗/poet.song.76000.json','["以有夢幻身，安能軃饑渇。", "剃頭捨飾好，則以乞爲活。", "鍊盡世間心，方稱閒披衲。", "格言非汝欺，餘塵尚諸學。", "吾師三界尊，食時亦持鉢。", "春風吹湘雲，萬峰寒踢卓。", "出門一句子，團團生四角。"]'),
('87d1fe68-a75b-4e65-8d46-a033cf5f56d5','讀龍勝尊者語','釋德洪','宋','宋诗','song-poetry','','[]','鼓聲無作者，有作必有處。',72,'全唐诗/poet.song.76000.json','["鼓聲無作者，有作必有處。", "乃知畢竟空，誑惑凡耳故。", "鏡象無生滅，生滅則有體。", "乃知畢竟空，誑惑凡眼爾。", "以我如實知，法無心外者。", "若人見自心，一切如幻化。"]'),
('46b82156-bf37-4c29-9f15-245c67f0f9ad','花藥英禪師生日其子通慧設齋作此','釋德洪','宋','宋诗','song-poetry','','[]','甲辰臘旦底時節，太虚完全無一缺。',96,'全唐诗/poet.song.76000.json','["甲辰臘旦底時節，太虚完全無一缺。", "陷虎機參陕右禪，罵人觜是新羅鐵。", "雲居老子最精鋭，長笑師兄難控制。", "龍象蹴踏非驢堪，鵝王擇乳非鴨類。", "睡快庵中知見香，試焚一銖熏十方。", "不在鼻端空與木，畢竟此香何處藏。"]'),
('f07806d8-b9f2-425c-90dd-e21df5127662','四偈  其一','釋德洪','宋','宋诗','song-poetry','','[]','妒忌之火，焚燒善根。',80,'全唐诗/poet.song.76000.json','["妒忌之火，焚燒善根。", "增惡果報，壞好名聞。", "以著我故，見慢增勝。", "瞋所蓋纒，心不清浄。", "大則壞國，小則殺身。", "從古至今，數如沙塵。", "既會愛憎，當衣慈忍。", "如是進者，名真随順。"]'),
('bb07db52-d453-4578-b75e-5c61ec4a7591','四偈  其二','釋德洪','宋','宋诗','song-poetry','','[]','見勝進者，心生嫉妒。',80,'全唐诗/poet.song.76000.json','["見勝進者，心生嫉妒。", "以苾芻相，包蛇虺怒。", "不敢以身，而先天下。", "三人同行，必有師者。", "孔老之聖，行已如此。", "奈何懷瞋，而稱釋子。", "子以緣差，我故痛告。", "盡世間心，乃可學道。"]'),
('4e691f7d-7f18-48d4-98e3-40c990b8a32a','四偈  其三','釋德洪','宋','宋诗','song-poetry','','[]','瞋恚現行時，無明所迷醉。',48,'全唐诗/poet.song.76000.json','["瞋恚現行時，無明所迷醉。", "不知自之失，但見他人是。", "如人在暗處，見外不見裏。", "大哉聖人學，事事必求己。"]'),
('2e489e41-6851-4b38-b6be-c8b339f03987','四偈  其四','釋德洪','宋','宋诗','song-poetry','','[]','曹谿傳祖位，夜舂先屈身。',48,'全唐诗/poet.song.76000.json','["曹谿傳祖位，夜舂先屈身。", "童子誦句偈，乃稱曰上人。", "南山證果位，天神常伏膺。", "自以本持律，不敢稱大乘。"]'),
('d286fd6d-1b9e-4643-a2e2-e3efaa137e57','日用','釋德洪','宋','宋诗','song-poetry','','[]','晝爲情緣，夜爲惡想。',120,'全唐诗/poet.song.76000.json','["晝爲情緣，夜爲惡想。", "譬如血脉，流注不斷。", "笑喜怒罵，折旋俯仰。", "我觀箇中，無三界相。", "山河大地，與意俱喪。", "十方分身，向此安葬。", "耳中有塵，捕風縛響。", "舌頭無骨，如拳展掌。", "嬰兒哆啝，語無背向。", "終必得物，人不敢誑。", "是堅密身，獨露萬象。", "纔落意地，即同侣伴。"]'),
('5ccb9ae0-5317-4cac-98ea-3e41e708b641','八月十六入南昌右獄作對治偈','釋德洪','宋','宋诗','song-poetry','','[]','那落迦中，論刼受苦。',120,'全唐诗/poet.song.76000.json','["那落迦中，論刼受苦。", "焚鐵其地，汁銅其柱。", "魚鱠而臠，爪分而鋸。", "於一日夕，有萬痛楚。", "我避世紛，重閉其户。", "而此知識，勃然而怒。", "吏收付官，於此土住。", "自尋其罪，焦芽石女。", "然非天人，所能見與。", "自業成熟，現行會遇。", "受盡還無，無可措慮。", "我作是觀，上契佛祖。"]'),
('4e4dd360-ab8b-4253-8c45-47770faf0882','食不繼偈','釋德洪','宋','宋诗','song-poetry','','[]','觀餓鬼趣，論劫饑渇。',50,'全唐诗/poet.song.76000.json','["觀餓鬼趣，論劫饑渇。", "針鋒其咽，火聚其髪。", "晝夜號呼，百千死活。", "我常飽暖，今暫缺乏。", "當生大悲，入此觀法。"]'),
('3e036ee2-509f-4fe9-86c7-a4eb9a00ef31','讀巘禪師錄','釋德洪','宋','宋诗','song-poetry','','[]','白衣微涴輙易覺，軟泥硬地俱隱脚。',48,'全唐诗/poet.song.76000.json','["白衣微涴輙易覺，軟泥硬地俱隱脚。", "自家力量那借人，了義心頭無處著。", "實無一法可相傳，直語臨機休卜度。"]'),
('5869e561-7efc-43be-a242-e0912bf3d487','次韻李商老送杲上人還石門','釋德洪','宋','宋诗','song-poetry','','[]','解彈無絃琴，急拍紅牙碎。',52,'全唐诗/poet.song.76000.json','["解彈無絃琴，急拍紅牙碎。", "得生覩史天，冤債有頭對。", "須知泐潭禪，妙出言詮外。", "猛焰爐中墮指冰，箭鋒拄處君休昧。"]'),
('54ddab72-597c-4a3d-9ad3-079236e805ac','永明禪師生日','釋德洪','宋','宋诗','song-poetry','','[]','教乘法檀越，宗門禪判官。',43,'全唐诗/poet.song.76000.json','["教乘法檀越，宗門禪判官。", "今朝藏不得，推出與人看。", "看看，夜行只管貪明月，不覺渾身露水寒。"]'),
('afe6fb68-be2e-4d40-85d8-c3e091e7a67c','墮軒','釋德洪','宋','宋诗','song-poetry','','[]','當初二祖說禪，拜起依位而立。',56,'全唐诗/poet.song.76000.json','["當初二祖說禪，拜起依位而立。", "後来百丈聽法，卷却坐前拜席。", "曹山一墮二目，老兒衣穿骨露。", "譬如彈指閣前，門開還合如故。"]'),
('9136488c-5b59-4a4d-a903-c28cafb30bdf','棗柏生辰','釋德洪','宋','宋诗','song-poetry','','[]','十世古今圓當念，日用當以何法驗。',64,'全唐诗/poet.song.76000.json','["十世古今圓當念，日用當以何法驗。", "夢中享盡百年榮，黄梁未熟路傍店。", "乃知無明無性體，狂逐妄緣顛倒轉。", "棗柏指我此妙門，故能千偈如瓴建。"]'),
('a690e1a1-4658-45ef-b701-4571e4afeb90','三月十七老黄龍生辰','釋德洪','宋','宋诗','song-poetry','','[]','黄龍三月十有七，天下衲僧信不及。',64,'全唐诗/poet.song.76000.json','["黄龍三月十有七，天下衲僧信不及。", "盡道三關透者難，鼻直眼横誰不識。", "滿院東風花不言，死生情盡於今日。", "汨羅江上小叢林，放意說禪無愧色。"]'),
('bb91137f-16ee-45aa-9aa1-cb8ecac7173a','黄龍生辰因閲晦堂偈作此','釋德洪','宋','宋诗','song-poetry','','[]','萬古知音是今日，晦堂古錐口門窄。',64,'全唐诗/poet.song.76000.json','["萬古知音是今日，晦堂古錐口門窄。", "今既不来昔不往，桃花落盡春狼籍。", "南臺茗椀薦爐香，世禮叢林笑未忘。", "只箇死生收不得，夢中聲色謾遮藏。"]'),
('9557748f-7b10-429c-ba47-cc0c030ba9a0','正月六日南安巖主生辰','釋德洪','宋','宋诗','song-poetry','','[]','生死樅然無背面，名字由汝舌頭轉。',64,'全唐诗/poet.song.76000.json','["生死樅然無背面，名字由汝舌頭轉。", "昔日曾死今應生，今日是生何不見。", "是俗何故無鬚髪，是僧何不著伽梨。", "僧俗死生明不得，團欒一句匾如錐。"]'),
('4164f9c7-930d-47ea-9b3e-174ab0319656','超禪師示衆云見聞覺知只可一度','釋德洪','宋','宋诗','song-poetry','','[]','見聞覺知只一度，如刀斫水終不破。',64,'全唐诗/poet.song.76000.json','["見聞覺知只一度，如刀斫水終不破。", "細尋痕迹了無有，謂無破處則不可。", "譬如密室風寂然，謂風無有俱是過。", "以扇爲風則動揺，風本不動汝會麽。"]'),
('1681b30b-0483-4aba-b97d-0a6dcb29955e','不能争得偈','釋德洪','宋','宋诗','song-poetry','','[]','頭顱枿枿貪肉臠，眼孔巴巴憎妒聚。',64,'全唐诗/poet.song.76000.json','["頭顱枿枿貪肉臠，眼孔巴巴憎妒聚。", "但尋他人是非說，不知自己敗闕露。", "鬭死他年輸與我，鬭生今日不及汝。", "見時先意相不審，各自念佛修行去。"]'),
('44054494-1861-45ff-beba-3254f48be30e','雲菴和尚生日燒香偈','釋德洪','宋','宋诗','song-poetry','','[]','妄見往来顛倒性，智入三際刹那定。',64,'全唐诗/poet.song.76000.json','["妄見往来顛倒性，智入三際刹那定。", "即此名言是污染，知爲污染心清浄。", "此知不屬緣非緣，一絲不挂魚脱淵。", "夢幻死生藏不得，永夜清宵常現前。"]'),
('df259e8d-0d59-49a4-8529-ae608eba959c','戊戌歲元日夢雲菴携登塔問答甚多覺而忘之作此','釋德洪','宋','宋诗','song-poetry','','[]','政和八年四十八，一念了知一切法。',64,'全唐诗/poet.song.76000.json','["政和八年四十八，一念了知一切法。", "顛倒妄想垢消滅，平等性智光通達。", "常令現前絕功勳，不欲染污差毫髪。", "雲庵夢中提誨我，不然何以同登塔。"]'),
('89705402-7145-45b6-a41e-a49fa738e6a5','過張家渡遇雲菴生辰','釋德洪','宋','宋诗','song-poetry','','[]','十月十六誰宗旨，無聲三昧重拈起。',64,'全唐诗/poet.song.77000.json','["十月十六誰宗旨，無聲三昧重拈起。", "十方三世側耳聽，刹刹塵塵俱解義。", "雙林樹開榮枯枝，寶塔佛分生滅理。", "一絲不挂露堂堂，要識雲菴今日是。"]'),
('f0ee9cb5-81ba-411b-8d01-b1b5af1ce42d','永明禪師生辰','釋德洪','宋','宋诗','song-poetry','','["\u897f\u6e56"]','西湖水生洲渚失，南屏雪盡峰巒集。',64,'全唐诗/poet.song.77000.json','["西湖水生洲渚失，南屏雪盡峰巒集。", "新春歸来誰使令，殘臘遁逃追不及。", "死生難分後先際，古今不與絲毫隔。", "平生說法如雨雲，說得分明惟此日。"]'),
('11099f83-c262-4c6a-8eb5-44ea29b68bae','贈承天邃岑','釋德洪','宋','宋诗','song-poetry','','[]','長沙大蟲今尚在，眼吻開合珠光彩。',64,'全唐诗/poet.song.77000.json','["長沙大蟲今尚在，眼吻開合珠光彩。", "妙年憑陵舌翻海，衲僧呼作叢林客。", "邇来頭有把茅蓋，栽田博飯自扶耒。", "禪道從他别人會，且復閑眠搔癢背。"]'),
('b062e781-34c9-4b33-ac63-70c7ea6d6485','題淡軒','釋德洪','宋','宋诗','song-poetry','','[]','道人口吻最光滑，行脚飽參奈粗糲。',64,'全唐诗/poet.song.77000.json','["道人口吻最光滑，行脚飽參奈粗糲。", "少年嘗編諸方禪，邇来解毳三隻韈。", "世味從来崖蜜甜，我此一軒如嚼蠟。", "客来有語但寒温，坐久時見眼開合。"]'),
('23f192b2-ae2c-4f2e-9464-4377e2873412','送澄禪者入蔣山','釋德洪','宋','宋诗','song-poetry','','[]','妙明廓徹圓當念，念未圓明顛倒轉。',64,'全唐诗/poet.song.77000.json','["妙明廓徹圓當念，念未圓明顛倒轉。", "譬如醉眼旋屋廬，屋廬巋然醉目眩。", "要令鶻崙常現前，一切時中莫污染。", "昔日蔣山解顛草，一字不可饒兩點。"]'),
('8cb098ae-ab2d-4379-b1bd-10927a74991c','送忠道者乞炭','釋德洪','宋','宋诗','song-poetry','','[]','水行無聲知其深，玉瑕不變知其粹。',64,'全唐诗/poet.song.77000.json','["水行無聲知其深，玉瑕不變知其粹。", "逆順門高懽喜登，辦心成就一切智。", "楊岐卧榻有真珠，杜順法身無紙被。", "焰上說禪炭裏藏，不妨道者閑游戲。"]'),
('ce957d07-ae9d-469d-9aa0-35c878992371','再送之','釋德洪','宋','宋诗','song-poetry','','[]','出家放曠斷愛緣，是心清浄離蓋纒。',64,'全唐诗/poet.song.77000.json','["出家放曠斷愛緣，是心清浄離蓋纒。", "君看鐵脊忠道者，妙如神魚初脱淵。", "閑行覻地一笑喜，自言拾得南臺禪。", "東勝身洲兜一喝，驚得山河磨蟻旋。"]'),
('1d4d2b30-93ec-45a4-b5be-45f95d20bd65','昌禪師瓦翁塔','釋德洪','宋','宋诗','song-poetry','','[]','瓦翁外瓦中曠達，未死不妨先建塔。',64,'全唐诗/poet.song.77000.json','["瓦翁外瓦中曠達，未死不妨先建塔。", "心如平地起骨堆，聊對時人翻著韈。", "住山送客不過溪，瓦徑不減石頭滑。", "諸方来者莫麤心，舉步亦須防倒躂。"]'),
('0b4f69d1-0cad-4273-a4bf-d09154839365','送肇上人還江南省阿尚','釋德洪','宋','宋诗','song-poetry','','[]','窮冬急景江村暮，道人千里江南去。',64,'全唐诗/poet.song.77000.json','["窮冬急景江村暮，道人千里江南去。", "明宵應宿路傍店，敗簀枯禪山月吐。", "死生面目無處尋，但餘體粟空齟齬。", "能知忍凍非他物，便可鶻崙吞佛祖。"]'),
('d3bfe0e3-b0f4-491f-b0c2-7ee691a0a637','明教夢中作','釋德洪','宋','宋诗','song-poetry','','[]','劍戟光芒星斗動，虎方肉醉山嶽恐。',64,'全唐诗/poet.song.77000.json','["劍戟光芒星斗動，虎方肉醉山嶽恐。", "層崖斷處一庵深，宴坐不言百神悚。", "臨濟仆地掖而起，眼蓋叢林氣深穩。", "覿面堂堂不覆藏，個中無地容思忖。"]'),
('e22690e4-5e19-484f-8309-5e0d4bbf1620','見志','釋德洪','宋','宋诗','song-poetry','','[]','逼寒虚空難躱避，笑渠百計苦捜尋。',64,'全唐诗/poet.song.77000.json','["逼寒虚空難躱避，笑渠百計苦捜尋。", "至無著力爲明見，但盡攀緣是肯心。", "顧我竪旗降老病，有誰横槊捍叢林。", "木鵝巫峡思前事，正惬雲巖隔信音。"]'),
('026feb8e-66eb-4d35-ac72-2161d294db40','示禪者','釋德洪','宋','宋诗','song-poetry','','[]','庵內不知庵外事，坐看来者墮鋒機。',64,'全唐诗/poet.song.77000.json','["庵內不知庵外事，坐看来者墮鋒機。", "忽思良遂參麻谷，大類清平見翠微。", "黄蘗棒頭寧有法，惠超言下便知非。", "意根欲立無存處，萬象同時把手歸。"]'),
('53d61020-fdd1-43ac-88d0-ca0db4c0d6b3','題石頭頓斧亭','釋德洪','宋','宋诗','song-poetry','','[]','兀坐等閑酬客問，碌磚抛出亦光生。',64,'全唐诗/poet.song.77000.json','["兀坐等閑酬客問，碌磚抛出亦光生。", "欲憑妙語分賓主，須識塵機有濁清。", "麟角譽高推獨步，石頭路滑苦難行。", "草菴依舊青松下，睡起晴窗撥眼明。"]'),
('28a352cc-efbc-40d2-8629-1968e4d5d41d','十二月二十六日永明禪師生辰三首  其一','釋德洪','宋','宋诗','song-poetry','','[]','世界撮来如粟米，根塵劈破似虚空。',64,'全唐诗/poet.song.77000.json','["世界撮来如粟米，根塵劈破似虚空。", "驕嘶鐵馬追風去，杴鬭泥牛躍浪中。", "十聖撼揺無縫罅，三賢摸索墮盲聾。", "長因此日容瞻仰，面目分明歲歲同。"]'),
('a9e15408-cbc3-4589-829c-1561a032d0e0','十二月二十六日永明禪師生辰三首  其二','釋德洪','宋','宋诗','song-poetry','','[]','刹那思慮不及處，智入三世無去来。',64,'全唐诗/poet.song.77000.json','["刹那思慮不及處，智入三世無去来。", "水母有蝦方見色，芭蕉無耳亦聞雷。", "閑中情垢消磨盡，笑裏心花造次開。", "今日全身毛孔笑，老師带伴與春回。"]'),
('a1c4ba8d-bb99-4791-bc71-d8d00a8b62a6','十二月二十六日永明禪師生辰三首  其三','釋德洪','宋','宋诗','song-poetry','','[]','昨日雲門曲調分，今朝法眼已生孫。',64,'全唐诗/poet.song.77000.json','["昨日雲門曲調分，今朝法眼已生孫。", "渠將大地藏針孔，汝等諸人甚處蹲。", "塊石浮空將壓汝，一毛在火不曾焚。", "孤猨叫月千巖曉，知道當時以眼聞。"]'),
('f7339c7e-1da1-447f-9b64-64cd055dfe76','南安巖主定光生辰五首  其一','釋德洪','宋','宋诗','song-poetry','','[]','老兒饒舌太慈悲，此日提綱決衆疑。',64,'全唐诗/poet.song.77000.json','["老兒饒舌太慈悲，此日提綱決衆疑。", "解說神光摩頂後，分疏死日降生時。", "落人塊石懸空住，噴火雙蓮結子遲。", "堪笑年年正月六，出羣消息少人知。"]'),
('a83edff4-3777-45b4-aeb0-a2a7fef5c853','南安巖主定光生辰五首  其二','釋德洪','宋','宋诗','song-poetry','','[]','贈以之中擊電機，不令點畫入思惟。',64,'全唐诗/poet.song.77000.json','["贈以之中擊電機，不令點畫入思惟。", "嘶風木馬空成夢，喘月泥牛醉未知。", "五藴完全真死日，百骸消散是生時。", "雲門函蓋乾坤句，語默何人遘得伊。"]'),
('6f49c2e2-3acd-4b19-8b91-e4f539013ac4','南安巖主定光生辰五首  其三','釋德洪','宋','宋诗','song-poetry','','[]','南安巖本在長汀，巖主年年此日生。',64,'全唐诗/poet.song.77000.json','["南安巖本在長汀，巖主年年此日生。", "笑裏一毛無閒斷，毫端十字露縦横。", "未離唇吻成窠臼，纔落思惟墮壍坑。", "自是定光那惜借，可憐馳逐並頭争。"]'),
('368fc84e-28e7-479f-80fb-e8a18e6a5ca4','南安巖主定光生辰五首  其四','釋德洪','宋','宋诗','song-poetry','','[]','體妙常明目神解，不關托境仗緣生。',64,'全唐诗/poet.song.77000.json','["體妙常明目神解，不關托境仗緣生。", "從来懶欲當頭道，恐後空存染污名。", "苦口傷慈成漏泄，死時生日太分明。", "堂堂試展巖中像，稽首重瞻道骨清。"]'),
('6428abb0-8e4e-4380-84f2-674b18d65793','南安巖主定光生辰五首  其五','釋德洪','宋','宋诗','song-poetry','','[]','不涉春緣正月六，衲僧拾得聚頭看。',64,'全唐诗/poet.song.77000.json','["不涉春緣正月六，衲僧拾得聚頭看。", "大家宜著音容想，一笑風吹牙齒寒。", "欲問死生口門窄，更分僧俗眼皮寛。", "湘山雪盡千巖曉，贈以之中墨未乾。"]'),
('73574c25-8cbe-445f-a7c5-11af6e0467e7','老黄龍生辰三首  其一','釋德洪','宋','宋诗','song-poetry','','[]','綱宗壁立大崔嵬，魔外聞風膽自摧。',64,'全唐诗/poet.song.77000.json','["綱宗壁立大崔嵬，魔外聞風膽自摧。", "萬古知音今日是，三關鏁鑰一時開。", "從教意氣縱横去，終解形容寂寞回。", "寄語兒孫著精彩，黄龍手段似南臺。"]'),
('d07c37e5-7086-491d-a9e4-eb604cbd3a88','老黄龍生辰三首  其二','釋德洪','宋','宋诗','song-poetry','','[]','塵勞山峻鐵崔嵬，曾向慈明喝下摧。',64,'全唐诗/poet.song.77000.json','["塵勞山峻鐵崔嵬，曾向慈明喝下摧。", "解作隱身衣带露，不須彈指閣門開。", "三關未透從教去，萬里追思却再回。", "已墜綱宗誰整頓，杖藜今日獨登臺。"]'),
('b9d94dfe-68fb-4a57-ac3b-de8cb2c60e2b','老黄龍生辰三首  其三','釋德洪','宋','宋诗','song-poetry','','[]','同登九仞到崔嵬，困極那辭共墮摧。',64,'全唐诗/poet.song.77000.json','["同登九仞到崔嵬，困極那辭共墮摧。", "待汝狐疑猶豫處，當機佛手等閑開。", "昔年成物心空切，今日臨風首重回。", "滿院新晴春已老，落花飛絮點池臺。"]'),
('decd8ae8-0ea1-45e4-b119-e9b2df0c673a','雲庵生辰十一首  其一','釋德洪','宋','宋诗','song-poetry','','[]','今年十月十六日，老漢行藏世不知。',64,'全唐诗/poet.song.77000.json','["今年十月十六日，老漢行藏世不知。", "石女夢中無死地，空花落後記生時。", "無聲三昧重聞舉，入骨風流說向誰。", "妙叶當機休擬議，電光翻影不容追。"]'),
('6b1f89bb-f346-417f-8837-e9868784a064','雲庵生辰十一首  其二','釋德洪','宋','宋诗','song-poetry','','[]','一句全提離死生，如今非住昔非行。',64,'全唐诗/poet.song.77000.json','["一句全提離死生，如今非住昔非行。", "若知此老無今古，便解臨機透識情。", "滿院松聲霜後好，十分山月夜来清。", "兒孫要識吾宗旨，只箇金剛瞎眼睛。"]'),
('4aeefa00-fb22-4feb-adcb-5b4db6f266f3','雲庵生辰十一首  其三','釋德洪','宋','宋诗','song-poetry','','[]','多寶重来應爲法，塔中全體不鮮陳。',64,'全唐诗/poet.song.77000.json','["多寶重来應爲法，塔中全體不鮮陳。", "却思平日分身集，何似今朝一句親。", "略露爪牙藏理窟，不留影迹走機輪。", "叢林欲問南陽事，我是躭源老應真。"]'),
('ad10e3b6-e7a3-4f11-8ed7-3812a1df986d','雲庵生辰十一首  其四','釋德洪','宋','宋诗','song-poetry','','[]','一切智慮不及處，曠劫無明壞滅時。',64,'全唐诗/poet.song.77000.json','["一切智慮不及處，曠劫無明壞滅時。", "頂相後常光照曜，髑髏前略露風規。", "根塵不敢覆藏者，生死那能染污之。", "消汝去来顛倒想，共瞻遺像入追思。"]'),
('87592880-5048-4dd8-831d-ecc35b8af0a9','雲庵生辰十一首  其五','釋德洪','宋','宋诗','song-poetry','','[]','十月月團光到曉，蠻煙瘴雨卷晴空。',64,'全唐诗/poet.song.77000.json','["十月月團光到曉，蠻煙瘴雨卷晴空。", "石門想像同袍集，珠浦行藏異類中。", "鉢飯薦陳虚坐設，罏香拜奠與誰同。", "曲高唱獨知音少，鯨浪粘天地脉通。"]'),
('1f21a83b-20fa-4f6c-8ee4-43d38c8473e7','雲庵生辰十一首  其六','釋德洪','宋','宋诗','song-poetry','','[]','不落思惟離聖凡，令君覿露見雲菴。',64,'全唐诗/poet.song.77000.json','["不落思惟離聖凡，令君覿露見雲菴。", "平生不許當頭道，今日重聞稱性談。", "老鑒三機酬跛偃，洞山一半肯雲巖。", "我無奇特報恩德，九死歸從瘴海南。"]'),
('3245c408-4403-47a8-b8d7-1276bfa92fa6','雲庵生辰十一首  其七','釋德洪','宋','宋诗','song-poetry','','[]','面目分明畫裏傳，渾如父母未生前。',64,'全唐诗/poet.song.77000.json','["面目分明畫裏傳，渾如父母未生前。", "此真若信同十智，三要方知具一玄。", "無語臨機成滲漏，麤心開口墮情緣。", "老兒今日親分付，不寫題銜款識全。"]'),
('54ca451b-85e7-498c-aa50-2329c9e23dae','雲庵生辰十一首  其八','釋德洪','宋','宋诗','song-poetry','','[]','空庭叢橘半垂黄，繞屋畦蔬又著霜。',64,'全唐诗/poet.song.77000.json','["空庭叢橘半垂黄，繞屋畦蔬又著霜。", "山縣人歸輸井税，麥田雪後縦牛羊。", "意行門徑欣来客，背負茅簷愛夕陽。", "今日故山成悵望，鳥殘紅柿憶分嘗。"]'),
('b233b0d3-b0eb-4c34-98b5-6fb3a51dd4b1','雲庵生辰十一首  其九','釋德洪','宋','宋诗','song-poetry','','[]','雲庵化去二十載，今日重聞說法音。',64,'全唐诗/poet.song.77000.json','["雲庵化去二十載，今日重聞說法音。", "覿露全身太分曉，森羅萬象自平沈。", "攀緣路絕無生死，栽接情忘透古今。", "此老傷慈真故態，依前饒舌老婆心。"]'),
('e914be36-af45-4987-99cd-3f6cec1d7582','雲庵生辰十一首  其一○','釋德洪','宋','宋诗','song-poetry','','[]','大地無一法可見，雲庵露萬象中身。',64,'全唐诗/poet.song.77000.json','["大地無一法可見，雲庵露萬象中身。", "頑空消殞明方極，肉眼遮藏覷不親。", "苦口老師歸寂日，知恩弟子慶生辰。", "罏香長伴青燈曉，賽却靈山法供真。"]'),
('b2aac373-3d51-4de0-aac3-4cdfc80129a6','雲庵生辰十一首  其一一','釋德洪','宋','宋诗','song-poetry','','[]','老師一句撲不破，徹底完全爲不存。',64,'全唐诗/poet.song.77000.json','["老師一句撲不破，徹底完全爲不存。", "何處干戈能脅嚇，誰家夢幻敬追奔。", "太虚影像藏蹤跡，大地山河喪膽魂。", "今日與君呈伎倆，都將生死鶻崙吞。"]'),
('db896cec-4f03-4e26-80aa-a659ba224e46','陳處士爲予畫像求頌戲與之','釋德洪','宋','宋诗','song-poetry','','[]','吴儂戲入筆三昧，老儼分身縑素間。',64,'全唐诗/poet.song.77000.json','["吴儂戲入筆三昧，老儼分身縑素間。", "平昔垂鬚曾跨海，暮年留眼飽看山。", "肯甘夢幻所折困，不受叢林輙見刪。", "我不是渠渠是我，謾餘名字落人寰。"]'),
('c7daa259-d8af-43a3-9875-1d62fdb0e8ce','次韻楊君所問','釋德洪','宋','宋诗','song-poetry','','[]','學道全無箇入頭，老師曾指路蹤由。',64,'全唐诗/poet.song.77000.json','["學道全無箇入頭，老師曾指路蹤由。", "岸如欲上先停棹，車若不行須打牛。", "殘蕚萬枝紅錦墮，暮雲一縷碧煙浮。", "爲君直截根源說，不落春緣會也不。"]'),
('ef1e3f2c-cf20-4f06-899d-c1cc07e6616e','讀十明論','釋德洪','宋','宋诗','song-poetry','','[]','了知無性滅無明，空慧須從戒定生。',64,'全唐诗/poet.song.77000.json','["了知無性滅無明，空慧須從戒定生。", "峰頂世間心已盡，蓮開幻事觀方成。", "尚無欣慕厭除念，豈有神通變化情。", "對現色身人不識，南風小雨共籠晴。"]'),
('0e0b3ce4-64f0-4d2d-9a03-9081944e6f3c','僧問烏喙義','釋德洪','宋','宋诗','song-poetry','','[]','知之百事不改舊，欲理情緣一笑譁。',64,'全唐诗/poet.song.77000.json','["知之百事不改舊，欲理情緣一笑譁。", "畫水成紋覓生滅，盤珠無影計横斜。", "人言烏喙豈堪食，我見飯囊今是沙。", "舉措施爲頭踞地，逸羣方解世吾家。"]'),
('f8e942b2-5a14-4834-af10-41434d208f9b','僧請釋金剛經卒軸','釋德洪','宋','宋诗','song-poetry','','[]','杵形中實兩頭虚，法喻初中後善俱。',64,'全唐诗/poet.song.77000.json','["杵形中實兩頭虚，法喻初中後善俱。", "九類衆生同寂静，四重我相頓消除。", "人天但仰懸河辯，蚊蚋難藏烈焰殊。", "悟了更須防老漢，紫羅帳裏撒真珠。"]'),
('43e53052-e57e-4e7f-a2a8-bcfa0df393c7','題溈山立雪軒','釋德洪','宋','宋诗','song-poetry','','[]','溈山雪曉試憑欄，露地牛兒覓轉難。',64,'全唐诗/poet.song.77000.json','["溈山雪曉試憑欄，露地牛兒覓轉難。", "脱體見前誰對立，一塵不受眼空寒。", "日長齒頬茶甘在，客去軒窗篆縷殘。", "好在少林成想像，祖師時展畫圖看。"]'),
('de36378c-a4ba-4d10-aee2-170c0056acb3','三月二十八日棗柏大士生辰用達本情忘知心體合爲韻作八偈供之時在建康獄中  其一','釋德洪','宋','宋诗','song-poetry','','[]','道不藉劬勞，心唯論曉達。',48,'全唐诗/poet.song.77000.json','["道不藉劬勞，心唯論曉達。", "圓明常了知，豈受情想雜。", "如人夢馳驅，身自安牀榻。", "一句脱思惟，大千挂毫髪。"]'),
('c975ee97-bd84-4870-afcd-9cf6f38695f7','三月二十八日棗柏大士生辰用達本情忘知心體合爲韻作八偈供之時在建康獄中  其二','釋德洪','宋','宋诗','song-poetry','','[]','句中開活路，要汝到根本。',48,'全唐诗/poet.song.77000.json','["句中開活路，要汝到根本。", "如射中百步，巧力觀者奮。", "箭鋒相直時，何嘗落思忖。", "相逢佇思間，雪峰毬子輥。"]'),
('bcc5af71-bb87-4d8e-bcd4-18dc5a6a32a0','三月二十八日棗柏大士生辰用達本情忘知心體合爲韻作八偈供之時在建康獄中  其三','釋德洪','宋','宋诗','song-poetry','','[]','人間皆熱惱，我自不随情。',48,'全唐诗/poet.song.77000.json','["人間皆熱惱，我自不随情。", "一室閑趺坐，天魔魂震驚。", "百千大火聚，中有片玉清。", "大哉慈忍力，妙湛合無生。"]'),
('27892aef-293e-4254-807e-a3b52eebd107','三月二十八日棗柏大士生辰用達本情忘知心體合爲韻作八偈供之時在建康獄中  其四','釋德洪','宋','宋诗','song-poetry','','[]','見行常潤發，種子復難忘。',48,'全唐诗/poet.song.77000.json','["見行常潤發，種子復難忘。", "倐爾情塵起，刹那心境彰。", "譬如鏡中女，非鏡非紅粧。", "欲證牛無角，當如龜六藏。"]'),
('832cb9d8-6e2d-48c8-a5d8-8baa9141d74a','三月二十八日棗柏大士生辰用達本情忘知心體合爲韻作八偈供之時在建康獄中  其五','釋德洪','宋','宋诗','song-poetry','','[]','吾聞能障道，惟强覺妄知。',48,'全唐诗/poet.song.77000.json','["吾聞能障道，惟强覺妄知。", "欲得長靈妙，直須無失時。", "鐘聲鳴静夜，晝擊則生疑。", "踞地真師子，風顛漏泄之。"]'),
('f2d95ea0-a943-468a-b61c-3987a795520c','三月二十八日棗柏大士生辰用達本情忘知心體合爲韻作八偈供之時在建康獄中  其六','釋德洪','宋','宋诗','song-poetry','','[]','衆生各圓滿，本覺妙明心。',48,'全唐诗/poet.song.77000.json','["衆生各圓滿，本覺妙明心。", "常用交神對，無令見慢侵。", "霜刀惟切玉，妙指但鳴琴。", "□與雪山子，經行煙翠深。"]'),
('0c9697d1-c8d2-4405-b362-0b92676a6a9d','三月二十八日棗柏大士生辰用達本情忘知心體合爲韻作八偈供之時在建康獄中  其七','釋德洪','宋','宋诗','song-poetry','','[]','了然心自知，法法露全體。',48,'全唐诗/poet.song.77000.json','["了然心自知，法法露全體。", "遣化借燈王，引手搏妙喜。", "大用吾亦然，何獨居士耳。", "萬里見神光，當以頂後視。"]'),
('f38282c5-2dec-42e0-a0bd-53bd856cf654','三月二十八日棗柏大士生辰用達本情忘知心體合爲韻作八偈供之時在建康獄中  其八','釋德洪','宋','宋诗','song-poetry','','[]','汝常與智俱，自不與妄合。',48,'全唐诗/poet.song.77000.json','["汝常與智俱，自不與妄合。", "其智自神解，成就一切覺。", "諸佛方便門，衆生五欲樂。", "皆依真智生，醖造乳中酪。"]'),
('b6565b53-9017-4b06-8271-72d729e21d6c','二十九日明白菴主寂滅之日用欲得現前莫存順逆爲韻作八偈  其一','釋德洪','宋','宋诗','song-poetry','','[]','道心固有恒，至剛定無欲。',48,'全唐诗/poet.song.77000.json','["道心固有恒，至剛定無欲。", "得飽即酣卧，稱心良易足。", "清歌一瓢風，笑唾千鍾祿。", "誰能作九原，我欲掖埋玉。"]'),
('47bfe035-1950-4e4c-9713-d13427c645d6','二十九日明白菴主寂滅之日用欲得現前莫存順逆爲韻作八偈  其二','釋德洪','宋','宋诗','song-poetry','','[]','然燈有法傳，釋迦當即得。',48,'全唐诗/poet.song.77000.json','["然燈有法傳，釋迦當即得。", "但聞記別音，乃知無所獲。", "精真妙平等，明吿恐疑惑。", "永懷常不輕，好心遭捶擲。"]'),
('a4824ca4-ddb4-4af3-901f-8e98a43fe6fb','二十九日明白菴主寂滅之日用欲得現前莫存順逆爲韻作八偈  其三','釋德洪','宋','宋诗','song-poetry','','[]','心馳即攝来，寂然住正念。',48,'全唐诗/poet.song.77000.json','["心馳即攝来，寂然住正念。", "譬如分身集，全身方出現。", "生佛識精聚，滅佛遊魂變。", "分坐寶塔中，貳法君試辨。"]'),
('7854eadb-e606-45b2-989b-006cae8cc4f6','二十九日明白菴主寂滅之日用欲得現前莫存順逆爲韻作八偈  其四','釋德洪','宋','宋诗','song-poetry','','[]','道非止精進，此意曾密傳。',48,'全唐诗/poet.song.77000.json','["道非止精進，此意曾密傳。", "宴坐歷十劫，佛法不現前。", "一乘論知見，三獸分聖賢。", "君看娑竭女，初不學安禪。"]'),
('364d0b8e-f626-41b6-8fd4-a48c16f88a92','二十九日明白菴主寂滅之日用欲得現前莫存順逆爲韻作八偈  其五','釋德洪','宋','宋诗','song-poetry','','[]','汝心有罅隙，甘受夢幻縛。',48,'全唐诗/poet.song.77000.json','["汝心有罅隙，甘受夢幻縛。", "我念無異相，魔外分遮莫。", "初緣五欲囚，乃得入禪樂。", "自喜如弄猢，旁觀膽先落。"]'),
('fa7e551e-4777-40ef-b8ab-61065f691469','二十九日明白菴主寂滅之日用欲得現前莫存順逆爲韻作八偈  其六','釋德洪','宋','宋诗','song-poetry','','[]','火風肆怒嗔，萬物遭蕩焚。',48,'全唐诗/poet.song.77000.json','["火風肆怒嗔，萬物遭蕩焚。", "起止甚自若，不受冤債吞。", "六情具三毒，安得有罪愆。", "異哉根與境，乃得此理存。"]'),
('70571199-8f90-441b-9e10-3d95baeeb243','二十九日明白菴主寂滅之日用欲得現前莫存順逆爲韻作八偈  其七','釋德洪','宋','宋诗','song-poetry','','[]','餘生老變衰，復卧癡愛病。',48,'全唐诗/poet.song.77000.json','["餘生老變衰，復卧癡愛病。", "默觀顛倒因，聊復自随順。", "負暄慶生辰，自誑倚年運。", "偶然吐文章，朽木生芝菌。"]'),
('63d634b4-c9d8-4cb3-8bcf-069203202707','二十九日明白菴主寂滅之日用欲得現前莫存順逆爲韻作八偈  其八','釋德洪','宋','宋诗','song-poetry','','[]','業熟會冤憎，遂爾遭横逆。',48,'全唐诗/poet.song.77000.json','["業熟會冤憎，遂爾遭横逆。", "願行報冤行，遇此真知識。", "用智滅無明，以事觀色力。", "當登萬煆爐，乃驗真金色。"]'),
('f65c8291-25ca-4fb1-a47d-de7a30663af0','政和二年余謫海外館瓊州開元寺儼師院遇其遊行市井宴坐静室作務時恐緣差失念作日用偈八首  其一','釋德洪','宋','宋诗','song-poetry','','[]','一切境界，病眼倒見。',20,'全唐诗/poet.song.77000.json','["一切境界，病眼倒見。", "但静意根，空慧自現。"]'),
('9b55f1f8-e22f-40d8-8a3c-e2e17c7dd81e','政和二年余謫海外館瓊州開元寺儼師院遇其遊行市井宴坐静室作務時恐緣差失念作日用偈八首  其二','釋德洪','宋','宋诗','song-poetry','','[]','一切境界，随念而至。',20,'全唐诗/poet.song.77000.json','["一切境界，随念而至。", "念未生時，髑髏是水。"]'),
('5f9b97a5-15eb-41fd-8371-ebdc24d375e1','政和二年余謫海外館瓊州開元寺儼師院遇其遊行市井宴坐静室作務時恐緣差失念作日用偈八首  其三','釋德洪','宋','宋诗','song-poetry','','[]','道人何故，婬坊酒肆。',20,'全唐诗/poet.song.77000.json','["道人何故，婬坊酒肆。", "我自調心，非干汝事。"]'),
('8ec31e0d-4f84-49d0-b50b-c077e98e2519','政和二年余謫海外館瓊州開元寺儼師院遇其遊行市井宴坐静室作務時恐緣差失念作日用偈八首  其四','釋德洪','宋','宋诗','song-poetry','','[]','一日不作，一日不食。',20,'全唐诗/poet.song.77000.json','["一日不作，一日不食。", "誰其嗣之，我有遺則。"]'),
('02064c2b-36d3-4275-a1dd-4acc40ef6f85','政和二年余謫海外館瓊州開元寺儼師院遇其遊行市井宴坐静室作務時恐緣差失念作日用偈八首  其五','釋德洪','宋','宋诗','song-poetry','','[]','折脚鐺子，随處安置。',20,'全唐诗/poet.song.77000.json','["折脚鐺子，随處安置。", "食無精粗，但欲接氣。"]'),
('b39b0b57-f157-4035-8d85-b3bb0a9d6083','政和二年余謫海外館瓊州開元寺儼師院遇其遊行市井宴坐静室作務時恐緣差失念作日用偈八首  其六','釋德洪','宋','宋诗','song-poetry','','[]','心欲馳散，即當攝来。',20,'全唐诗/poet.song.77000.json','["心欲馳散，即當攝来。", "大火聚中，青蓮花開。"]'),
('17c2af02-ebab-4c7c-868d-f1b308cbb93a','政和二年余謫海外館瓊州開元寺儼師院遇其遊行市井宴坐静室作務時恐緣差失念作日用偈八首  其七','釋德洪','宋','宋诗','song-poetry','','[]','此障道法，上品蓋纒。',20,'全唐诗/poet.song.77000.json','["此障道法，上品蓋纒。", "是何時節，乃復安眠。"]'),
('24d37f0a-0eed-4c03-8204-99c9cdaa236a','政和二年余謫海外館瓊州開元寺儼師院遇其遊行市井宴坐静室作務時恐緣差失念作日用偈八首  其八','釋德洪','宋','宋诗','song-poetry','','[]','沙彌嗜乳，作乳中蟲。',20,'全唐诗/poet.song.77000.json','["沙彌嗜乳，作乳中蟲。", "三篾高道，一鉢孤風。"]'),
('5334f6b6-f81c-4c24-9b72-2a453ff52cd3','示禪者二首  其一','釋德洪','宋','宋诗','song-poetry','','[]','刹說衆生說，三世一切說。',48,'全唐诗/poet.song.77000.json','["刹說衆生說，三世一切說。", "廣大古井波，平等紅爐雪。", "照用本来同，賓主互相攝。", "如圓伊三點，不同亦不别。"]'),
('851b53d1-4df7-43f3-b60b-285f8038c18a','示禪者二首  其二','釋德洪','宋','宋诗','song-poetry','','[]','高高峰頂立，深深海底行。',48,'全唐诗/poet.song.77000.json','["高高峰頂立，深深海底行。", "道人行立處，塵世有誰争。", "無間功不立，渠儂尊貴生。", "强酬顛倒欲，火裏鐵牛耕。"]'),
('0be5da17-1a5d-402a-b677-e12b7612cc57','嶺外大雪故人多在南中元日作三偈奉寄瑩中  其一','釋德洪','宋','宋诗','song-poetry','','[]','徧界不會藏，處處光皎皎。',48,'全唐诗/poet.song.77000.json','["徧界不會藏，處處光皎皎。", "開眼失蹤由，都緣太分曉。", "園林匆生春，萬瓦粲一笑。", "遙知忍凍人，未悟安心了。"]'),
('9440462d-5006-4b5c-8e53-349ba629c966','嶺外大雪故人多在南中元日作三偈奉寄瑩中  其二','釋德洪','宋','宋诗','song-poetry','','[]','昨夜一歲除，今朝一歲長。',48,'全唐诗/poet.song.77000.json','["昨夜一歲除，今朝一歲長。", "如人暗書空，點畫自想像。", "春風依舊寒，底處有来往。", "居士亦赤窮，眉毛在眼上。"]'),
('d3b026d8-e16c-4486-8650-aac5c03d0682','嶺外大雪故人多在南中元日作三偈奉寄瑩中  其三','釋德洪','宋','宋诗','song-poetry','','[]','傳聞嶺外雪，壓倒千年樹。',48,'全唐诗/poet.song.77000.json','["傳聞嶺外雪，壓倒千年樹。", "老兒拍手笑，有眼未曾覩。", "故應潤物材，一洗瘴江霧。", "寄語牧牛人，莫教頭角露。"]'),
('167c7001-e721-4633-80d4-24c05bf1c40b','初入制院','釋德洪','宋','宋诗','song-poetry','','[]','無所住生心，佛語祖師意。',48,'全唐诗/poet.song.77000.json','["無所住生心，佛語祖師意。", "何人賞此音，空絃閑妙指。", "清歌餞餘年，堅卧答萬語。", "了知空花間，無地容生死。"]'),
('d4ccfc72-4c6c-4fd6-ba50-d762d5a7036e','余日渡海即號甘露滅所至問者尤多時作偈答益不解乃吿之曰湼槃經云甘露之性食之令人不死若合異物亦能不死維摩經亦曰得甘露滅覺道成又爲之偈','釋德洪','宋','宋诗','song-poetry','','[]','萬象獨露身，三世一切說。',48,'全唐诗/poet.song.77000.json','["萬象獨露身，三世一切說。", "解聞寂静音，方見甘露滅。", "從来幾生死，何處今堆疊。", "不受夢幻纒，紅罏存片雪。"]'),
('c9d3fedb-3747-41ec-bc2e-32411b20549e','述古德遺事作漁父詞八首 萬回','釋德洪','宋','宋诗','song-poetry','','[]','玉带雲袍童頂露，一生笑傲知何故，萬里歸来方旦暮。',72,'全唐诗/poet.song.77000.json','["玉带雲袍童頂露，一生笑傲知何故，萬里歸来方旦暮。", "休疑慮，大千揑在毫端聚。", "不解犁田分畝步，却能對客鳴花鼓，忽共老安相耳語。", "還推去，莫来攔我毬門路。"]'),
('03b5247d-1c84-47df-ab9c-3fc3f7fcc0ed','述古德遺事作漁父詞八首 丹霞','釋德洪','宋','宋诗','song-poetry','','[]','不怕石頭行路滑，歸来那愛駒兒踏，言下百骸俱撥撒。',72,'全唐诗/poet.song.77000.json','["不怕石頭行路滑，歸来那愛駒兒踏，言下百骸俱撥撒。", "無剩法，靈然晝夜光通達。", "古寺天寒還惡發，夜將木佛齊燒殺，炙背横眠真快活。", "憨抹撻，從教院主無鬚髪。"]'),
('4a251e4f-e7cd-4566-b44f-2f7b94c55514','述古德遺事作漁父詞八首 寶公','釋德洪','宋','宋诗','song-poetry','','[]','来往獨龍岡畔路，杖頭落索閑家具，後事前觀如目覩。',72,'全唐诗/poet.song.77000.json','["来往獨龍岡畔路，杖頭落索閑家具，後事前觀如目覩。", "非讖語，須知一念無今古。", "長笑老蕭多病苦，笑中與藥皆狼虎，蠟炬一枝非囑付。", "聊戲汝，熱来脱却娘生袴。"]'),
('e2ca68d6-0647-4511-9eb2-04c5466d3c69','述古德遺事作漁父詞八首 香嚴','釋德洪','宋','宋诗','song-poetry','','[]','畫餅充饑人笑汝，一庵歸掃南陽塢。',72,'全唐诗/poet.song.77000.json','["畫餅充饑人笑汝，一庵歸掃南陽塢。", "擊竹作聲方省悟，徐回顧，本来面目無藏處。", "却望溈山敷坐具，老師頭角渾呈露，珍重此恩踰父母。", "須薦取，堂堂密密聲前句。"]'),
('6a1d1f70-4e05-4148-8378-5a1934316729','述古德遺事作漁父詞八首 藥山','釋德洪','宋','宋诗','song-poetry','','[]','野鶴精神雲格調，逼人氣韻霜天曉。',72,'全唐诗/poet.song.77000.json','["野鶴精神雲格調，逼人氣韻霜天曉。", "松下殘經看未了，當斜照，蒼煙風撼流泉遶。", "閨閣珍奇徒照耀，光無滲漏方靈妙，活計現成誰管紹。", "孤峰表，一聲月下聞清嘯。"]'),
('51ca5f51-dfc3-450a-8aca-3db5f5040f3d','述古德遺事作漁父詞八首 亮公','釋德洪','宋','宋诗','song-poetry','','[]','講處天花随玉麈，波心月在那能取，旁舍老師偷指注。',72,'全唐诗/poet.song.77000.json','["講處天花随玉麈，波心月在那能取，旁舍老師偷指注。", "回頭覷，虚空特地能言語。", "歸對學徒重自訴，從前見解都欺汝，隔岸有山横暮雨。", "翻然去，千巖萬壑無尋處。"]'),
('c3cd0aec-006d-4d84-9174-d95d31e338df','述古德遺事作漁父詞八首 靈雲','釋德洪','宋','宋诗','song-poetry','','[]','急雨顛風花信早，枝枝葉葉春俱到。',72,'全唐诗/poet.song.77000.json','["急雨顛風花信早，枝枝葉葉春俱到。", "何待小桃方悟道，休迷倒，出門無限青青草。", "根不覆藏塵亦掃，見精明樹唯心造，試借疑情看白皂。", "回頭討，靈雲笑殺玄沙老。"]'),
('543b62a0-1c95-41f4-9c6d-a875a7a8d412','述古德遺事作漁父詞八首 船子','釋德洪','宋','宋诗','song-poetry','','[]','萬疊空青春杳杳，一簑煙雨吴江曉，醉眼忽醒驚白鳥。',72,'全唐诗/poet.song.77000.json','["萬疊空青春杳杳，一簑煙雨吴江曉，醉眼忽醒驚白鳥。", "拍手笑，清波不犯魚吞釣。", "津渡有僧求法要，一橈爲汝除玄妙，已去回頭知不峭。", "猶迷照，漁舟性懆都翻了。"]'),
('752de287-a814-434b-9eff-3831c6b24bc7','釋迦出山畫像贊','釋德洪','宋','宋诗','song-poetry','','[]','徧大海味，具於一滴。',159,'全唐诗/poet.song.77000.json','["徧大海味，具於一滴。", "盡法界身，足於纖埃。", "佇思則燈王之座不能入毗耶之室，斂念則彌勒之門彈指即開。", "惟我鼻祖，釋迦和尚。", "初出雪山，即示此像。", "以百千億微塵數身，九十七大人之相。", "頓入毫端三昧，而幻此一幅之上。", "垂手跣足，頂螺頷絲。", "超然静深，出三界癡。", "如浩蕩春寄於纖枝，如清涼月印於盆池。", "鏤冰琢雪，我作贊詞。", "關空鎖夢夫，子其牢蓄之。"]'),
('3ec44131-0648-4f6b-9215-01989a653c43','漣水觀音畫像贊','釋德洪','宋','宋诗','song-poetry','','[]','稽首浄聖甘露門，無量勝身徧沙界。',288,'全唐诗/poet.song.77000.json','["稽首浄聖甘露門，無量勝身徧沙界。", "應諸衆生心所求，譬如春色花萬卉。", "西方肅殺憂愁地，故住寶陀落伽山。", "此方教體在音聞，故稱名者得解脱。", "一切衆生殺心盛，癡暗不見不發心。", "故現鷹巢蚌蛤中，亦作畫師畫其像。", "菩薩豈有種種心，皆其悲願力如是。", "何人毫端寄逸想，幻出百福莊嚴身。", "屹然欲動千光集，譬如將回紫金山。", "瞭然欲瞬衆生好，譬如欲坼青蓮花。", "蠻奴水王来獻誠，想見細雨天花落。", "衆生五濁熱惱中，色欲愛見所熏炙。", "忽然覩此寶月相，一切毛孔皆清浄。", "成此不思議功德，皆因上人心所獻。", "願我早熏知見香，願我常披慈忍服。", "願魔障山速崩裂，願大智慧常現前。", "心精遺聞證圓通，自然静極光通達。", "我當定如觀世音，一切衆生願如我。"]'),
('2d83e5ec-22f6-4f94-a6e5-2d26378c92de','旃檀四十二臂觀音贊','釋德洪','宋','宋诗','song-poetry','','[]','汝意有言，枯杌作鬼。',240,'全唐诗/poet.song.77000.json','["汝意有言，枯杌作鬼。", "我心不生，髑髏則水。", "乃知妄覺，一法成二。", "湛然圓明，百千一耳。", "稽首大士，應物而形。", "随其小大，如谷答聲。", "千臂執持，千眼觀照。", "以無心故，受用俱妙。", "臂如青春，藏於化身。", "随其枝葉，疏密精神。", "唯此瑞相，四十二臂。", "不越徑寸，莊嚴畢備。", "清凉寶月，或慈或威。", "如欲舉足，花輪乘之。", "碧螺之間，有佛儼容。", "如蟭螟蟲，巢蚊睫中。", "隱于石間，顯出蚌蛤。", "以無礙慈，不擇清濁。", "我觀震旦，種性猛利。", "由聞思入，甘露滅地。", "願加被我，障盡心開。", "如觀世音，無礙辯才。", "我說此偈，萬象合掌。", "何以無礙，敲空作響。"]'),
('2078a008-4c59-423d-ba2c-78731aba6800','華藏寺慈氏菩薩贊','釋德洪','宋','宋诗','song-poetry','','[]','何人寄逸想，游戲浮漚間。',264,'全唐诗/poet.song.77000.json','["何人寄逸想，游戲浮漚間。", "以如幻之力，刻此旃檀像。", "坐令衆妙好，秀發千花中。", "天冠束紺髪，銖衣絡華鬘。", "種種妙莊嚴，成此功德聚。", "當時億萬種，感極則悲號。", "樓觀出談笑，祕護百寶攢。", "如登覩史天，如集龍華會。", "嗟哉像教末，羽嘉成百鳥。", "棘生薝蔔林，龍神爲悲慟。", "王臣寔外護，異夢非意思。", "願推明月輪，出此蓬勃煙。", "願回紫金山，安置清涼處。", "至今百福相，儼然臨人天。", "神力吁莫測，拜起涕汍瀾。", "我諦觀十方，實無心外境。", "自然離依地，及與徧計執。", "即今目所見，非有亦非無。", "如像現鏡中，非鏡亦非像。", "願入此三昧，識心自然明。", "於十方國土，而作大佛事。", "稽首大慈尊，證我如是說。"]'),
('88645a87-02ac-4bf5-97d3-62e5da70f902','泗州院旃檀白衣觀音贊','釋德洪','宋','宋诗','song-poetry','','[]','我聞菩薩昔因地，所供養佛名觀音。',272,'全唐诗/poet.song.77000.json','["我聞菩薩昔因地，所供養佛名觀音。", "從聞思修入悟心，心精遺聞而得道。", "見聞覺知不可易，譬如西北與東南。", "而此乃曰聞可遺，令人罔然墮疑網。", "龍本無耳聞以神，蛇亦無耳聞以眼。", "牛無耳故聞以鼻，螻蟻無耳聞以身。", "六根互用乃如此，聞不可遺豈理哉。", "彼於異類昧劣中，而亦精妙不間斷。", "况我自在慈忍力，無畏解脱獨不然。", "鐘鼓俱擊聲不同，知其不同是生滅。", "而二種聲不相參，即是同時寂滅法。", "稽首浄智功德聚，廣大莊嚴悲願海。", "憫我心明力不逮，時時種子發現行。", "如人因酒而發狂，戒飲輙復逢佳醖。", "願滅顛倒癡暗障，願獲辯才智慧藏。", "游戲十方微塵刹，亦施無畏利衆生。", "凡曰有心能聞者，同入圓通三昧海。"]'),
('51635aea-0b15-4f6a-9b69-b73bf101f766','靖安胡氏所蓄觀音贊','釋德洪','宋','宋诗','song-poetry','','[]','稽首净智甘露門，稽首無礙悲願海。',208,'全唐诗/poet.song.77000.json','["稽首净智甘露門，稽首無礙悲願海。", "稽首紫金光聚山，稽首心精遺聞地。", "願賜威光加被我，摧滅一切夙障山。", "令我一切刹塵中，見此百福如月面。", "菩薩常念諸衆生，譬如慈母憶憐子。", "子若晝夜常念母，母子百劫必相見。", "如針之契諸磁石，如雷之文於象牙。", "皆即自然如是應，非諸心識可思量。", "鷹巢現形蚌中出，化爲畫女并魚師。", "皆随衆生心所變，一一成辦無遺餘。", "妙哉三十二應身，一十四種無畏力。", "願于一念浄心現，譬如秋月現止水。", "一切衆生見者聞，皆入圓通三昧海。"]'),
('7ef7694c-efb1-4a7c-b6b7-c1ed4b3a3abc','潭州東明石觀音贊','釋德洪','宋','宋诗','song-poetry','','[]','大悲智光本無礙，於一切處常發現。',288,'全唐诗/poet.song.77000.json','["大悲智光本無礙，於一切處常發現。", "豈特夜半瓦礫間，始復爛然上霄漢。", "此邦衆生共勝業，時節成熟故如是。", "譬如日月行虚空，水無穢潔皆照臨。", "灰沙若沉波自寒，圜影於中迥殊特。", "稽首妙智光世音，是娑婆界真教體。", "應機而現爲說法，信心起處說法竟。", "我今見境得成就，亦同音聞獲圓通。", "六根遲速雖不齊，要是一精明所現。", "我知暗相不能昏，與彼心精遺聞處。", "衆塵隔越妄分别，常真實中無是事。", "死生之變尚不改，豈有根塵乃能蔽。", "願令持此妙法門，於此刹土爲佛事。", "一切聲色熱惱中，與衆生作清涼處。", "皈命救世大悲者，願賜威光加被我。", "令我獲無作妙力，令我亦名無所畏。", "令我具無礙辯才，令我入一切種智。", "我及一切諸有情，皆如觀音得自在。"]'),
('7ce4c04b-b993-437d-ac83-63efd4cb626c','空生真贊','釋德洪','宋','宋诗','song-poetry','','[]','以空寂身，無所倚依。',90,'全唐诗/poet.song.77000.json','["以空寂身，無所倚依。", "而捉杖藜，以靈知心。", "不在散攝，而玩貝葉。", "不舍聲色，而證真空。", "與我日用，能所心同。", "於一切處，寂入法海。", "如風行空，無所妨礙。", "但離二執，圓成普會。", "當慎以修，入此三昧。"]'),
('d8edf456-3d18-49c9-a416-14b8c2f8d7f7','祐勝菩薩贊','釋德洪','宋','宋诗','song-poetry','','[]','雷發春曉，象牙有花。',100,'全唐诗/poet.song.77000.json','["雷發春曉，象牙有花。", "是何因緣，而使然耶。", "一切幻物，感以無心。", "不思而合，如磁石針。", "况我大士，慈善根力。", "不起于座，沛然甘澤。", "千峰青碧，環如長城。", "經今幾時，殿閣崇成。", "咨爾邦士，時朔薦拜。", "稽首真慈，是甘露海。"]'),
('2317c398-35e3-4d4b-8495-e9e8ad64d913','繡釋迦像并十八羅漢贊 釋迦佛','釋德洪','宋','宋诗','song-poetry','','[]','指以心運，茸以針通。',40,'全唐诗/poet.song.77000.json','["指以心運，茸以針通。", "針針是佛，佛佛皆茸。", "十分月滿，萬國春同。", "稽首真慈，生女巧中。"]'),
('6d619482-b197-4ce5-958c-cd55462e9c6a','繡釋迦像并十八羅漢贊 第一賓度羅跋囉墮闍尊者','釋德洪','宋','宋诗','song-poetry','','[]','霜筠雪竹，石磴下安。',40,'全唐诗/poet.song.77000.json','["霜筠雪竹，石磴下安。", "青猊妥尾，徐行仰看。", "師則跏趺，顧視空几。", "吐詞如雷，侍者無耳。"]'),
('1c2c7f22-6173-4d10-bd54-6416bcefe281','繡釋迦像并十八羅漢贊 第二迦諾迦伐蹉尊者','釋德洪','宋','宋诗','song-poetry','','[]','蒼髯紫鱗，上有懸錫。',40,'全唐诗/poet.song.77000.json','["蒼髯紫鱗，上有懸錫。", "玉像金瓶，層置立石。", "蠻王跪看，鑪煙上直。", "手搯珠輪，心境俱寂。"]'),
('c073359f-ce01-45a8-9892-3e701712debf','繡釋迦像并十八羅漢贊 第三跋釐墮闍尊者','釋德洪','宋','宋诗','song-poetry','','[]','神觀静深，合爪欽視。',40,'全唐诗/poet.song.77000.json','["神觀静深，合爪欽視。", "誰設華輪，前置净几。", "髥王捧塔，自何而至。", "中有全身，勿安舍利。"]'),
('c7b20c1d-04dd-4381-b6d4-b828d87428bc','繡釋迦像并十八羅漢贊 第四蘇頻陀尊者','釋德洪','宋','宋诗','song-poetry','','[]','石牀之外，老松挺拔。',40,'全唐诗/poet.song.77000.json','["石牀之外，老松挺拔。", "玉瓶之中，山花自發。", "手持如意，默而說似。", "梵帙不看，知離文字。"]'),
('e5d74917-0937-4655-879a-8bb6f13650b7','繡釋迦像并十八羅漢贊 第五諾距羅尊者','釋德洪','宋','宋诗','song-poetry','','[]','樹亦求法，身當牀坐。',40,'全唐诗/poet.song.77000.json','["樹亦求法，身當牀坐。", "鹿有施心，供以山果。", "雪眉許長，舒綰在我。", "默而識之，未用驚破。"]'),
('fb6029d0-f7b8-4fb3-a4e5-8b1e6661a46a','繡釋迦像并十八羅漢贊 第六跋陀羅尊者','釋德洪','宋','宋诗','song-poetry','','[]','兩鬼投書，與僧聚語。',40,'全唐诗/poet.song.77000.json','["兩鬼投書，與僧聚語。", "師竊聞之，抱膝回顧。", "我心均平，等視諸趣。", "一念捨心，即離五怖。"]'),
('77f3f1d0-255a-471c-9554-057759af7a26','繡釋迦像并十八羅漢贊 第七迦理迦尊者','釋德洪','宋','宋诗','song-poetry','','[]','身如蕉虚，心如兔止。',40,'全唐诗/poet.song.77000.json','["身如蕉虚，心如兔止。", "師慈如和，侍者笑視。", "毒龍難降，我試彈指。", "便升鉢中，喜見脊尾。"]'),
('178c1b6b-4478-48f6-9488-7009111592ca','繡釋迦像并十八羅漢贊 第八闍羅弗多羅尊者','釋德洪','宋','宋诗','song-poetry','','[]','坐依胡牀，手把筇竹。',40,'全唐诗/poet.song.77000.json','["坐依胡牀，手把筇竹。", "偏袒右肩，而收一足。", "小僧滌器，師視而笑。", "主伴則殊，日用同妙。"]'),
('3013d33a-3ef6-424f-93a3-9b476f480be9','繡釋迦像并十八羅漢贊 第九戍博迦尊者','釋德洪','宋','宋诗','song-poetry','','[]','此琉璃瓶，中迸五色。',40,'全唐诗/poet.song.77000.json','["此琉璃瓶，中迸五色。", "是功德聚，善慈根力。", "僧俗儼然，殊迹同道。", "即事之理，一體三寶。"]'),
('42a07367-8785-4e2e-a671-b96412756f80','繡釋迦像并十八羅漢贊 第十半託迦尊者','釋德洪','宋','宋诗','song-poetry','','[]','手雖有拂，境以無塵。',40,'全唐诗/poet.song.77000.json','["手雖有拂，境以無塵。", "出三毒夢，乘五色雲。", "霜露果熟，慈忍現身。", "以空爲地，立處皆真。"]'),
('34b8e6bd-d5e2-4e88-87e0-f3e6da9d1baa','繡釋迦像并十八羅漢贊 第十一羅怙羅尊者','釋德洪','宋','宋诗','song-poetry','','[]','閑提數珠，背坐危石。',40,'全唐诗/poet.song.77000.json','["閑提數珠，背坐危石。", "捉錫山童，越樹而劇。", "象衘藕花，来獻法供。", "六根妙同，鼻能致用。"]'),
('fd470285-ff70-430b-9eb3-8fb1f1b250eb','繡釋迦像并十八羅漢贊 第十二那迦犀那尊者','釋德洪','宋','宋诗','song-poetry','','[]','苾芻捧塔，示空寂身。',40,'全唐诗/poet.song.77000.json','["苾芻捧塔，示空寂身。", "於菟對我，示心境真。", "手把寶書，而不展玩。", "又示解空，文字不斷。"]'),
('e3c1e650-b66e-40fd-b2d2-e5dabec74e5c','繡釋迦像并十八羅漢贊 第十三因羯陀尊者','釋德洪','宋','宋诗','song-poetry','','[]','情無住著，袒而憑几。',40,'全唐诗/poet.song.77000.json','["情無住著，袒而憑几。", "侍僧擊磬，狻猊卧戲。", "石屏倚天，下迸流水。", "水聲觸眼，石光到耳。"]'),
('6b52dc38-ccfa-4eee-aaa0-05b81fa13c0a','繡釋迦像并十八羅漢贊 第十四伐那波斯尊者','釋德洪','宋','宋诗','song-poetry','','[]','縦倚箕踞，莫不是定。',40,'全唐诗/poet.song.77000.json','["縦倚箕踞，莫不是定。", "毒既止息，邪亦自正。", "鉢花自香，蒲扇閑把。", "目視雲霄，我相未捨。"]'),
('fe39db02-7088-4254-b7b1-495e1dcdb8e2','繡釋迦像并十八羅漢贊 第十五阿氏多尊者','釋德洪','宋','宋诗','song-poetry','','[]','蠻奴鶴立，盆花置前。',40,'全唐诗/poet.song.77000.json','["蠻奴鶴立，盆花置前。", "倚杖屈足，頷髭虬然。", "了世間空，獨游理窟。", "石上軍持，是吾長物。"]'),
('0a768f22-b7c2-42f6-845e-8c9bed5683cb','繡釋迦像并十八羅漢贊 第十六注茶半託迦尊者','釋德洪','宋','宋诗','song-poetry','','[]','心花開敷，行象明潔。',40,'全唐诗/poet.song.77000.json','["心花開敷，行象明潔。", "翛然宴坐，秀目豐頬。", "萬象之語，六根之功。", "以手搏取，置不言中。"]'),
('7769bdd9-e439-4207-a7cf-496ec6dfbf2b','繡釋迦像并十八羅漢贊 第十七難提蜜多羅慶友尊者','釋德洪','宋','宋诗','song-poetry','','[]','風度凝遠，支頤而倦。',40,'全唐诗/poet.song.77000.json','["風度凝遠，支頤而倦。", "看此寶塔，至身出現。", "戲蠻弄毬，引此穉獸。", "萬用不藏，如日之晝。"]'),
('a3f79c9a-ab5b-4b20-96a4-165ccd4dd11f','繡釋迦像并十八羅漢贊 第十八賓頭盧尊者','釋德洪','宋','宋诗','song-poetry','','[]','夷奴碾茶，愚中有慧。',40,'全唐诗/poet.song.77000.json','["夷奴碾茶，愚中有慧。", "走鹿卧地，動中有止。", "而師持麈，閒坐俯視。", "曾見佛来，法法如是。"]'),
('1a51f533-91c1-451d-9f22-ff1d553e354a','放光二大士贊','釋德洪','宋','宋诗','song-poetry','','[]','人趣可學道，乃爲婬事苦。',186,'全唐诗/poet.song.77000.json','["人趣可學道，乃爲婬事苦。", "生那落迦中，方無婬欲樂。", "衆生如犛牛，愛此貪欲尾。", "異哉兩童子，藕花中化生。", "對天龍鬼神，作大師子吼。", "我若從今始，起於貪欲心。", "是則爲欺誑，十方一切佛。", "以是因緣故，證色身三昧。", "我亦于今日，復作師子吼。", "若從今日始，不斷貪欲心。", "是則爲滅絕，十方三世佛。", "願如二大士，持心等虚無。", "太虚有殞壞，衆生界有盡。", "我此願不盡，稽首平等慈。", "廣大同體悲。", "於刹刹塵塵，證我作是說。"]'),
('0789a900-8365-4437-ac5f-1a9fd9dbf7db','杏殻觀音菩薩贊','釋德洪','宋','宋诗','song-poetry','','[]','對現色身，色身三昧。',110,'全唐诗/poet.song.77000.json','["對現色身，色身三昧。", "如無邊春，透塵透海。", "使諸衆生，道與神會。", "知寂滅法，不以身礙。", "随欲觀者，非小非大。", "此銀杏殻，纖穠向背。", "百福莊嚴，千花自在。", "稽首大慈，如大地載。", "如皎空月，無所覆蓋。", "舍精進幢，如堅剛鎧。", "太虚殞消，我願不退。"]'),
('e8617f0b-24e4-425a-bb65-799a308590bc','李伯時畫彌陀像贊','釋德洪','宋','宋诗','song-poetry','','[]','以慈爲室，以忍爲衣。',180,'全唐诗/poet.song.77000.json','["以慈爲室，以忍爲衣。", "法空爲座，示同體悲。", "四十八願，爲世所歸。", "如日沒時，鳥接翅飛。", "大哉甘露，妙法縂持。", "令我觀門，洞開坦夷。", "諦見自心，妙絕知思。", "是皈依處，真不思議。", "律我意馬，使不妄馳。", "光明現前，見白蓮池。", "不假中陰，屈伸頃時。", "欣然化生，如八歲兒。", "何以至此，請審思之。", "皆我精進，想力所持。", "稽首妙湛，不動巍巍。", "令一切衆，絕癡暗疑。", "有同願者，但瞻導師。", "脱然蟬蜕，出五濁泥。"]'),
('e261086d-36db-4e18-99a2-cd361e8fa8c2','漣水觀音像贊','釋德洪','宋','宋诗','song-poetry','','[]','聲音語言形體絕，何以稱爲光世音。',352,'全唐诗/poet.song.77000.json','["聲音語言形體絕，何以稱爲光世音。", "聲音語言生滅法，何以又稱寂静音。", "凡有聲音語言法，是耳所觸非眼境。", "而此菩薩名觀音，是以眼觀聲音相。", "聲音若能到眼處，則耳能見諸色法。", "若耳實不可以見，則眼觀聲是寂滅。", "見聞既不能分隔，清浄寶覺自圓融。", "以無執故則有光，雖有千臂如兩手。", "以無分别故寂滅，雖有千手如一身。", "既無分别亦無執，雖有千眼兩目同。", "故稱光音寂静音，及觀世音三種異。", "稽首對現妙色身，徧一切處如虚空。", "妙哉此像非筆畫，厭足佛子欣慕心。", "藕絲銖衣春霧白，覆此随好光明聚。", "一切衆生熱惱滅，我手方捨甘露枝。", "唯佛子因心清浄，如水澄澈月清亮。", "借於畫工百巧技，如暗室眼以燈見。", "了知此畫非工有，謂燈能見其可哉。", "我無此像乃能贊，如眼見物不自見。", "自能說偈不蓄像，眼有見矣燈亦可。", "願持此大解脱門，施衆生作無所畏。", "世世但無礙辯才，稱贊觀世音功德。"]'),
('861fa694-78d2-463a-bb53-fa732fe11aa1','印上人持觀音像来乞贊余曰率伯時畫也爲作此贊','釋德洪','宋','宋诗','song-poetry','','[]','稽首浄勝光明聚，無礙慈忍精進幢。',96,'全唐诗/poet.song.77000.json','["稽首浄勝光明聚，無礙慈忍精進幢。", "清浄圓滿萬星月，分身如影分千江。", "佛子心如涔蹄水，随其清濁現影耳。", "從来但聞一月真，是影何從有非是。", "寒松瑟瑟哀霜風，愛此贊辭章句同。", "佛子正當以身讀，即滿追求顛倒欲。"]'),
('983068bc-fd76-4899-9e49-629721c0d7a0','衡山南臺寺飛来羅漢贊','釋德洪','宋','宋诗','song-poetry','','["\u5e90\u5c71", "\u8861\u5c71"]','惟毗尼藏，稱性之印。',200,'全唐诗/poet.song.77000.json','["惟毗尼藏，稱性之印。", "印一切法，無有少賸。", "而此尊者，跏趺不瞬。", "外寂中空，幻滅都盡。", "諸佛子等，勿故起妄。", "於是像中，作去来想。", "昔本不来，今亦焉往。", "即一切法，離一切相。", "如一月真，無二無别。", "於衆水中，同時見月。", "像非異同，月豈生滅。", "以應緣故，光影清絕。", "鍾山衆泉，石井異味。", "靈隱衆山，小嶺異翠。", "此嶺此泉，皆飛而至。", "示根境法，其實同體。", "如此大士，諸法成就。", "南嶽廬山，宴坐馳走。", "而事藏界，随處而有。", "雖證無生，亦不滅受。"]'),
('83955b31-a4c7-47a7-a27f-482e7a9dfc12','無爲山十生觀音贊','釋德洪','宋','宋诗','song-poetry','','[]','死生二法，了無實相。',80,'全唐诗/poet.song.77000.json','["死生二法，了無實相。", "世駭異之，墮顛倒想。", "公獨不然，十生一念。", "化緣之迹，皆可考驗。", "一切聲音，當以眼聽。", "俱不相參，以本寂静。", "要如菩薩，色相對現。", "何以必之，我有大願。"]'),
('58417c75-71e1-448d-a8c6-b79fec5c5691','第十五祖真贊','釋德洪','宋','宋诗','song-poetry','','[]','石彪肉醉，木駒夜嘶。',160,'全唐诗/poet.song.77000.json','["石彪肉醉，木駒夜嘶。", "我此三昧，非識情知。", "應緣而現，不落思惟。", "是故鉢水，以針投之。", "如仲尼韶，如子期琴。", "又如蕭何，而識淮陰。", "無言可寄，無迹可尋。", "粲然現前，傳之以心。", "穴像之目，我豈慢神。", "指樹之耳，我知其因。", "物我如是，所立皆真。", "随其妙用，見我全身。", "稽首真慈，爲僧中王。", "如萬星月，見者清凉。", "尚以衆生，不信爲傷。", "蓋盲者咎，非光掩藏。"]'),
('fb740637-4b76-4374-bd4b-ff797ba52e40','六世祖師畫像贊 初祖','釋德洪','宋','宋诗','song-poetry','','[]','妄想無性，證不滅受。',80,'全唐诗/poet.song.77000.json','["妄想無性，證不滅受。", "前聖所知，轉相授手。", "風煙花開，器界以形。", "霜露果熟，王子乃生。", "護持佛乘，指示心體。", "但遮其非，不言其是。", "嬰兒索物，意正語偏。", "哆啝之中，語意俱捐。"]'),
('32fcc23e-82c5-4496-9523-8c825753e09e','六世祖師畫像贊 二祖','釋德洪','宋','宋诗','song-poetry','','[]','頂峰朝露，神光夜生。',80,'全唐诗/poet.song.77000.json','["頂峰朝露，神光夜生。", "堪任單傳，荷擔上乘。", "自尋其心，不見歸宿。", "如視環輪，求其斷續。", "用獄除間，履瘦知肥。", "婬坊酒肆，盡其塵機。", "雪中斫臂，願續佛壽。", "兒孫聞之，竪毛呵手。"]'),
('ca96f03d-5bd6-45f3-9b16-97f28729b071','六世祖師畫像贊 三祖','釋德洪','宋','宋诗','song-poetry','','[]','六道暗昏，不礙明潔。',80,'全唐诗/poet.song.77000.json','["六道暗昏，不礙明潔。", "毫釐弗差，證甘露滅。", "但赤頭顱，特諱名氏。", "離見超情，欲盡世累。", "潛谿海山，麻衣風帽。", "翩然往來，被褐懷寶。", "精一其誠，聲名俱捨。", "後世丘墳，猶無知者。"]'),
('154f45b3-c53c-4fa8-ba2c-3464ac52b862','六世祖師畫像贊 四祖','釋德洪','宋','宋诗','song-poetry','','[]','破頭峰下，龍象雜遝。',80,'全唐诗/poet.song.77000.json','["破頭峰下，龍象雜遝。", "衣付小兒，道傳嬾衲。", "乃爾相違，求人爲法。", "天書至門，堅卧不答。", "念諸衆生，捕風捉影。", "十地治之，猶未蘇醒。", "師發笑曰，何必眩瞑。", "但勿强名，自然無病。"]'),
('212f3a99-9a8d-4508-8470-7d73c3ad0b87','六世祖師畫像贊 五祖','釋德洪','宋','宋诗','song-poetry','','[]','觀前後身，兩鏡一面。',80,'全唐诗/poet.song.77000.json','["觀前後身，兩鏡一面。", "左右對之，三者頓現。", "今非昔是，增金以黄。", "昔非今是，謗沉無香。", "已絕死生，豈纒老少。", "全機現前，常明而妙。", "夜江佐舟，吾今渡汝。", "句中之眼，如水有乳。"]'),
('1342d88d-2c60-4b48-90ff-517402ca3399','六世祖師畫像贊 六祖','釋德洪','宋','宋诗','song-poetry','','[]','是風旛動，眼自遮護。',80,'全唐诗/poet.song.77000.json','["是風旛動，眼自遮護。", "非風旛動，心則顯露。", "是謂曹谿，顯及要旨。", "欲證之者，勿留汝意。", "暫時斂念，妙寂了然。", "汝自受用，密非我邊。", "負石舂糧，趁獐逐兔。", "鏡中之空，欲尋無路。"]'),
('b648c90a-c286-47f2-82e8-60376dd73081','寶公畫像贊','釋德洪','宋','宋诗','song-poetry','','[]','水月道場嚴浄久，空華人世落殘餘。',32,'全唐诗/poet.song.77000.json','["水月道場嚴浄久，空華人世落殘餘。", "骨埋龍阜誰名寶，却在鷹巢不姓朱。"]'),
('c3477057-e47e-45f2-a958-d233900a60d4','棗柏大士畫像贊','釋德洪','宋','宋诗','song-poetry','','[]','鬚眉如畫頎而美，風神如秋氣奇偉。',256,'全唐诗/poet.song.77000.json','["鬚眉如畫頎而美，風神如秋氣奇偉。", "平生歸宿東北方，長勞動中寂而止。", "翛然跣足散衣行，智智用中不乖體。", "帝王家生得自在，壽量不書絕終始。", "虎受使令心境空，女爲伴助憎愛棄。", "冠巾傳心即俗真，方隅示法即事理。", "只將棗柏薦齋鉢，我来閻浮非著味。", "自然光明生齒牙，我談辭章皆實義。", "佛子授汝以顯訣，一言便足超十地。", "随順無明起諸有，若不随順有離異。", "聖賢酪生凡乳中，只由觀照戒定慧。", "是謂大士同體悲，令我頓入一切智。", "作大佛事徧塵刹，華藏界中容頓轡。", "以空爲坐禮十身，以願爲舌說千偈。", "如以花說無邊春，如以滴說大海味。", "稽首世間妙蓮華，願常清净出泥滓。"]'),
('123a66ac-3962-44b1-a664-1c6b24fcdec8','永嘉真覺大師真贊','釋德洪','宋','宋诗','song-poetry','','[]','情根無功，意識無作。',150,'全唐诗/poet.song.77000.json','["情根無功，意識無作。", "現量圓成，見聞知覺。", "如鏡受燈，光無壞雜。", "烈火焚燒，河流湍逝。", "谷風怒號，大地依止。", "俱無知思，亦復如是。", "此湼槃門，如鼓塗毒。", "曹谿撾之，聞者僵仆。", "以椎授公，萬像驚縮。", "光明之語，粲如日星。", "精嚴之行，清如玉冰。", "惟不傳者，與空相應。", "我初學道，如握與拳。", "晚乃覺之，如手安然。", "有時而用，搏取大千。"]'),
('b1f6504b-c912-45d0-8cf1-c6e31eca6bb3','百丈大智禪師真贊','釋德洪','宋','宋诗','song-poetry','','[]','以實問答，空可青黄。',100,'全唐诗/poet.song.77000.json','["以實問答，空可青黄。", "以意求道，神落陰陽。", "陰陽不測，脱略陰界。", "青黄摸畫，果因不昧。", "我有大機，佛無密語。", "如師子王，露地方踞。", "稱性文字，随分叢林。", "如以妙指，發和雅音。", "同世之波，壽九十二。", "護持心宗，謚曰大智。"]'),
('809b559e-0df8-4272-aaf1-66b639367fbb','大達國師無業公畫像贊','釋德洪','宋','宋诗','song-poetry','','[]','以如是觀，覺知見聞。',240,'全唐诗/poet.song.77000.json','["以如是觀，覺知見聞。", "性等太虚，卓然而存。", "示其身世，如空忽雲。", "應緣上洛，寄名李氏。", "在齠齓中，儼大乘器。", "坐必跏趺，行必直視。", "十二落髪，二十受具。", "能於諸佛，放身命處。", "解衣盤礴，從容笑語。", "江西指佛，即心最的。", "初亦不然，回首乃識。", "如眼照物，了證無惑。", "燕坐并汾，聲動天壤。", "有所問詰，戒莫妄想。", "兩朝致敬，累召不往。", "終不得已，別道以行。", "蓋視死生，洞若户庭。", "出入去来，物莫能攖。", "衆生拘囚，如蠅唾污。", "公如香象，卓立回顧。", "擺壞韁鎖，自在而去。", "公之所養，一至於兹。", "人英僧傑，龍章鳳姿。", "謚曰大達，憲穆之師。"]'),
('9aa575c6-6025-4342-9c39-289e6bfede74','赤眼禪師畫像贊','釋德洪','宋','宋诗','song-poetry','','[]','森森禪林，公特秀出。',120,'全唐诗/poet.song.77000.json','["森森禪林，公特秀出。", "輕世急道，不可跂及。", "遺風至今，秋霜烈日。", "我初瞻像，再拜稽首。", "一室嚴冷，如虎方吼。", "嗟余寡助，乃生公後。", "忍視大法，陵夷末運。", "奴婢小人，利欲迫窘。", "冀公一吒，腦破膽隕。", "嗚呼公乎，再見無由。", "冗攘方熾，何時云休。", "願起公死，從之以游。"]'),
('694878c0-4920-4c76-a941-d7ac76552aca','破竈墮和尚贊','釋德洪','宋','宋诗','song-poetry','','[]','嵩山屋老竈有神，民爭祠之日宰烹。',152,'全唐诗/poet.song.77000.json','["嵩山屋老竈有神，民爭祠之日宰烹。", "師與門人偶經行，即而視之因歎驚。", "此唯土瓦和合成，是中何從有聖靈。", "以杖敲之輙墮傾，須臾青衣出笑迎。", "謝師爲我談無生，言訖登空如鳥輕。", "門人問之拜投誠，伏地但聞破墮聲。", "君看一體情非情，皎如朗月懸青冥。", "未證據者以事明，鞭草血流石吼升，涅槃門開見户庭。", "老安憐兒爲作名，金屑雖貴翳眼睛。"]'),
('e71ab893-1621-4e3b-a34b-920bee49fa1f','永明禪師真贊二首  其一','釋德洪','宋','宋诗','song-poetry','','[]','三界種性，有萬妍醜。',110,'全唐诗/poet.song.77000.json','["三界種性，有萬妍醜。", "生順死逆，夢夜想晝。", "往復無間，聲度垣牖。", "皆依末那，戲論成就。", "而末那體，無作無受。", "譬如空花，實無而有。", "一念了知，光明通透。", "我如是見，無有錯謬。", "是爲心宗，祖佛授手。", "孰振頽綱，秀傑奇茂。", "稽首永明，月臨星斗。"]'),
('92f8b450-a267-419a-acd6-9e2209101239','永明禪師真贊二首  其二','釋德洪','宋','宋诗','song-poetry','','[]','以公風神，爲我律度。',20,'全唐诗/poet.song.77000.json','["以公風神，爲我律度。", "交神見之，是真保護。"]'),
('4d9df999-8ff1-4052-89bc-a613c75629f4','陳尊宿贊','釋德洪','宋','宋诗','song-poetry','','[]','雲門臨濟，一龍一夔。',80,'全唐诗/poet.song.77000.json','["雲門臨濟，一龍一夔。", "嗣存參運，皆公使之。", "叢林米嶺，衆不滿百。", "僉一典客，覺有難色。", "即袖手去，古寺閒房。", "織屨養母，自含其光。", "欽其遺風，秋滿鬚髪。", "唯不少貶，是真宏法。"]'),
('7803ff19-01f9-4f80-ba06-c73979a1d0c9','臨濟和尚贊','釋德洪','宋','宋诗','song-poetry','','[]','一句中具三玄，一玄中具三要。',28,'全唐诗/poet.song.77000.json','["一句中具三玄，一玄中具三要。", "腦後見腮村僧，向上更有一竅。"]'),
('8bde354d-b3e9-4e6f-af5c-5c658fe75d4f','長沙岑大蟲真贊','釋德洪','宋','宋诗','song-poetry','','[]','長沙大蟲，聲威甚重。',100,'全唐诗/poet.song.77000.json','["長沙大蟲，聲威甚重。", "獨眠空林，百獸震恐。", "寂子兒戲，見不知畏。", "引手捋鬚，幾缺其耳。", "大空小空，是虎是你。", "如備與覺，可撩其尾。", "嗟今衲子，眼如裴旻。", "但見其彪，安識虎真。", "我拜公像，非存非沒。", "百尺竿頭，行塵勃勃。"]'),
('a44ec48e-a603-45ae-a3f5-e3dfbc4b029f','清凉大法眼禪師真贊','釋德洪','宋','宋诗','song-poetry','','[]','非風幡動，非風鈴語。',110,'全唐诗/poet.song.77000.json','["非風幡動，非風鈴語。", "見聞起滅，了無處所。", "何以明之，俱寂静故。", "此光明藏，平等顯露。", "由本無明，愛欲慳妒。", "如隔日瘧，痛自遮護。", "有能了者，即同本悟。", "索爾虚閑，随緣静住。", "一切仍舊，自無染污。", "爲物作則，嶮崖之句。", "不可犯干，如大火聚。"]'),
('cb578a49-da06-4f54-914d-e73fd0ca3c61','玄沙宗一禪師真贊','釋德洪','宋','宋诗','song-poetry','','[]','根門有功，則是心外見法。',84,'全唐诗/poet.song.77000.json','["根門有功，則是心外見法。", "用處換機，則是問時有答。", "問答交馳，摸索大道。", "心法對峙，破碎真如。", "異哉此老，超出兩途。", "亡僧面前，波全露水。", "猛虎須畔，光自照珠。", "衲僧不識，如井覷驢。"]'),
('be01e07e-35e9-442c-a3d2-669bd79d9811','雲門匡真禪師畫像贊二首','釋德洪','宋','宋诗','song-poetry','','[]','見流滔天，公峙如山。',140,'全唐诗/poet.song.77000.json','["見流滔天，公峙如山。", "壁立萬仞，捍其狂瀾。", "可望而却，不可覽攀。", "犀顱虎眸，美髥繞頬。", "雲辭電機，霹靂爲舌。", "邪宗墮傾，魔膽破裂。", "須臾清明，光風霽月。", "叢林驢騾，蹴踏龍象。", "不可系羈，逸氣邁往。", "我不得濟，大地是浪。", "忽然現前，清機歷掌。", "阿羅漢有，三毒捺落。", "迦沒欛柄，咄哉黄面。", "淛子一生，喫著不盡。"]'),
('58e1b99c-6d71-4870-96b8-cdf430a4f4b4','南安巖主定光古佛木刻像贊','釋德洪','宋','宋诗','song-poetry','','[]','秦時𨍏轢，如刀口希。',180,'全唐诗/poet.song.77000.json','["秦時𨍏轢，如刀口希。", "廓然見前，石火莫追。", "法於是中，不著思惟。", "舉既不顧，咦之而往。", "天中函蓋，目機銖兩。", "久雨不晴，清機歷掌。", "孰傳其要，絕塵逸羣。", "深明二子，詳豁諸孫。", "維定光佛，出豁之門。", "以真如用，使令萬象。", "反易黠魯，縦奪雨暘。", "洗癡暗目，回顛倒想。", "示汝語言，一切智畏。", "如月入水，如風行空。", "無所妨礙，贈以之中。", "又復憐汝，□□未識。", "方其死時，謂是生日。", "如光照珠，如甜說蜜。"]'),
('bf584c13-d455-468b-b9bc-5bef344d50a8','毛氏所蓄巖主贊','釋德洪','宋','宋诗','song-poetry','','[]','此像爲誰，天中之尊。',120,'全唐诗/poet.song.77000.json','["此像爲誰，天中之尊。", "道傳雲門，爲四世孫。", "白帽蒙首，鬚髯繞頬。", "見之清凉，洗煩惱熱。", "以偈爲檄，指撝造化。", "詩乃辦兩，出於咄嗟。", "以境惟心，往復無間。", "是故死時，亦生之旦。", "怒猊乳虎，亦生敬虔。", "何以致之，真慈則然。", "南率古□，形如側磬。", "稽首定光，千江月影。"]'),
('f95d662f-965f-405d-b8fa-0dc0a1be94a0','小字華嚴經贊','釋德洪','宋','宋诗','song-poetry','','[]','我聞尊者龍勝師，應供曾入娑竭海。',384,'全唐诗/poet.song.77000.json','["我聞尊者龍勝師，應供曾入娑竭海。", "龍宫微塵妙章句，目所一瞥輙能誦。", "流於五天及震旦，爲熱惱中甘露門。", "唯道人棲出其後，願力猛利思精特。", "能於方策紙墨間，書此大經十萬偈。", "誦於蝸舍巢菴中，了然如在龍宫見。", "觀者種性有差别，愛慕皆生殊異想。", "要當諦觀一塵中，亦有無邊妙經卷。", "昔有智人破此塵，十方世界一切說。", "以名塵故非斷空，而可破故非實有。", "了此兩宗妙法門，亦攝一切契經海。", "譬如困卧俄頃際，夢中所歷更千載。", "乃知一念圓古今，真實際中法如是。", "一微塵妙不可測，當知一一塵亦然。", "譬如天帝網明珠，珠體瑩然俱照徹。", "一珠具足諸網珠，一一珠中同徧入。", "我今以此金剛句，壞滅彼衆下劣想。", "使悟塵中含此經，奚方策中乃驚異。", "咨爾山君河樹神，各各當憶本願力。", "要當勇猛勤守護，勿令邪念輙蠧侵。", "毗藍風吹須彌盧，劫火焚燒大千界。", "爲攤此經一切處，使其涼曝各得所。", "我此現前佛子等，作是觀者名正觀。", "稽首十方調御師，刹刹塵塵爲作證。"]'),
('ce4e1e7f-2204-4a39-90d2-7d82d09f487f','小字金剛經贊','釋德洪','宋','宋诗','song-poetry','','[]','昔有佛子根猛利，能觀空性則是色。',192,'全唐诗/poet.song.77000.json','["昔有佛子根猛利，能觀空性則是色。", "欲顯空色不思議，仰空書此金剛句。", "至今風雨被原野，諸樵牧者集其下。", "乃知肉眼不能見，譬如水中有鹽味。", "唯道人瓊思精奇，能觀色性即是空。", "視此纖管大如椽，揮翰如行九軌道。", "故於兼寸環中備，足廣大言說身世。", "人可見，不可讀，譬如嬰兒親崖蜜。", "我於此經能證入，初中後善三法門。", "忽然落筆如建瓴，不復現行生倒想。", "由色空觀入諸境，奏刀肯綮無全牛。", "盡持此法施羣生，甚微細智願同證。"]'),
('b7a3683e-fcdd-4f1c-a2ac-f8e4c97d1639','東坡畫應身彌勒贊','釋德洪','宋','宋诗','song-poetry','','[]','唯老東坡，秀氣如春。',90,'全唐诗/poet.song.77000.json','["唯老東坡，秀氣如春。", "游戲翰墨，撾雷翻雲。", "偶寄逸想，幻此沙門。", "了無一事，荷囊如奔。", "憨腮皤腹，行若不聞。", "衆生狂迷，以利欲昏。", "如一器中，閙萬虻蚊。", "吾未暇度，駝卧猿蹲。", "傲睨一世，随處乾坤。"]'),
('d3d1f047-5c6d-43c6-b4fb-3f25746ff048','出檀衣贊二首  其一','釋德洪','宋','宋诗','song-poetry','','[]','古佛身上衣，佛佛相付授。',156,'全唐诗/poet.song.77000.json','["古佛身上衣，佛佛相付授。", "慈母愛兒心，鍼鍼自成就。", "是故吾雙峰，自少至白首。", "護惜如鏡奩，一塵不敢受。", "何以出檀名，此時無别慮。", "如持油鉢行，如躡獨木渡。", "永懷毗尼藏，一旦成萬古。", "紛紛五羣衆，来觀亦頂禮。", "平時放逸心，化作額間泚。", "將見衣匣前，泚流似江水。", "咨爾淮山神，守護當奉職。", "無使塵涴侵，無使雲潤濕。", "諦觀不敢瞬，心折三歎息。"]'),
('5fa261a1-4246-4dbe-94d7-e9b41da9ab0b','出檀衣贊二首  其二','釋德洪','宋','宋诗','song-poetry','','[]','此出檀衣，慈母授我。',60,'全唐诗/poet.song.77000.json','["此出檀衣，慈母授我。", "不敢手撲，矧敢覆卧。", "五十餘年，儼臨清衆。", "寒暑不易，盡形受用。", "師後當知，商那和老。", "於母腹中，披九枝草。"]'),
('81cb1bcb-6912-4c0d-93b3-23c1576547bb','傳衣閣贊','釋德洪','宋','宋诗','song-poetry','','[]','達磨信衣，轉相傳付。',70,'全唐诗/poet.song.77000.json','["達磨信衣，轉相傳付。", "四傳至今，今以付汝。", "受授惟艱，命如懸絮。", "法徧沙界，此衣乃住。", "想見峰前，父子相語。", "唯僧行月，以閣其處。", "坐令朱欄，環繞雲雨。"]'),
('822bbbef-180a-4838-a305-a5d75dc5d977','栽松道者真身贊','釋德洪','宋','宋诗','song-poetry','','[]','生死變滅，如漚在海。',90,'全唐诗/poet.song.77000.json','["生死變滅，如漚在海。", "無有處所，浩然茫昧。", "而此老人，游戲自在。", "出死入生，初無限礙。", "譬如壯士，脱袍著鎧。", "令鎧與袍，儼然相對。", "是故山中，兩身俱在。", "凡夫衆生，爲眼所蓋。", "爲抉其膜，使生光彩。"]'),
('2342bd8c-a9c8-4b8d-8cfb-a82982a57444','定身巖贊','釋德洪','宋','宋诗','song-poetry','','[]','淮山深處，容我卓錫。',90,'全唐诗/poet.song.77000.json','["淮山深處，容我卓錫。", "樹下經行，巖間宴寂。", "六十餘年，脇不至席。", "天子三詔，掉頭不應。", "知不可致，南向加敬。", "山揺海驚，天空地迥。", "後代兒孫，則反於是。", "如乳中蟲，貪嗜世味。", "我尋其迹，爲隕涕淚。"]'),
('53814940-987a-4b02-a986-9097c748ff2d','五祖慈覺贊','釋德洪','宋','宋诗','song-poetry','','[]','龍湖山上霹靂，馬駒潭畔門庭。',84,'全唐诗/poet.song.77000.json','["龍湖山上霹靂，馬駒潭畔門庭。", "千聖莫能窺測，十地望崖震驚。", "霜露果熟推出，白蓮峰下芬馨。", "不受聲名控勒，逸群勝氣英靈。", "試問是何宗旨，東山雲霞空青。", "海堂室中神穎，汾陽直下雲仍。"]'),
('fd294e32-091b-4d83-9edb-68a5e752c5b5','癩可贊','釋德洪','宋','宋诗','song-poetry','','[]','父伯固，兄養直。',48,'全唐诗/poet.song.77000.json','["父伯固，兄養直。", "父超絕，兄豪逸。", "家世風流稱第一。", "二祖名，三祖疾。", "名是虚，疾是實。", "詩成舌頭翻霹靂。"]'),
('0991bc61-df7f-4f02-86b2-236f6bb8e546','醉僧贊','釋德洪','宋','宋诗','song-poetry','','[]','我愛龍眠老居士，筆端談笑了萬事。',64,'全唐诗/poet.song.77000.json','["我愛龍眠老居士，筆端談笑了萬事。", "君看一時拈破筆，畫作醉僧醒時意。", "此是沙門絕妙門，不妨随處有乾坤。", "瞢騰流涎枕臂卧，破柱疾雷殊不聞。"]'),
('93357487-87f8-4394-827b-7993c3520daa','石霜普照珂禪師贊','釋德洪','宋','宋诗','song-poetry','','[]','漆瞳照座，骨相巉巖。',40,'全唐诗/poet.song.77000.json','["漆瞳照座，骨相巉巖。", "横拈麈拂，寒擁雲衫。", "五住名刹，道振湘南。", "是誰之子，親見雲庵。"]'),
('33f84f18-0c5f-43bf-a468-a45db7087d97','疏山仁禪師贊','釋德洪','宋','宋诗','song-poetry','','[]','三支習氣，其毒熾然。',100,'全唐诗/poet.song.77000.json','["三支習氣，其毒熾然。", "熏烝識心，盤屈糾纒。", "衆生不明，横生疑怖。", "忽然見之，輙自驚仆。", "空花世間，本離生滅。", "廓然十方，露其窘宂。", "唯矬師叔，是大幻師。", "與奪萬法，自在娱嬉。", "乃知大千，皆公戲具。", "手中木蛇，是曹家女。"]'),
('e99e55ec-60b7-4def-8a87-161b50616667','汾陽昭禪師真贊','釋德洪','宋','宋诗','song-poetry','','[]','維摩杜口，釋迦饒舌。',40,'全唐诗/poet.song.77000.json','["維摩杜口，釋迦饒舌。", "動容顧瞻，非默非說。", "雖宣一字，不露點墨。", "稽首汾陽，千聖同轍。"]'),
('251ea476-1bfd-4b95-90c3-732eab61ac04','翠巖真禪師真贊','釋德洪','宋','宋诗','song-poetry','','[]','我方涇渭同流，笑中軟頑滑頭。',54,'全唐诗/poet.song.77000.json','["我方涇渭同流，笑中軟頑滑頭。", "爲君人境俱奪，閙裏白拈巧偷。", "如水洗水，相樓打樓。", "從来脱略無窠臼，接得南泉嗣趙州。"]'),
('ada2c18c-4774-45b8-a4a8-5618c98b5b1c','慈明禪師真贊','釋德洪','宋','宋诗','song-poetry','','[]','緣生諸法名體絕，如空字身水魚迹。',160,'全唐诗/poet.song.77000.json','["緣生諸法名體絕，如空字身水魚迹。", "是無相門緣寂宗，一切智智差别海。", "公於是中如法船，汎然出沒無所畏。", "使諸游者心泰定，種種驚怖成虛空。", "平生神兵雙不借，玄機不動萬象驚。", "而公宴坐不言中，諸有求心如古井。", "鈍根阿師終聽瑩，法味迷醉如惺惺。", "矍然奮迅爲一戲，句裏明人揳出揳。", "紫金鎖骨眠空山，吁嗟音容不可覿。", "當知其聲如雷霆，稽首慈明常出現。"]'),
('12061a10-8306-4e27-ad0d-7d0eb1a14bc5','郴州乾明進和尚舍利贊','釋德洪','宋','宋诗','song-poetry','','[]','李廣射虎，石爲之穿。',200,'全唐诗/poet.song.77000.json','["李廣射虎，石爲之穿。", "耿恭祝井，涸爲之泉。", "忠孝所致，如響答焉。", "公亦何爲，饑餐困眠。", "人初莫測，公豈自言。", "戲爲火浴，朽者明鮮。", "舍利粲粲，玉碎珠圓。", "乃至所養，蓋其云全。", "天全之妙，非麤不傳。", "如春在花，如意在絃。", "嗤嗤横目，氣凌雲天。", "死未及寒，化爲腥膻。", "矧投于火，不作腥煙。", "安有萬手，收此精堅。", "維德之一，垔所拳拳。", "死生之大，卒莫能遷。", "公初設心，唯此是専。", "不祈人知，人趨如川。", "終必有驗，理之固然。", "我作贊詞，豐碑以鐫。"]'),
('250cbf57-f679-4850-ae0a-c0bea4905e9d','南嶽彌陀和尚贊','釋德洪','宋','宋诗','song-poetry','','["\u8861\u5c71"]','與之食則食，與之衣則衣。',60,'全唐诗/poet.song.77000.json','["與之食則食，與之衣則衣。", "無衣衣木葉，無食食土泥。", "爲人汲樵牧，僅存骨與皮。", "其道不可致，天子南向師。", "出家有如子，我亦著伽梨。"]'),
('31f0aefe-7da5-4edb-9b08-d82f7fe3f90f','宣律師贊','釋德洪','宋','宋诗','song-poetry','','[]','此毘尼藏，三世完堅。',100,'全唐诗/poet.song.77000.json','["此毘尼藏，三世完堅。", "願王手封，款識具全。", "死生之烈，不能變遷。", "何以至之，正知則然。", "何人逸想，以筆墨傳。", "跏趺俯視，頽然深淵。", "天神護持，弟子敬虔。", "我拜稽首，淚滴九泉。", "法道凌夷，障雲蓋纒。", "乃於是時，瞻此釋天。"]'),
('6f1bba62-3940-4d04-82b6-e6a1c2f2975d','嵩禪師贊','釋德洪','宋','宋诗','song-poetry','','[]','歐陽之學，師宗於世。',160,'全唐诗/poet.song.77000.json','["歐陽之學，師宗於世。", "其徒喧闐，攻我以喙。", "童首儒林，氣索力屈。", "公於是時，粹然一出。", "天縦之辯，武庫縱横。", "璜璣捍我，如護目睛。", "義如串肉，理如析薪。", "一時名譽，聳動縉紳。", "世尊舉身，毛孔俱笑。", "如公語言，筆下皆妙。", "六物不壞，未易致詰。", "豈其踐履，明驗之力。", "宗教之衰，河壞山摧。", "冠巾緇衲，其寒如灰。", "拂拭塵翳，見冰雪容。", "拜起而喟，涕落無從。"]'),
('25c177c9-9f44-4005-9686-636a73af5a6c','雲庵和尚贊三首  其一','釋德洪','宋','宋诗','song-poetry','','[]','於自住境，見與見緣。',100,'全唐诗/poet.song.77000.json','["於自住境，見與見緣。", "如夢能所，如蜜中邊。", "帷具正眼，入此三昧。", "如妙蓮華，出緣生海。", "祖師活意，如来密機。", "成就衆生，如鵾鵬飛。", "使其自化，不由他悟。", "秀出叢林，光于佛祖。", "趨滅陕右，誕生江南。", "暗中五色，天下雲庵。"]'),
('b88410a4-05a0-47ea-9e50-88516fcbc222','雲庵和尚贊三首  其二','釋德洪','宋','宋诗','song-poetry','','[]','槁容而毳衣，殆不逾於中人。',129,'全唐诗/poet.song.77000.json','["槁容而毳衣，殆不逾於中人。", "而於祖道顛危之秋，勃然而中興。", "知我亦何幸，自幼及壯。", "出入其户庭，俯仰其藩籬。", "而其道德之精華，未能略窺其毫微。", "譬如戴天履地於終日，而其高明深厚所不能知。", "惟聞孔子之歿一百年而生孟子，釋迦之寂二千歲而有禪師。", "拜手稽首，堂堂乎三界之依者耶。"]'),
('6ba1653e-3bbf-49d4-8ab2-39ecb527daff','雲庵和尚贊三首  其三','釋德洪','宋','宋诗','song-poetry','','[]','三玄銓量，設選佛科。',40,'全唐诗/poet.song.77000.json','["三玄銓量，設選佛科。", "邪師壞之，付授外訛。", "以陷虎機，擊其頽波。", "不動聲氣，怖走天魔。"]'),
('7f1c082c-05b8-4a61-8823-910f1fee2c16','潛庵源禪師真贊一首','釋德洪','宋','宋诗','song-poetry','','[]','十年積翠侍立，學得眼横鼻直。',60,'全唐诗/poet.song.77000.json','["十年積翠侍立，學得眼横鼻直。", "平生氣壓叢林，問著左科背聽。", "一庵深藏霹靂，舌從教萬象自分說。", "百非四句無處蹲，孤風照人衆星月。"]'),
('b45ac018-03c1-48cd-a926-a9deb4b4266c','僧求潛庵贊','釋德洪','宋','宋诗','song-poetry','','[]','德臘俱難及，一庵江寺隈。',48,'全唐诗/poet.song.77000.json','["德臘俱難及，一庵江寺隈。", "敢稱少室後，親見老南来。", "鬢雪殘零盡，心花爛熳開。", "若言只這是，九尾似黄能。"]'),
('c4d93aec-8de1-4783-ae66-c3c3113c0834','游龍山斷際院潛庵常居之有小僧乞贊戲書其上','釋德洪','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','趙州只有一箇齒，潛庵一個恐不趐。',64,'全唐诗/poet.song.77000.json','["趙州只有一箇齒，潛庵一個恐不趐。", "雖然下下都咬著，鹹酸自分鹽醋味。", "龍興古寺曾閉門，斷際雲孫第十世。", "勸人莫信馬大師，一口吸盡西江水。"]'),
('ec0acdf3-6985-47d4-b0f6-c7c037e766dd','靈源清禪師贊五首  其一','釋德洪','宋','宋诗','song-poetry','','[]','辯如玄沙有邊幅，韻如睦州出風骨。',64,'全唐诗/poet.song.77000.json','["辯如玄沙有邊幅，韻如睦州出風骨。", "默然而說心自昭，八荒光明寄毛粟。", "獨立南榮山嶽峻，臨濟欲傾不敢覆。", "笑横玉麈氣如春，一堂嚴冷天魔哭。"]'),
('c9bea18b-27f2-4828-a822-da286894ccf9','靈源清禪師贊五首  其二','釋德洪','宋','宋诗','song-poetry','','[]','衲子無處摸索，畫師筆筆畫著。',42,'全唐诗/poet.song.77000.json','["衲子無處摸索，畫師筆筆畫著。", "山僧醉眼難憑，付與衆人彈駁。", "似則打殺靈源，不似㡠子燒却。"]'),
('c032ebc5-37d4-485c-8ddb-c27f13a8d0f2','靈源清禪師贊五首  其三','釋德洪','宋','宋诗','song-poetry','','[]','魔外如驚濤，大願真砥柱。',40,'全唐诗/poet.song.77000.json','["魔外如驚濤，大願真砥柱。", "生與海衆同，沒與海衆處。", "兀然引带笑不言，從教大地山河語。"]'),
('5e56b060-4c84-4bae-9776-423f9a1b4aa4','靈源清禪師贊五首  其四','釋德洪','宋','宋诗','song-poetry','','[]','風度凝遠，杳然靖深。',40,'全唐诗/poet.song.77000.json','["風度凝遠，杳然靖深。", "如春在花，如意在琴。", "雖甚昭著，莫可追尋。", "蹶起臨濟，如磁石針。"]'),
('749f7d45-6fe2-41a2-97fa-0ae1a82a2948','靈源清禪師贊五首  其五','釋德洪','宋','宋诗','song-poetry','','[]','披衣肯来，奔百川而地喘。',52,'全唐诗/poet.song.77000.json','["披衣肯来，奔百川而地喘。", "袖手歸去，碧一天而電收。", "閉門無個事，兀坐青兩眸。", "喝月倒行前日令，呼山入坐上簾鈎。"]'),
('872a0123-401a-4d5d-a5c4-5f6b2088ab74','雲蓋生日三月初七報慈僧持真求贊','釋德洪','宋','宋诗','song-poetry','','[]','平生脊骨，生鐵鑄就。',94,'全唐诗/poet.song.77000.json','["平生脊骨，生鐵鑄就。", "關門理鉏，揎起兩手。", "禪者見之，立不敢久。", "問未及答，已欲返走。", "如老黄龍機鋒，如英邵武□叟。", "如雪峰之嶮，如百丈之壽。", "末後報慈寺中，笑中打箇筋斗。", "試問是何宗旨，代云合取狗口。"]'),
('3dccf44d-1fca-44ba-8afe-fc090d13b638','黄龍草堂清禪師贊','釋德洪','宋','宋诗','song-poetry','','[]','黄覺晚子，死心季弟。',48,'全唐诗/poet.song.77000.json','["黄覺晚子，死心季弟。", "住黄龍山，爲十二世。", "青春無背面，空花有根蒂。", "欲識晦堂背觸拳，寒到黄河凍連底。"]'),
('0eb418ec-7cb8-426f-bb89-845555bbfbcf','香城瑛禪師贊','釋德洪','宋','宋诗','song-poetry','','[]','黄龍三關，初豈拒人。',80,'全唐诗/poet.song.77000.json','["黄龍三關，初豈拒人。", "見者佇思，剩却法身。", "祐公掉臂直去，悦公追之絕塵。", "維瑛實兩公之後，觀其滿腹精神。", "木牀足折，續之以薪。", "則三十年後，當令天下聞之甚富，見之甚貧也。"]'),
('b29835ef-76ec-4047-b66f-2ce39cf9feb3','龍城智公真贊','釋德洪','宋','宋诗','song-poetry','','[]','奉持毗尼，珪璧無玷。',80,'全唐诗/poet.song.77000.json','["奉持毗尼，珪璧無玷。", "研味般若，金剛有焰。", "有萬其衆，感以無心。", "如象牙雷，如磁石針。", "住持此山，垂三十白。", "殿閣化成，兒孫戢戢。", "高明廣大，不可形容。", "稽首寄老，後身寶公。"]'),
('8238fd83-7efb-4d0e-ac27-3e4a98c5ca4f','石頭志庵主贊','釋德洪','宋','宋诗','song-poetry','','[]','自住石頭，老無氣力。',36,'全唐诗/poet.song.77000.json','["自住石頭，老無氣力。", "一回上山，一回氣急。", "禪流相見問宗風，一日兩度鉢盂濕。"]'),
('7a994f87-2f91-407c-bfc9-eec395581183','華藥英禪師贊','釋德洪','宋','宋诗','song-poetry','','[]','以鐵作喙，名無有雙。',100,'全唐诗/poet.song.77000.json','["以鐵作喙，名無有雙。", "老住回雁，道冠湘江。", "神機之妙，如鐘在撞。", "爲功德林，爲精進幢。", "不動聲氣，天魔自降。", "懷我雲庵，黄龍的嗣。", "說法如雲，縦横放肆。", "孰知此老，膽氣相似。", "大法付授，良亦在此。", "是名關西，克家之子。"]'),
('bd8a8f39-cdda-4aee-98ec-ffc1b4507974','寶峰凖禪師贊','釋德洪','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','洞庭無蓋，虚空有口。',62,'全唐诗/poet.song.77000.json','["洞庭無蓋，虚空有口。", "步水東山，藏身北斗。", "石門壁立萬仞，踞地一聲哮吼。", "驚得四序回旋，喝下須彌倒走。", "是謂湛堂老人，不落威音之後。"]'),
('37815c66-b95a-4405-a8f1-8cbf290439f1','芙蓉楷禪師贊','釋德洪','宋','宋诗','song-poetry','','[]','望之翛然，冰枯而天粹。',167,'全唐诗/poet.song.77000.json','["望之翛然，冰枯而天粹。", "即之淵然，雲閑而水止。", "意坐石而情無住著，故杖瘦藤而欲起。", "人言即俗復即真，出塵之相加冠巾。", "非因引法忤聖主，我宗僧俗兩不存。", "五位正宗將仆地，以手挈之閲人世。", "屹然萬仞捍狂瀾，荷負大法當如是。", "紛紛鄙夫拜公像，譬如螻螘見龍象。", "驚魂已化千微塵，豈特形容先沮喪。", "火刀直裰誰得之，醉李故時捕魚師。", "嶺梅已熟莫咬破，核子乞與寧馨兒。"]'),
('99c666da-b851-4560-8780-8980039c56e0','妙高仁禪師贊','釋德洪','宋','宋诗','song-poetry','','[]','春風入其肺肝，秋色潄其毛骨。',58,'全唐诗/poet.song.77000.json','["春風入其肺肝，秋色潄其毛骨。", "名飛縉紳之間，身卧雲泉之窟。", "嶽頂鳳之真子，僧中龍之的孫。", "吹徹風前無孔笛，露香和月落紛紛。"]'),
('5b655d45-ebaa-4e63-a25d-0e4d4fe195fc','道林枯木成禪師贊','釋德洪','宋','宋诗','song-poetry','','[]','揚廣山頭種性，雷衡洞裏根苗。',92,'全唐诗/poet.song.77000.json','["揚廣山頭種性，雷衡洞裏根苗。", "法雲明暗體露，道林知見香飄。", "試問春風吹不起，何如黄河凍連底。", "十分似九不欲全，一身兩號只這是。", "大千戲以一塵攝，又譬此塵取空劫。", "置於掌間剔突圞，撾鼓升堂普請看。"]'),
('f6e2bb1a-bcbf-453b-bd46-7fc7ebd4b53c','佛印璵禪師贊','釋德洪','宋','宋诗','song-poetry','','[]','臨濟正宗，有楊歧會。',96,'全唐诗/poet.song.77000.json','["臨濟正宗，有楊歧會。", "化四十年，叢林精彩。", "唯端精神，辯博無礙。", "克肖其家，溈仰猶在。", "後出舒勤，骨面氣槩。", "始自太平，遂游智海。", "如法中龍，游戲三昧。", "璵也其後，斫額前輩。", "要識當年栗棘蓬，白藕火中香不改。"]'),
('94a5cfef-a86a-44c5-b905-f42443f8782f','溈山軾禪師贊','釋德洪','宋','宋诗','song-poetry','','[]','天骨巖巖，美髯玉頬。',60,'全唐诗/poet.song.77000.json','["天骨巖巖，美髯玉頬。", "冰雪在躬，霹靂爲舌。", "軒昂萬僧，衆星中月。", "視其心胸，山包海容。", "大溈小興，振其家風。", "叢林百世，見者肅恭。"]'),
('9cdc0076-83a7-4458-8991-3a57aa692659','報慈宣祕禪師贊','釋德洪','宋','宋诗','song-poetry','','[]','二百員衲子領袖，三十年叢林耆舊。',60,'全唐诗/poet.song.77000.json','["二百員衲子領袖，三十年叢林耆舊。", "所至樓閣森然，自然眷屬成就。", "諸方度脚買鞵，報慈就身剪裁。", "莫嫌此老無巴鼻，曾見西堂古佛来。"]'),
('a012a718-5229-4fd3-ae89-e7739f7f632b','臨平慧禪師贊二首  其一','釋德洪','宋','宋诗','song-poetry','','[]','釘空露痕迹，補雲留罅隙。',83,'全唐诗/poet.song.77000.json','["釘空露痕迹，補雲留罅隙。", "目機銖兩中，思慮所不及。", "象王卓立回旋，師子翻身跳躑。", "眼光常蓋人天，對面識與不識。", "識則火外有熱，不識則水中無濕。", "劈破雲門一字關，個中乾燥如瓊液。"]'),
('4328289e-2220-445f-87b8-ab6b3cdaa85b','臨平慧禪師贊二首  其二','釋德洪','宋','宋诗','song-poetry','','[]','㘞氣秋腴雪，秀目椹口。',59,'全唐诗/poet.song.77000.json','["㘞氣秋腴雪，秀目椹口。", "其骨臨濟，其髄雪竇。", "袖手儼然，不落滲漏。", "一千龍象之冠，七世雲門之後。", "君看一句當機，笑中脱略窠臼。"]'),
('a9c08539-4c0b-47f3-9dad-654cbcfb33e8','上藍忠禪師贊','釋德洪','宋','宋诗','song-poetry','','[]','一法能知一切法，應機全不差毫髪。',64,'全唐诗/poet.song.77000.json','["一法能知一切法，應機全不差毫髪。", "如是知見如是解，於一切法中對待。", "平生脊梁硬如鐵，衲僧尋思心智絕。", "城中一室冷如冰，篆煙滅盡灰如雪。"]'),
('fb1aa465-8ae2-4ff8-899c-944c335376c5','雙峰演禪師贊','釋德洪','宋','宋诗','song-poetry','','[]','三關洞開無鏁扃，汝自艱難起戰兢。',64,'全唐诗/poet.song.77000.json','["三關洞開無鏁扃，汝自艱難起戰兢。", "師過此關悉閒暇，掉臂徑趨呼不譍。", "如春消冰自渙釋，如鯤化鵬誰使令。", "歸来笑搭出檀服，依舊淮山千萬青。"]'),
('2a3d8d93-58d8-46dd-89b7-d6061955329b','雲庵和尚舍利贊','釋德洪','宋','宋诗','song-poetry','','[]','是身夢境一塵垢，分段苦業所成就。',176,'全唐诗/poet.song.77000.json','["是身夢境一塵垢，分段苦業所成就。", "折旋俯仰誰使之，皆汝一念顛倒想。", "若言此身非念倫，云何想中可傳令。", "乃知妄想融通趣，如露如幻如雲影。", "念清浄則身光明，念雜想則身垢穢。", "君看火力初無情，聖凡僞真俱發夢。", "雲庵偏得老南道，粹然一出支臨濟。", "平生慈悲喜捨力，及樂說辯智慧光。", "大願所熏精進幢，上契佛祖超情見。", "至妙要非麤不傳，憫世狹劣示小者。", "稽首作贊示同學，千載叢林有耿光。"]'),
('cfb082f4-6c64-4c85-a16c-45f87a55b59d','死心禪師舍利贊','釋德洪','宋','宋诗','song-poetry','','[]','地水火風，動暖堅濕。',50,'全唐诗/poet.song.77000.json','["地水火風，動暖堅濕。", "是中何從，出此堅實。", "蓋衆生心，引大法力。", "化爲光明，圓粹五色。", "稽首死心，罵人老賊。"]'),
('8d273250-2b43-451e-9fb9-b0e4733cf338','寂音自贊四首  其一','釋德洪','宋','宋诗','song-poetry','','[]','竄朱崖軍而生，還遭黄茆瘴而復活。',84,'全唐诗/poet.song.77000.json','["竄朱崖軍而生，還遭黄茆瘴而復活。", "陷於采石而不死，囚於并門而自脱。", "夜行有披袖神光，露卧醉壓糟醇濁。", "魔外熟視之無如之何，佛祖不得已與之酬酢。", "兩眼入鬢頭髼鬆，手中木蛇毒如藥。"]'),
('307d40d8-f690-4542-b37c-ccf882a91328','寂音自贊四首  其二','釋德洪','宋','宋诗','song-poetry','','[]','三玄綱宗，壁立崔嵬。',60,'全唐诗/poet.song.77000.json','["三玄綱宗，壁立崔嵬。", "攀緣路絕，熱惱心灰。", "如化鯤鵬，不借風雷。", "蓋自化耳，寧有法哉。", "汾陽此祕，寂音掲開。", "手提大千，毫端往来。"]'),
('54a53cea-f399-4ba9-bd7e-0ebfaf1c1012','寂音自贊四首  其三','釋德洪','宋','宋诗','song-poetry','','[]','不似成背，似其成觸。',52,'全唐诗/poet.song.77000.json','["不似成背，似其成觸。", "随汝顛倒，直中有曲。", "抛在言前剔鶻崙，擬議令渠總滅門。", "平生活計無窖子，真是汾陽五世孫。"]'),
('e89aadcd-f30e-4c63-b10c-43735f000b15','寂音自贊四首  其四','釋德洪','宋','宋诗','song-poetry','','[]','随緣放曠，索爾虚閑。',20,'全唐诗/poet.song.77000.json','["随緣放曠，索爾虚閑。", "未埋白骨，且看青山。"]'),
('c6dc024e-2f33-48d7-a7b6-b06cc12c84f9','毛女贊','釋德洪','宋','宋诗','song-poetry','','[]','不嗅梨花，而撚紫芝。',100,'全唐诗/poet.song.77000.json','["不嗅梨花，而撚紫芝。", "不穿雲袖，而披槲衣。", "何以風神，洞如冰雪。", "使人見之，眼寒心折。", "如麝有香，以缶覆焉。", "透塵透風，種性則然。", "又如煙雨，過孤山宅。", "於荒寒中，微見春色。", "圖之壁間，是真過秦。", "季子好德，白髪日新。"]'),
('c310209d-13ac-4976-addd-365bf8f75710','解空居士贊','釋德洪','宋','宋诗','song-poetry','','[]','空若不解，即是斷空。',50,'全唐诗/poet.song.77000.json','["空若不解，即是斷空。", "解若不空，即是法執。", "是故居士，獨號解空。", "窠臼不立，凡聖豈存。", "是誰宗旨，臨濟仍雲。"]'),
('c208495a-1c7a-4346-b2c0-a171d0fa5473','東坡居士贊','釋德洪','宋','宋诗','song-poetry','','[]','家孝友以爲鄉，塾道德以爲基。',212,'全唐诗/poet.song.77000.json','["家孝友以爲鄉，塾道德以爲基。", "横忠義之勁氣，吐剛方之談辭。", "視閻浮其一漚，而寄夢境於儋耳。", "開胸次之八荒，而露幻影如蛾眉，此其大凡也。", "屬熙豐之勃興，追舜禹之有爲。", "常一出而事悞，則袖手悠然而去之。", "如鳳如麟，而瑞冠一世。", "非雷非霆，而名震四夷。", "造禆販之中傷，嗟妒忌之何知。", "方其茹拳而微醉，以翰墨爲娛嬉。", "則倒用祖師之印，檄萬古而疾馳。", "如河漢之流，無有窮極。", "如煙雲之出，無有定姿。", "欲錄之以藏，則懼六丁之竊取。", "要當以日月爲字，而天爲碑。", "可乎。"]'),
('0463ad3e-acae-4539-b996-84b8ff5075ca','山谷老人贊','釋德洪','宋','宋诗','song-poetry','','[]','蓋九州以醉眼，而其氣如神。',134,'全唐诗/poet.song.77000.json','["蓋九州以醉眼，而其氣如神。", "藻萬物以妙語，而應手生春。", "排黄龍之三關，則凡聖之情不敢呵止。", "竪寶覺之一拳，則背觸之意不立鮮陳。", "世波雖怒，而難移砥柱之操。", "詩名雖富，而不救卓錐之貧。", "情如維摩詰，而欠散花之天女。", "心如赤頭璨，而著折角之幅巾。", "豈平章佛法之宰相，乃檀越叢林之韻人也耶。"]'),
('2a93e12c-d111-458d-bd13-2be8b074c1b7','華嚴居士贊','釋德洪','宋','宋诗','song-poetry','','[]','徧界難藏，而應緣震旦。',141,'全唐诗/poet.song.77000.json','["徧界難藏，而應緣震旦。", "通身是眼，而現形宰官。", "粲如景星，矯如翔鸞。", "販夫竈婦，欣聞悦觀。", "醫國法門，筆端三昧。", "奮迅出入，遊戲自在。", "居然不容，世議迫隘。", "夢游海南，御風騎氣。", "覺来浙東，有口如耳。", "且置是事，聊觀其一。", "戲以稱性印，印毛印海。", "光生佛僧，沮却魔外。", "惟我可與此道人遊乎大華嚴毗盧法界也。"]'),
('f5e3ccb0-9221-484a-a820-d958cf0857a7','李道夫真贊','釋德洪','宋','宋诗','song-poetry','','[]','眼蓋九州，韻高一世。',138,'全唐诗/poet.song.77000.json','["眼蓋九州，韻高一世。", "儼玉山富貴之豪，洗士林寒乞之氣。", "挫萬化於筆端，置八荒於胸次。", "邁往不屑，不可犯干。", "意輕邴吉，情追謝安。", "軒特秀發，乃爾秃巾椹褐。", "婆娑步趨，合在玉堂金鑾。", "山澤不可窺測，所以納垢汙。", "麒麟不可繫羈，所以異犬羊。", "正恐横風月之笛，披雲錦之裳。", "騎元氣之背，而游無何有之鄉。"]'),
('23f03f3a-ea07-4524-a71e-71b51943b916','蔡元中真贊','釋德洪','宋','宋诗','song-poetry','','[]','德以退爲進，謙以後爲柄。',75,'全唐诗/poet.song.77000.json','["德以退爲進，謙以後爲柄。", "迹以暗而彰，麝匿缶而香。", "視夫子之胸次，若螻蟻其侯王。", "方罾繳而去之，登千仞而翺翔。", "與夫蒼顔槁項論博南，策未央者，殆各夢而同牀乎。"]'),
('cabc983a-316d-4121-af82-668aefc4b2af','王宏道舍人贊','釋德洪','宋','宋诗','song-poetry','','[]','翛然無累之神，見此有道之器。',151,'全唐诗/poet.song.77000.json','["翛然無累之神，見此有道之器。", "韻收一代之風流，骨含奕世之富貴。", "節臨事而不奪，貌甚威而常喜。", "方其少壯，則酒闌說劍。", "横槊賦詩，名動塞壘。", "及其倦也，則浮沅湘。", "上衡霍，盡室行於山水。", "至於醉心翰墨，傾倒肺懷，則有王右轄、吳武陵之風味。", "馳至金城，而忠款乃著。", "罷歸玉關，而功名自至者。", "皆非壯歲，庸詎知此老人獨不如是乎。"]'),
('4afcee0c-bbd3-4b64-9902-2502f8860eac','周達道通判贊','釋德洪','宋','宋诗','song-poetry','','[]','韻出縉紳，秀見眉鬚。',94,'全唐诗/poet.song.77000.json','["韻出縉紳，秀見眉鬚。", "矯絳闕之風度，宜玉堂之步趨。", "有人所盡有，無人所當無。", "而乃袖補衮之手，而弄雲泉以自娛也。", "余安能探其歸宿，獨見於皮膚。", "蓋神於酌古，僻於譽書。", "求於古人，則謝幼輿王子敬之徒歟。"]'),
('dfb2a8b4-3b89-4271-8f75-72186fa751f1','韓廉使奉御贊','釋德洪','宋','宋诗','song-poetry','','[]','幅巾椹衣，杳然深靖。',130,'全唐诗/poet.song.77000.json','["幅巾椹衣，杳然深靖。", "坐蘚石牀，横玉麈柄。", "松聲度曲，笑作風聽。", "是故有琴，絃索不整。", "人徒見其神和氣平，頽然委順。", "至於垂紳正笏，守法奉命。", "則活人之色嚴毅勁正，特不受富貴所吞，而有山林之韻。", "究其心胸，山包海容。", "表裏不隔，八窗玲瓏。", "蓋遊戲人間之出世，扶持洞上之宗風者也。"]'),
('a5db1ec4-2dbc-49a9-a256-1ecccffc0d37','毛季子贊','釋德洪','宋','宋诗','song-poetry','','[]','季子逸羣，矯難控御。',92,'全唐诗/poet.song.77000.json','["季子逸羣，矯難控御。", "迹寄黄塵，名在紫府。", "觀此風鑑，無以爲喻。", "但見其清却梅林之風，秀等蘭叢之露。", "妙文章之吐鳳，視功名其破釡。", "我欲醉袖之旁，更畫凌波之女。", "使其他日歸道山，渡弱水，而驂風馭。"]'),
('05352638-8388-4ae1-96fa-d690790468de','曾逢原待制真贊','釋德洪','宋','宋诗','song-poetry','','[]','冠冕道德，被服文武。',160,'全唐诗/poet.song.77000.json','["冠冕道德，被服文武。", "所臨有聲，最宜荆楚。", "果於去惡，發姦破柱。", "爲國金湯，折衝尊爼。", "廣平南海，乖崕西蜀。", "如雪中春，和而嚴肅。", "名聞乳兒，威被草木。", "能作豐年，茂我百穀。", "筆下煙雲，胸次丘壑。", "風流餘韻，與世酬酢。", "至於談禪，氣壓諸衲。", "戲以法界，玩于掌握。", "補衮之線，調鼎之手。", "笑而不言，置之懷袖。", "咨爾邦民，再拜稽首。", "潭非久留，歸相明后。"]'),
('74d78f35-6aca-4e47-a3b2-c13c5e09bf97','夢蝶居士贊二首  其一','釋德洪','宋','宋诗','song-poetry','','[]','俯看人世，一漚起滅。',80,'全唐诗/poet.song.77000.json','["俯看人世，一漚起滅。", "失脚来游，夢入螘穴。", "前身後身，獨臨兩境。", "左右見之，不雜其影。", "眉目秀發，嫩木含春。", "風度凝遠，霽月洗雲。", "葉屋花房，玉堂金宇。", "我視睨睨，渠方栩栩。"]'),
('7b81eb78-61ac-4d70-90e9-7f0070da074f','夢蝶居士贊二首  其二','釋德洪','宋','宋诗','song-poetry','','[]','余觀此老，神光渾圓，道骨粹剛。',158,'全唐诗/poet.song.77000.json','["余觀此老，神光渾圓，道骨粹剛。", "唾零功名，眼蓋侯王。", "何爲鬚髪滄浪，被此朝章乎。", "豈非如茅容殺雞，毛義捧檄。", "但欲致慈母之一笑，安知有佳客之在旁也。", "所以袖補天之妙手，祕醫國之奇方。", "獨游戲於富貴，如蝶棲宿於花房。", "占百年之閑適，寄一夢於幽香。", "千花百卉，金馬玉堂。", "麗風日之醇釅，徧雨露之恩光。", "遙增擊而栩栩，亦何異一丘一壑之相羊耶。"]'),
('28e830f6-5a45-4f24-a917-a7ad361dd18e','潘延之贊','釋德洪','宋','宋诗','song-poetry','','[]','毗盧無生之藏，震旦有道之器。',92,'全唐诗/poet.song.77000.json','["毗盧無生之藏，震旦有道之器。", "談妙義借身爲舌，擎大千以手爲地。", "機鋒不減龐藴，而解文字禪。", "行藏大類孺子，而值休明世。", "舒王强之而不可，神考致之而不起。", "此天下士大夫所共聞，然公豈止於是而已乎。"]'),
('c9893179-fa65-4d0b-b359-9c1bab1b1267','郤子中贊','釋德洪','宋','宋诗','song-poetry','','[]','師黄叔度以築太平之基，追韓退之以策翰墨之勳。',116,'全唐诗/poet.song.77000.json','["師黄叔度以築太平之基，追韓退之以策翰墨之勳。", "故語妙如其渾厚，論高如其精神。", "超然挺特，華裾逸羣。", "富貴之氣已如透花之春色，功名之志又如欲雨之層雲。", "秃巾折角，置之巖石亦不以爲屈。", "長劍拄頤，圖之凌煙亦不以爲伸。", "蓋虚以閲世，不可得而疏親也耶。"]'),
('fbcaed46-217d-4b4c-8d8d-797da0bdcabf','李運使贊','釋德洪','宋','宋诗','song-poetry','','[]','風度凝遠，和氣如春。',180,'全唐诗/poet.song.77000.json','["風度凝遠，和氣如春。", "綠髪授道，精敏絕倫。", "名冠縉紳，挺然忠義。", "知國知兵，如唐陸贄。", "頃者天府，奉使江南。", "晝錦之榮，父老聚觀。", "頓節西州，盗發江浙。", "提師百萬，蕩其窟穴。", "凱旋而還，口不言功。", "但欲使民，生於死中。", "重臨南楚，化行郡邑。", "如春在花，不見痕迹。", "恢躁坦夷，易親難忘。", "眎其胸次，山包海藏。", "宜宿玉堂，宜在黄閣。", "跬步可待，昂霄聳壑。", "長沙之民，自懷其私。", "龕此畫像，飲食必祠。"]'),
('0707f0c5-71d6-4b87-b6e3-ce2c77f10d9d','簡緣居士贊','釋德洪','宋','宋诗','song-poetry','','[]','言似簡緣公，法身有比並。',68,'全唐诗/poet.song.77000.json','["言似簡緣公，法身有比並。", "不似簡緣公，法身有少剩。", "平生赤吉歷，兩眼光迥迥。", "捨得大士打門椎，掣肘歸去叫不應。", "開箇鋪席在街頭，有藥只解醫禪病。"]'),
('9a724b8b-5c49-48c3-a013-141b08200ec1','瓦瓢贊','釋德洪','宋','宋诗','song-poetry','','[]','異哉此瓢，脩吭矬身。',160,'全唐诗/poet.song.77000.json','["異哉此瓢，脩吭矬身。", "弗生爪蔓，生陶家輪。", "我疑其中，藏十洲春。", "昔有列仙，雜于市人。", "屋簷懸之，自旦及申。", "輙入其中，偃仰而卧。", "而樓居者，見之膽破。", "遂從之游，推擠莫可。", "挽而同登，相向而坐。", "如四老人，會商山果。", "唯簡素公，道貌天容。", "豈其人歟，出處略同。", "道山巋然，弱水之東。", "何時來歸，泠然御風。", "而以此瓢，挂之瘦筇。", "我作妙語，天葩粲紅。"]'),
('5714f06b-0121-4249-b242-70847d4c44d3','許彦周所作墨戲爲之贊','釋德洪','宋','宋诗','song-poetry','','[]','異哉土蛇，登樹而怒。',140,'全唐诗/poet.song.77000.json','["異哉土蛇，登樹而怒。", "怒見脊尾，口眼可懼。", "王孫地坐，氣讋毛豎。", "欲去不敢，攀枝而顧。", "豐狐行藏，心常愧負。", "見之而走，敏若脱兔。", "孰能傲然，如此老樹。", "與之相親，不驚不怖。", "問何能爾，以無我故。", "酒色海中，有萬奇趣。", "不出二種，猜疑掉舉。", "蓋無常蛇，終不赦汝。", "居士圖之，以警未悟。", "覺範一見，笑手爲拊。"]'),
('774ecdc8-5c03-4c0b-a0a9-86edd599309a','四偈 無求行','釋德洪','宋','宋诗','song-poetry','','[]','形恃美好，今已毁壞。',40,'全唐诗/poet.song.77000.json','["形恃美好，今已毁壞。", "置之世路，自覺塞礙。", "始緣饑寒，致萬憎愛。", "欲壞身衰，入此三昧。"]'),
('e58aca40-c260-46dc-835b-9688ddfabdca','四偈 隨緣行','釋德洪','宋','宋诗','song-poetry','','[]','此生夢幻，緣業所轉。',40,'全唐诗/poet.song.77000.json','["此生夢幻，緣業所轉。", "隨其所遭，敢擇貴賤。", "眠食既足，餘復何羡。", "緣盡則行，無可顧戀。"]'),
('b668cd16-2f9d-4b75-9f99-c592e3ba9474','四偈 報冤行','釋德洪','宋','宋诗','song-poetry','','[]','僧嬰王難，情觀可醜。',40,'全唐诗/poet.song.77000.json','["僧嬰王難，情觀可醜。", "夙業純熟，所以甘受。", "受盡還無，何醜之有。", "轉重還輕，佛恩彌厚。"]'),
('2bd46a90-0d45-4605-bfd2-49468b601b20','四偈 稱法行','釋德洪','宋','宋诗','song-poetry','','[]','本無貪瞋，我持戒忍。',40,'全唐诗/poet.song.77000.json','["本無貪瞋，我持戒忍。", "食不過中，手不操楯。", "風必頓息，而浪漸盡。", "離微細念，方名見性。"]'),
('299094c7-32da-4758-9aa3-40cbb78ba0f7','十二時偈','釋德洪','宋','宋诗','song-poetry','','[]','吾活計，無可觀。',192,'全唐诗/poet.song.77000.json','["吾活計，無可觀。", "但日日，長一般。", "夜半子，困如死。", "被虱咬，動脚指。", "雞鳴丑，粥魚吼。", "忙繋裙，尋韈紐。", "平旦寅，忽欠伸。", "兩眉稜，重千斤。", "日出卯，自攪炒。", "眼誦經，口相拗。", "食時辰，齒生津。", "輸肚皮，虧口唇。", "禺中巳，眼前事。", "看見親，說不似。", "日南午，衣自補。", "忽穿針，全體露。", "日昳未，方破睡。", "洗開面，摸着鼻。", "晡時申，最天真。", "順便喜，逆便瞋。", "日入酉，壁掛口。", "鏡中空，日中斗。", "黄昏戍，作用密。", "眼開闔，烏崒律。"]'),
('44039fe8-309b-4747-abfa-24dbc9907009','偈四首  其一','釋德洪','宋','宋诗','song-poetry','','[]','舉手炷香，而供養佛。',120,'全唐诗/poet.song.77000.json','["舉手炷香，而供養佛。", "其心自知，應念獲福。", "舉手操刀，恣行殺戮。", "其心自知，死入地獄。", "或殺或供，一手之功。", "云何業報，罪福不同。", "皆自横計，有如是事。", "是故從來，枉沈生死。", "雷長芭蕉，銕轉磁石。", "俱無作者，而有是力。", "心不取境，境亦自寂。", "故如來藏，不許有識。"]'),
('aa2ebeaa-5e33-485b-9f33-9a3b36c7d62b','偈四首  其二','釋德洪','宋','宋诗','song-poetry','','[]','天下心知不可藏，紛紛嗅迹但尋香。',32,'全唐诗/poet.song.77000.json','["天下心知不可藏，紛紛嗅迹但尋香。", "端能百尺竿頭步，始見林梢掛角羊。"]'),
('18eb9a98-12ad-4279-9cdc-0467df19a06e','偈四首  其三','釋德洪','宋','宋诗','song-poetry','','[]','涼溫遠近轉增疑，不答當渠痛處錐。',32,'全唐诗/poet.song.77000.json','["涼溫遠近轉增疑，不答當渠痛處錐。", "當逐小兒爭未已，仲尼何獨古難知。"]'),
('0cd3e470-08d5-45cc-89f8-fc018ddcd21b','偈四首  其四','釋德洪','宋','宋诗','song-poetry','','[]','馬祖有伴則來，彭公死時即道。',28,'全唐诗/poet.song.77000.json','["馬祖有伴則來，彭公死時即道。", "睡裏蝨子咬人，信手摸得革蚤。"]'),
('e202b475-8ed5-469e-b31a-76ba8a07c176','偈三首  其一','釋德洪','宋','宋诗','song-poetry','','[]','出定只消彈指，佛法豈用工夫。',28,'全唐诗/poet.song.77000.json','["出定只消彈指，佛法豈用工夫。", "我今要用便用，不管罔明文殊。"]'),
('3658daf0-82fa-4f63-be52-839f6f2fd9f8','偈三首  其二','釋德洪','宋','宋诗','song-poetry','','[]','靈雲一見不再見，紅白枝枝不着花。',32,'全唐诗/poet.song.77000.json','["靈雲一見不再見，紅白枝枝不着花。", "尀耐釣魚船上客，卻來平地摝魚蝦。"]'),
('9cc75972-ce33-430e-b025-7d38f9638f6d','偈三首  其三','釋德洪','宋','宋诗','song-poetry','','[]','不知即問，不見即討。',40,'全唐诗/poet.song.77000.json','["不知即問，不見即討。", "圓滿現前，何須更道。", "維堅密身，生死病老。", "面前塔子，不可推倒。"]'),
('d0ab12d5-bacb-4593-9951-e0ed8ef34d8f','補秀老遺','釋德洪','宋','宋诗','song-poetry','','[]','萬壑搖蒼煙，百灘渡流水。',24,'全唐诗/poet.song.77000.json','["萬壑搖蒼煙，百灘渡流水。", "下有跨驢人，蕭蕭吹醉耳。"]'),
('fd1c4708-2ce5-4c55-a6d4-52e13e9fb334','贈朱世英','釋德洪','宋','宋诗','song-poetry','','[]','老妻營炊，稚子汲水。',40,'全唐诗/poet.song.77000.json','["老妻營炊，稚子汲水。", "龐公掃除，丹霞適至。", "棄帚迎朋，一笑相視。", "不必靈照，多說道理。"]'),
('9365dac4-45ea-4ee3-8e55-07e567d08097','戲贈劉跛子','釋德洪','宋','宋诗','song-poetry','','[]','相逢一拐大梁間，妙語時時見一斑。',32,'全唐诗/poet.song.77000.json','["相逢一拐大梁間，妙語時時見一斑。", "我欲從公蓬島去，爛銀堆裏見青山。"]'),
('07bc26e7-840e-4431-a71c-d092e818fa1e','偈','釋德洪','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','廬山殿閣如生成，食堂處處禪牀折。',32,'全唐诗/poet.song.77000.json','["廬山殿閣如生成，食堂處處禪牀折。", "我此三門如冷灰，盡日長廊卷風葉。"]'),
('1426afc3-7fe2-4b14-94db-22ef62a2b2f2','讀靈源自作誌銘','釋德洪','宋','宋诗','song-poetry','','[]','今年九月十有八，清凈法身忽衰颯。',96,'全唐诗/poet.song.77000.json','["今年九月十有八，清凈法身忽衰颯。", "生死鶻崙誰擘破，披露夢中根境法。", "無生塔成自作銘，人言無虧寧有成。", "一切法空尚曰座，此塔安得離色聲。", "障雲方增佛日晚，長嗟更失人天眼。", "但餘荷負大法心，乞與叢林照古今。"]'),
('bc96f4bb-10f0-4e84-83d5-22470eb657ea','偈二首  其一','釋德洪','宋','宋诗','song-poetry','','[]','難藏爲香釁，易滿坐褊小。',24,'全唐诗/poet.song.77000.json','["難藏爲香釁，易滿坐褊小。", "開口所有竭，饞奴法當笑。"]'),
('5eccf0c0-f875-4745-b1dc-eee6d7c84270','偈二首  其二','釋德洪','宋','宋诗','song-poetry','','[]','前朝詔住棲賢寺，雪夜逃居巖石間。',32,'全唐诗/poet.song.77000.json','["前朝詔住棲賢寺，雪夜逃居巖石間。", "想見煮茶延客處，直緣生死不相關。"]'),
('94d32aa3-d08b-415e-a773-c81b3c27e31e','詩一首','釋德洪','宋','宋诗','song-poetry','','[]','獨倚闌干玩野塘，俄驚節物老春光。',64,'全唐诗/poet.song.77000.json','["獨倚闌干玩野塘，俄驚節物老春光。", "綠楊陰密鶯將懶，紅杏枝空蝶不忙。", "詩思漫沿芳草遠，茶甌微带落花香。", "那堪風雨頻催促，公子王孫亦斷腸。"]'),
('6f6572e0-d668-4b57-95eb-6905f5fe13bc','宮詞','釋德洪','宋','宋诗','song-poetry','','[]','紅樓曉色催宮漏，紫閣春光雜禁煙。',32,'全唐诗/poet.song.77000.json','["紅樓曉色催宮漏，紫閣春光雜禁煙。", "風定玉爐香影直，日融金掌露華鮮。"]'),
('cd4f1d88-30f4-44c5-ace8-94ae702ffa83','頓脫所疑偈','釋德洪','宋','宋诗','song-poetry','','[]','靈雲一見不再見，紅白枝枝不著華。',32,'全唐诗/poet.song.77000.json','["靈雲一見不再見，紅白枝枝不著華。", "叵耐釣魚船上客，卻來平地摝魚蝦。"]'),
('fbb1ccc0-1aed-499e-ba31-12e9aaebfa19','偈','釋德洪','宋','宋诗','song-poetry','','[]','以字不成八不是，法身睡著無遮閉。',32,'全唐诗/poet.song.77000.json','["以字不成八不是，法身睡著無遮閉。", "衲僧對面不知名，百衆人前呼不起。"]'),
('5ce865a5-57bf-40f3-b576-3bf0c333a643','送王彥齡承務還河內','釋德洪','宋','宋诗','song-poetry','','[]','武陵王郎高韻度，鞍馬四方在定住。',128,'全唐诗/poet.song.77000.json','["武陵王郎高韻度，鞍馬四方在定住。", "眼隨泉石便吟哦，咳唾珠璣不計數。", "我亦悠悠事不羈，浪萍風梗隨安之。", "少室山前石蘭若，邂逅便與同襟期。", "興來岸幘一長嘯，清聲激越穿雲嶠。", "竹林故事獨未泯，人物如君獨高調。", "秋風獵獵促鳴蟬，歸路千山入馬鞭。", "白袍烏袖宜圖畫，不羨襄陽孟浩然。"]'),
('4b076f8c-b201-4770-983c-753c51bcaf1c','句  其一','釋德洪','宋','宋诗','song-poetry','','[]','我輩自應須左轉，知君豈是背匙人。',16,'全唐诗/poet.song.77000.json','["我輩自應須左轉，知君豈是背匙人。"]'),
('43f871b0-0395-4b7c-a12e-84133ba5bc0d','句  其二','釋德洪','宋','宋诗','song-poetry','','[]','啼妝露着花。',6,'全唐诗/poet.song.77000.json','["啼妝露着花。"]'),
('1c94e784-96f6-4975-9f78-9f424ef8d9b2','句  其三','釋德洪','宋','宋诗','song-poetry','','[]','至今牛斗氣，散作延平人。',12,'全唐诗/poet.song.77000.json','["至今牛斗氣，散作延平人。"]'),
('0076bd05-3161-488a-8cd5-1df7c3ef1d1c','句  其四','釋德洪','宋','宋诗','song-poetry','','[]','梢橫波面月搖影，花落尊前酒带香。',16,'全唐诗/poet.song.77000.json','["梢橫波面月搖影，花落尊前酒带香。"]'),
('cd0a597d-61b5-411c-857b-d2f2a6c0dc31','龍興寺閣','呂頤浩','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','危梯凌碧空，不與廛閭通。',96,'全唐诗/poet.song.77000.json','["危梯凌碧空，不與廛閭通。", "朝煙翳高棟，靄靄猶從龍。", "遥睇辨滄海，縱觀分岱宗。", "常山與馬耳，歷歷在目中。", "良時無停景，遠宦如飄蓬。", "汨没困簿領，何以舒心胸。", "公餘頻登臨，勿使酒樽空。", "行看五六月，下視零雨濛。"]'),
('d7949980-208b-4e75-98b0-fc9be0f61d87','同侯德裕登邠州凌峰閣','呂頤浩','宋','宋诗','song-poetry','','[]','招提掛層峰，朱檻倚天半。',72,'全唐诗/poet.song.77000.json','["招提掛層峰，朱檻倚天半。", "冷風閣底回，暑晝消清汗。", "危躋出䆗窱，俯視羣峰亂。", "吾人家東州，官學各羈絆。", "玆游豈易得，勿訝金樽滿。", "終期汗漫游，醉卧雲巒畔。"]'),
('670d2acc-8a12-4fda-8f98-2fbce1345d73','宗學寓宿貽謝任宿','呂頤浩','宋','宋诗','song-poetry','','[]','煌煌文德門，絳殿高巍巍。',84,'全唐诗/poet.song.77000.json','["煌煌文德門，絳殿高巍巍。", "朔望奉朝謁，自覺身光輝。", "吾家濟水南，舊隱掩雙扉。", "三徑雖就荒，松菊猶依依。", "歸歟懷魏闕，倦宦念東歸。", "游子行未已，江湖鴈南飛。", "去就兩無策，躊躇送殘暉。"]'),
('f7effa71-c4a3-4f42-b40b-8556b89f0a7e','扈從至西城道中作','呂頤浩','宋','宋诗','song-poetry','','[]','霜風捲霧散，天日增光明。',120,'全唐诗/poet.song.77000.json','["霜風捲霧散，天日增光明。", "警蹕轉前路，百鳥相和鳴。", "邊塵暗長淮，今歲幸西城。", "野店翠華過，縱觀滿簷楹。", "豐年高廪多，薄飯猶香秔。", "衰鈍猶何者，厚顔羞大烹。", "鹽梅乏滋味，終恐傷和羮。", "干戈幾時休，憂國心如酲。", "歸歟魏闕念，老矣滄洲情。", "勉力謂諸將，爲時請長纓。"]'),
('b4161ce2-3981-4cfb-a54a-6974bb453457','次韻劉省元希範題孫伯温舫齋','呂頤浩','宋','宋诗','song-poetry','','[]','昔年曾伴江湖客，泛宅浮家煙水闊。',192,'全唐诗/poet.song.77000.json','["昔年曾伴江湖客，泛宅浮家煙水闊。", "蘭旌桂棹去夷猶，醉吟爛賞湖山色。", "即今别來四五年，漁蓑煙艇想依然。", "驅車終歲走塵土，夢魂猶在苕霅間。", "主人好事誰能敵，鑿蘚誅茅開一室。", "宛如畫舫到江南，左列圖書右經籍。", "嗟予蹤蹟若飛蓬，笑談偃息幸相從。", "有時睡覺驚四顧，恍然身在船窗中。", "經營雅協滄洲趣，祇欠雲濤破煙霧。", "蕭蕭風雨夜深時，憶著扁舟横野渡。", "羡君腹大飽詩書，筆端摛藻飛瓊琚。", "行看乘槎犯牛斗，吾知此舍真蘧廬。"]'),
('36205547-ab7f-4c7f-ab13-8468fcb9a12c','和沈和仲同胡少汲河朔道中','呂頤浩','宋','宋诗','song-poetry','','[]','投分緣心合，相從與道俱。',48,'全唐诗/poet.song.77000.json','["投分緣心合，相從與道俱。", "歸途聯寶勒，佳句握靈珠。", "笑語調征賦，間關恤老孤。", "獨憐撫字謬，本計自疏蕪。"]'),
('0834edfe-582a-4ebe-aa18-9b1d332c613e','襄城大熱喜雨','呂頤浩','宋','宋诗','song-poetry','','[]','大暑方蒸濕，雲興忽蔽空。',48,'全唐诗/poet.song.77000.json','["大暑方蒸濕，雲興忽蔽空。", "俄然飄細雨，快矣濯清風。", "變化誰能測，炎凉迥不同。", "馬前襄漢路，山色有無中。"]'),
('e56e7322-00b2-4252-89d5-ee9b408cc7b2','懷臨濟舊居四首  其一','呂頤浩','宋','宋诗','song-poetry','','[]','古邑吾鄉閈，閑居况可嘉。',48,'全唐诗/poet.song.77000.json','["古邑吾鄉閈，閑居况可嘉。", "膏腴環百里，市井簇千家。", "南郭連山色，東郊接水涯。", "秋風故軍路，縱目賞荷花。"]'),
('165d12fc-b276-4e18-9662-98526631e889','懷臨濟舊居四首  其二','呂頤浩','宋','宋诗','song-poetry','','[]','出郭遥墻路，行行到舊莊。',48,'全唐诗/poet.song.77000.json','["出郭遥墻路，行行到舊莊。", "春深楊葉閙，雨足稻花香。", "草色連三徑，槐枝罩一堂。", "挂冠他日事，投老此徜徉。"]'),
('324f94dc-b9f3-4920-b8e7-ff81de19455c','懷臨濟舊居四首  其三','呂頤浩','宋','宋诗','song-poetry','','[]','鄉黨吾兄弟，家居孝友風。',48,'全唐诗/poet.song.77000.json','["鄉黨吾兄弟，家居孝友風。", "北堂諧力養，南畝幸年豐。", "婚嫁朱陳比，交游管鮑同。", "南枝真可戀，倦翼厭樊籠。"]'),
('74f7c3c3-8881-4a2c-b2d6-bfd3ad87ab2d','懷臨濟舊居四首  其四','呂頤浩','宋','宋诗','song-poetry','','[]','古邑西門外，煙村遠市廛。',48,'全唐诗/poet.song.77000.json','["古邑西門外，煙村遠市廛。", "呼鷹白草際，調馬綠楊邊。", "持節東西路，離家五六年。", "永懷豪横樂，半老尚依然。"]'),
('25a9e2f3-08f4-4889-8ba7-522986d7a38d','元祐甲戌二月省試夜分論經理詩','呂頤浩','宋','宋诗','song-poetry','','[]','睿聖崇儒治，嚴宸夜已分。',72,'全唐诗/poet.song.77000.json','["睿聖崇儒治，嚴宸夜已分。", "講論經理切，紬繹帝心勤。", "銅鼓三更漏，牙籖六藝文。", "游心通二典，刻意究三墳。", "玉殿澄寒月，楓庭藹慶雲。", "邇英如厠蹟，所學獻吾君。"]'),
('b49f42dd-4781-44f5-9e54-5e05f6f8b5b4','家學書懷  其一','呂頤浩','宋','宋诗','song-poetry','','[]','儒林從昔藹英猷，蚤步亨衢孰比儔。',64,'全唐诗/poet.song.77000.json','["儒林從昔藹英猷，蚤步亨衢孰比儔。", "四坐俊翹環策府，一時名位冠瀛洲。", "九苞丹鳳標文采，五總靈龜擅智謀。", "東觀退朝何所似，廣文詩徤欲凌秋。"]'),
('1146b5eb-5e3c-4933-8160-07d28cbd8855','家學書懷  其二','呂頤浩','宋','宋诗','song-poetry','','[]','窮經投老變書滛，兩鬢塵埃老欲侵。',64,'全唐诗/poet.song.77000.json','["窮經投老變書滛，兩鬢塵埃老欲侵。", "滿院好風炎日晚，一庭疏雨夜堂深。", "十年塵坌無高步，萬里雲霄有素心。", "誰謂腐儒何所用，試將肝膽報知音。"]'),
('4228880f-3ad9-451d-a78d-2589e503bfea','感舊書懷','呂頤浩','宋','宋诗','song-poetry','','[]','宦塗忽忽六周星，萬事於今一未成。',64,'全唐诗/poet.song.77000.json','["宦塗忽忽六周星，萬事於今一未成。", "但著青衫趨冉冉，不知華髮欲莖莖。", "驅馳翻憶林泉卧，頑鈍宜歸畎畝耕。", "賴有鄉人端契誼，相逢時慰寂寥情。"]'),
('7fdb50e9-f2a4-4212-8cb9-f981bc3b9149','雄州道中寄沈和仲侍郎','呂頤浩','宋','宋诗','song-poetry','','[]','扁舟隱隱馬駸駸，重到燕山感念深。',64,'全唐诗/poet.song.77000.json','["扁舟隱隱馬駸駸，重到燕山感念深。", "水陸共時同偃薄，雲途今日異升沉。", "青山豈乏歸耕路，白髪難忘報國心。", "木落鴈飛秋復盡，惘然懷抱寄幽吟。"]'),
('e0b521ed-2f8f-4cd7-87c6-37ce955667f4','李希中祉故門下侍郎邦直次子有文章器業嘗任淮南兩浙轉運使及江淮發運使靖康元年三月僕寓維揚游開元寺見公題名感槩成詩','呂頤浩','宋','宋诗','song-poetry','','[]','當年對策大明宫，曾見揮毫氣吐虹。',64,'全唐诗/poet.song.77000.json','["當年對策大明宫，曾見揮毫氣吐虹。", "楚客才華推宋玉，漢儒文賦許揚雄。", "漳濱墓木皆成拱，洛汭池臺半已空。", "經濟才高英槩盡，感恩垂淚向東風。"]'),
('83d843fb-fd72-4b19-b4df-46e4d90a6b7f','離京師','呂頤浩','宋','宋诗','song-poetry','','[]','春光冉冉過皇州，桂棹東歸汴水流。',64,'全唐诗/poet.song.77000.json','["春光冉冉過皇州，桂棹東歸汴水流。", "滿岸風光連别浦，兩行煙柳送歸舟。", "麤官自不隨時用，拙宦安能爲已謀。", "香寺故人來話别，一樽清酒散牢愁。"]'),
('6d23822d-abdc-48ca-a9e5-3346d86aa74a','送朱景行','呂頤浩','宋','宋诗','song-poetry','','[]','學士文章早擅名，大夫官業久馳聲。',64,'全唐诗/poet.song.77000.json','["學士文章早擅名，大夫官業久馳聲。", "暫分雷土三年政，佇看雲衢萬里程。", "顧我飄蓬非夙契，辱公傾蓋若平生。", "尋蹤曾醉姑蘇酒，水遠山長愴别情。"]'),
('45b7d882-2387-4381-918b-93cc1a9fdbc9','次韻台守晁子莫見貽','呂頤浩','宋','宋诗','song-poetry','','[]','去歲乘桴暫得閑，忽驚三命促登壇。',64,'全唐诗/poet.song.77000.json','["去歲乘桴暫得閑，忽驚三命促登壇。", "向來彊健思投筆，老去衰遲懶據鞍。", "玉帳夢回烽燧曉，水鄉春盡鐵衣寒。", "海山深處幽棲地，爲我經營竚掛冠。"]'),
('c34b1707-1d3f-4144-b432-e5216467ff52','次韻台守劉仲忱','呂頤浩','宋','宋诗','song-poetry','','[]','瓦橋傾蓋暫徘徊，自渡江南蹟屢陪。',64,'全唐诗/poet.song.77000.json','["瓦橋傾蓋暫徘徊，自渡江南蹟屢陪。", "衰謝未能高隱去，依棲還傍故人來。", "青蒲諫諍推公望，皂蓋承宣屈大才。", "但恐政成公促召，異時懷抱向誰開。"]'),
('f42ae1d8-33cc-45aa-bb8b-cf5425daae65','次韻陳國佐喜雨','呂頤浩','宋','宋诗','song-poetry','','[]','吾皇懇惻念三農，聖德昭昭格昊穹。',64,'全唐诗/poet.song.77000.json','["吾皇懇惻念三農，聖德昭昭格昊穹。", "丹詔丁寧祈雨澤，幽人歌詠願年豐。", "焦枯已有生成意，膏潤全歸造化功。", "竊食太倉真厚幸，况聞湖外奏膚公。"]'),
('e498aba1-3b71-48ea-8865-3b195ab4bd53','送張德遠宣撫川陕二首  其一','呂頤浩','宋','宋诗','song-poetry','','[]','維揚傾蓋意相投，國事當時已共憂。',64,'全唐诗/poet.song.77000.json','["維揚傾蓋意相投，國事當時已共憂。", "鐵馬勤王曾並轡，戎衣護聖每同舟。", "山西氣槩終須在，塞北煙塵漫不收。", "宗社有靈天悔禍，尚期一戰掃邊愁。"]'),
('aeff095a-24d3-4f47-9c4f-20e67bf9c8c4','送張德遠宣撫川陕二首  其二','呂頤浩','宋','宋诗','song-poetry','','[]','子房雲裔擅英名，位冠樞庭獨本兵。',64,'全唐诗/poet.song.77000.json','["子房雲裔擅英名，位冠樞庭獨本兵。", "毎憤中原淪半壁，擬將孤劍斬長鯨。", "漢中險阻真堪據，關內安危繫此行。", "勉力功名扶帝業，臨風何用愴離情。"]'),
('1f945eec-51bd-4f34-83c6-2b7516599595','次韻崔彊恕墜馬見貽','呂頤浩','宋','宋诗','song-poetry','','[]','昔參幕府事從軍，躍馬翩翩犯塞塵。',64,'全唐诗/poet.song.77000.json','["昔參幕府事從軍，躍馬翩翩犯塞塵。", "舞劍未饒横槊客，屬鞬何羡佩鈎人。", "中年衰鈍難堪事，一跌支離近浹旬。", "多謝故人情意厚，佳篇惟待細書紳。"]'),
('76be0a76-22a5-4eb8-b648-c17857b7a10a','謝劉仲忱寵惠詩編','呂頤浩','宋','宋诗','song-poetry','','[]','久欽文采動簪紳，晚見佳篇妙入神。',64,'全唐诗/poet.song.77000.json','["久欽文采動簪紳，晚見佳篇妙入神。", "金自鷄林酬去貴，珠從驪頷探来珍。", "越羅蜀錦工誰擬，陣馬風檣勇莫倫。", "四十年来無此作，睢陽今繼少陵人。"]'),
('8c879f2c-949d-4b82-b628-12ab317aaefa','次韻姜光彦移居','呂頤浩','宋','宋诗','song-poetry','','[]','仕途憂患久相隨，老去求閑遂燕私。',64,'全唐诗/poet.song.77000.json','["仕途憂患久相隨，老去求閑遂燕私。", "隴笛不聞吹舊曲，彩牋時見賦新詩。", "清宵好月穿蓬户，落日凉風動桂枝。", "兩鬢霜毛如舊少，按絃無意望鍾期。"]'),
('ae1e804b-92ab-428d-8cd4-7212754a8204','次韻盧虞卿樞密見寄之什','呂頤浩','宋','宋诗','song-poetry','','[]','維揚初記接英躔，日月飛馳已十年。',64,'全唐诗/poet.song.77000.json','["維揚初記接英躔，日月飛馳已十年。", "政路翺翔常在後，祠宫閑退蚤輸先。", "欲陪清會時顒首，辱惠新詩思湧泉。", "幸有會稽棲隱地，約公歸老釣魚船。"]'),
('2f883e35-2442-45e2-a46b-f58042fb44af','登第後道中燈下讀書','呂頤浩','宋','宋诗','song-poetry','','[]','十載燈前筆下耕，如今鴈塔幸題名。',32,'全唐诗/poet.song.77000.json','["十載燈前筆下耕，如今鴈塔幸題名。", "他年若遂平生志，肯爲長檠棄短檠。"]'),
('6452df74-43a3-460e-b7b9-24ac2f1bc5e7','行次澠池道中','呂頤浩','宋','宋诗','song-poetry','','[]','十年兩度到秦川，每憶東歸意浩然。',32,'全唐诗/poet.song.77000.json','["十年兩度到秦川，每憶東歸意浩然。", "何况驅車度殽澠，眼前都是好風煙。"]'),
('ff93ea91-c3e4-4dda-908e-704a57b623a5','偶成','呂頤浩','宋','宋诗','song-poetry','','[]','金風蕭瑟動疏簾，細雨霏微拂畫簷。',32,'全唐诗/poet.song.77000.json','["金風蕭瑟動疏簾，細雨霏微拂畫簷。", "籬菊半開家釀熟，自慙生理勝陶潛。"]'),
('fc29bd06-104a-46f7-9c82-cdb5e2c33e12','重和改元冬至','呂頤浩','宋','宋诗','song-poetry','','[]','至後光陰爭一線，竹軒小閣獸爐新。',32,'全唐诗/poet.song.77000.json','["至後光陰爭一線，竹軒小閣獸爐新。", "捲簾賸放冬曦入，暖律渾如洞府春。"]'),
('4a6c4c24-24be-4820-98b8-c1014664a8e8','題樊將軍廟','呂頤浩','宋','宋诗','song-poetry','','[]','排危盛氣冠英雄，逆耳忠言悟沛公。',32,'全唐诗/poet.song.77000.json','["排危盛氣冠英雄，逆耳忠言悟沛公。", "何事時人太求備，欲將瑕翳掩前功。"]'),
('52021ad0-5887-4c27-9238-fe1caaa979a9','承乏河北東路不得爲天平之游偶成小詩呈沈和中殿撰胡少汲龍圖','呂頤浩','宋','宋诗','song-poetry','','[]','夢想天平紫府開，却嗟匏繫在銅臺。',32,'全唐诗/poet.song.77000.json','["夢想天平紫府開，却嗟匏繫在銅臺。", "山靈有意憎塵俗，不許尋芳暫到來。"]'),
('ba1e598d-65cc-4485-b235-258e2d69651b','寄劉聖可楊如晦賈習之三首  其一','呂頤浩','宋','宋诗','song-poetry','','[]','清暉堂下相從夜，見說崔橋自昔游。',32,'全唐诗/poet.song.77000.json','["清暉堂下相從夜，見說崔橋自昔游。", "别後不知能幾日，却來橋上繫扁舟。"]'),
('fbfee781-b175-4146-81fd-a2607e01d93c','寄劉聖可楊如晦賈習之三首  其二','呂頤浩','宋','宋诗','song-poetry','','[]','霜汀野岸清宵月，偏照蓬窗不寐人。',32,'全唐诗/poet.song.77000.json','["霜汀野岸清宵月，偏照蓬窗不寐人。", "遥想塞垣千里共，可憐名宦阻相親。"]'),
('8fc325a9-f983-408e-b0cb-41382b87f5f8','寄劉聖可楊如晦賈習之三首  其三','呂頤浩','宋','宋诗','song-poetry','','[]','北山逋客今何在，西塞從軍各未歸。',32,'全唐诗/poet.song.77000.json','["北山逋客今何在，西塞從軍各未歸。", "欲訪草堂尋舊隱，恐教猿鶴謾依依。"]'),
('5cf4b5b2-ee85-4c41-bfa9-c36997bd33a5','新酒金橘寄李德升','呂頤浩','宋','宋诗','song-poetry','','[]','稻醅初熟鵝兒色，金橘方包弹子新。',32,'全唐诗/poet.song.77000.json','["稻醅初熟鵝兒色，金橘方包弹子新。", "寄與鄉朋供一醉，捧觴應笑獨醒人。"]'),
('91c9809f-8101-4b8c-8404-0d40c63368dc','舟次魏村阻風','呂頤浩','宋','宋诗','song-poetry','','[]','扁舟深入水雲鄉，浩渺渾疑带遠江。',32,'全唐诗/poet.song.77000.json','["扁舟深入水雲鄉，浩渺渾疑带遠江。", "蓼岸阻風還度日，夕陽依約照篷窗。"]'),
('58863f9d-a8a1-496d-80b8-d2ecd6a2078b','真定城中聞鶯聲方響和賈明仲','呂頤浩','宋','宋诗','song-poetry','','[]','誰家方響聞鶯聲，恰似年時在帝京。',32,'全唐诗/poet.song.77000.json','["誰家方響聞鶯聲，恰似年時在帝京。", "寶馬金鞍芳草路，却教潘鬢二毛生。"]'),
('1ab18130-9063-4dd4-b4ac-829859890bbd','夢室','呂頤浩','宋','宋诗','song-poetry','','[]','丹心憂國夢魂間，祗恐清霄亦未閑。',32,'全唐诗/poet.song.77000.json','["丹心憂國夢魂間，祗恐清霄亦未閑。", "枕上幾回游魏闕，覺來聊且看閩山。"]'),
('22f0fc4f-a8f9-4f9e-823f-c5058e7619d0','蘭室','呂頤浩','宋','宋诗','song-poetry','','[]','秋蘭馥郁有幽香，不謂無人不吐芳。',32,'全唐诗/poet.song.77000.json','["秋蘭馥郁有幽香，不謂無人不吐芳。", "最好移根来一室，試紉幽佩意何長。"]'),
('5246ff99-ff4d-48ef-8ded-78505d473e6e','雙蓮閣','呂頤浩','宋','宋诗','song-poetry','','[]','雙蓮爭秀漾清波，霧卷煙收認兩娥。',32,'全唐诗/poet.song.77000.json','["雙蓮爭秀漾清波，霧卷煙收認兩娥。", "楓落澄江秋欲盡，半池霜倒奈愁何。"]'),
('7e9d0986-949a-4c59-ac44-ccad609bf320','菖蒲澗','呂頤浩','宋','宋诗','song-poetry','','[]','溪蓀得地恣芬芳，三尺揮空劍刃長。',32,'全唐诗/poet.song.77000.json','["溪蓀得地恣芬芳，三尺揮空劍刃長。", "聞道仙人嘗採掇，澗邊栽植對朝陽。"]'),
('c0f6f303-8d23-42fe-a8d2-5ccf7d125587','題臨濟所居','呂頤浩','宋','宋诗','song-poetry','','[]','鳴鐘列鼎心無累，茹糗羮藜樂亦全。',32,'全唐诗/poet.song.77000.json','["鳴鐘列鼎心無累，茹糗羮藜樂亦全。", "解把窮通爲一致，此生何處不超然。"]'),
('fcd5c780-7aed-4b92-9689-2a2d4000320e','襄邑道中贈孫天予子禮三首  其一','呂頤浩','宋','宋诗','song-poetry','','[]','咸平岸下分襟日，襄邑亭前把臂時。',32,'全唐诗/poet.song.77000.json','["咸平岸下分襟日，襄邑亭前把臂時。", "十載光陰驚一夢，塞塵踏盡鬢如絲。"]'),
('e6a5b0e0-6389-4686-8f49-6e1899de0e9c','襄邑道中贈孫天予子禮三首  其二','呂頤浩','宋','宋诗','song-poetry','','[]','霜毛一别各毿毿，興味年来老不堪。',32,'全唐诗/poet.song.77000.json','["霜毛一别各毿毿，興味年来老不堪。", "横槊賦詩休塞北，扁舟垂釣漸江南。"]'),
('c7e4cceb-ce03-4d90-bf9c-83d1a542a0b8','襄邑道中贈孫天予子禮三首  其三','呂頤浩','宋','宋诗','song-poetry','','[]','弟兄交契比雷陳，白首相看意轉親。',32,'全唐诗/poet.song.77000.json','["弟兄交契比雷陳，白首相看意轉親。", "收拾壯懷同老去，江皋他日幸相鄰。"]'),
('52e4c93b-e435-4cc5-af51-53b7046e1b13','圭沼','呂頤浩','宋','宋诗','song-poetry','','[]','鑿沼因方類介圭，雨餘泉石轉增輝。',32,'全唐诗/poet.song.77000.json','["鑿沼因方類介圭，雨餘泉石轉增輝。", "排空恨乏乘風術，去傍滄浪濯我衣。"]'),
('09fd1241-e95d-4fc3-bb3c-4451941594a9','桂齋二首  其一','呂頤浩','宋','宋诗','song-poetry','','[]','雙桂亭亭傍竹齋，窗前會見紫花開。',32,'全唐诗/poet.song.77000.json','["雙桂亭亭傍竹齋，窗前會見紫花開。", "它時釀入椒漿後，香逐和羮滿座來。"]'),
('ade08549-7596-47f8-b6ad-a7764b070c88','桂齋二首  其二','呂頤浩','宋','宋诗','song-poetry','','[]','團團雙桂拂茅齋，虚幌疏櫺盡日開。',32,'全唐诗/poet.song.77000.json','["團團雙桂拂茅齋，虚幌疏櫺盡日開。", "會待高秋風露下，清香飄泛月中來。"]'),
('d53093fa-9ae3-49ac-8e46-499cf9574b39','竹亭','呂頤浩','宋','宋诗','song-poetry','','[]','此君瀟灑綠筠抽，直幹凌雲碧翠浮。',32,'全唐诗/poet.song.77000.json','["此君瀟灑綠筠抽，直幹凌雲碧翠浮。", "想見風枝陪宴坐，囊封草就告嘉猷。"]'),
('6333bfe5-65e2-4c6d-b715-bf25fe516ce8','橘亭','呂頤浩','宋','宋诗','song-poetry','','[]','翠葉田田粲綠雲，黄金苞實露華新。',32,'全唐诗/poet.song.77000.json','["翠葉田田粲綠雲，黄金苞實露華新。", "遶亭雖乏千株廣，不羡當年萬户人。"]'),
('b863364c-3c0b-4cd5-aca7-293d64400259','荔枝亭','呂頤浩','宋','宋诗','song-poetry','','[]','水晶絳雪舊馳名，珍重移來近野亭。',32,'全唐诗/poet.song.77000.json','["水晶絳雪舊馳名，珍重移來近野亭。", "看取薫風炎暑際，丹苞萬顆粲繁星。"]'),
('a9be0843-b9d4-4ea6-aa9c-2c29c41d9493','題汝南縣蒙溪亭二首  其一','呂頤浩','宋','宋诗','song-poetry','','[]','門外行人困鬱蒸，不知蕭寺有溪亭。',32,'全唐诗/poet.song.77000.json','["門外行人困鬱蒸，不知蕭寺有溪亭。", "暫鋪冰簟閑伸展，一枕清風午夢醒。"]'),
('0e1a17f4-1db2-46b4-b4d0-99fbc65f1330','題汝南縣蒙溪亭二首  其二','呂頤浩','宋','宋诗','song-poetry','','[]','暑途白晝倦趨程，月暗泥深夜阻行。',32,'全唐诗/poet.song.77000.json','["暑途白晝倦趨程，月暗泥深夜阻行。", "却羡野僧無一事，布衣蔬飯任平生。"]'),
('989b6fac-319d-4d38-aed8-40387aeb6db4','頃爲河北東路常平廳事後有便坐廳兩檻植竹春時僕别栽新竹去其舊本後二十年脩榦森聳遂成茂林友人郭仲思嘗爲本路提刑寓此廨有書因回信寄一絕','呂頤浩','宋','宋诗','song-poetry','','[]','昔年官守在銅臺，兩檻疏篁手自栽。',32,'全唐诗/poet.song.77000.json','["昔年官守在銅臺，兩檻疏篁手自栽。", "勁節濃陰還在否，清風應爲故人來。"]'),
('c9e3c1c5-a278-4247-a9e1-39d3474333db','次韻沈元用遊天台三首  其一','呂頤浩','宋','宋诗','song-poetry','','[]','出處何勞問大鈞，如公材哭略鋪陳。',64,'全唐诗/poet.song.77000.json','["出處何勞問大鈞，如公材哭略鋪陳。", "談兵玉帳詩書帥，演誥綸闈侍從臣。", "萬疊名山聊寓目，一方仙宅勿藏身。", "中原未復須留念，先入夷門漸入秦。"]'),
('8aea702b-6393-45c4-a40d-195d4fa10424','次韻沈元用遊天台三首  其二','呂頤浩','宋','宋诗','song-poetry','','[]','山居猶不厭山行，石磴欹危步履轅馬。',65,'全唐诗/poet.song.77000.json','["山居猶不厭山行，石磴欹危步履轅馬。", "夾路不聞雙闕在，幽巖應有五芝生。", "春寒未放遷鶯囀，風暖先催布穀鳴。", "我欲營茅留俗駕，無貲誰寄孔方兄。"]'),
('01fd6046-7ba4-4f9b-a59c-a194be8d7695','次韻沈元用遊天台三首  其三','呂頤浩','宋','宋诗','song-poetry','','[]','前麾轉綵陳旗紅，二紀窮邊一夢中。',64,'全唐诗/poet.song.77000.json','["前麾轉綵陳旗紅，二紀窮邊一夢中。", "曾擁琱戈思卻日，屢乘鐵馬聽嘶風。", "誰憐老去三春病，自覺閑來萬慮空。", "滿路落花歸雁後，勿令書疏不相通。"]'),
('80de43f4-cd7f-4481-bc97-c1b99f15c7b0','登巾子山寄懷韓嗣夫','呂頤浩','宋','宋诗','song-poetry','','[]','幾年蹤跡共飛沈，自渡江來幸盍簪。',64,'全唐诗/poet.song.77000.json','["幾年蹤跡共飛沈，自渡江來幸盍簪。", "奉使久違常恨別，閑居無夢不相尋。", "勒功鐘鼎經綸志，混跡漁樵老退心。", "籬菊正開家醸熟，一樽何日得同斟。"]'),
('bc62e375-0768-4e4c-8c33-e6318fa9b713','將至天台馬上口占','呂頤浩','宋','宋诗','song-poetry','','[]','東歸頓覺馬蹄輕，竚望天台景色新。',32,'全唐诗/poet.song.77000.json','["東歸頓覺馬蹄輕，竚望天台景色新。", "遙想故園芳草盛，一番桃李又烘春。"]'),
('07b85e33-cf7d-42e3-95ac-a9294dca37b4','次韻郭傳師寵寄閑居之什','呂頤浩','宋','宋诗','song-poetry','','[]','小隱丹丘郡，安閑世慮空。',48,'全唐诗/poet.song.77000.json','["小隱丹丘郡，安閑世慮空。", "運籌邊閫帥，昭代將家風。", "牙帳霜矛白，賓筵舞袖紅。", "何時同把臂，醉伴釣魚翁。"]'),
('eef26a4c-0bc2-403c-a76b-7dd3d098a622','次韻李德升老堂  其一','呂頤浩','宋','宋诗','song-poetry','','[]','腐儒才術庸庸，祖業安能效太公。',63,'全唐诗/poet.song.77000.json','["腐儒才術庸庸，祖業安能效太公。", "老去退休營小隱，閑來時幸濯清風。", "相從坦率形骸外，投分交遊意氣中。", "衰謝何堪撫鳴劍，夢魂猶擬滅羌戎。"]'),
('d578db18-263d-4ca5-bcbe-2d8c38513a70','次韻李德升老堂  其二','呂頤浩','宋','宋诗','song-poetry','','[]','野堂豈意題佳句，強欲賡酬愧續貂。',64,'全唐诗/poet.song.77000.json','["野堂豈意題佳句，強欲賡酬愧續貂。", "閑適更須馳廄馬，訪臨無惜過溪橋。", "秋風南浦觀垂釣，落日東山伴採樵。", "此樂有時驚自得，泥途何必羨煙霄。"]'),
('76abd0ac-8120-40a9-9f57-7166accdbf04','次綦叔厚韻  其一','呂頤浩','宋','宋诗','song-poetry','','[]','佐時勳業愧先賢，迹退丹丘已二年。',64,'全唐诗/poet.song.77000.json','["佐時勳業愧先賢，迹退丹丘已二年。", "買得石田東郭外，蓋成茅屋北山前。", "長林遠水相縈带，翠岫奇峰更接連。", "多謝朋遊念衰颯，寄題佳句已成編。"]'),
('66828378-87bb-4b50-be38-d4aee35763b8','次綦叔厚韻  其二','呂頤浩','宋','宋诗','song-poetry','','[]','心存魏闕豈能忘，揣分非才合退藏。',64,'全唐诗/poet.song.77000.json','["心存魏闕豈能忘，揣分非才合退藏。", "此日燕休難報國，半生艱險憶垂堂。", "枕戈每嘆身先老，覽鏡常嗟貌不揚。", "每今蘧廬聊偃息，會須恢復返吾鄉。"]'),
('82a73369-3d79-4ffa-acf3-6c00813ca0b8','次石迪功韻  其一','呂頤浩','宋','宋诗','song-poetry','','[]','楓庭累歲玷朝班，老荷宸恩得退閑。',64,'全唐诗/poet.song.77000.json','["楓庭累歲玷朝班，老荷宸恩得退閑。", "櫪馬虺隤休入馭，隴禽衰倦合知還。", "莫辭斂跡歸南畝，幸免移文向北山。", "恢復中原乖素願，夢魂時得到鄉關。"]'),
('93ebf4f5-4f19-4c7f-bc4d-e7471c55496a','次石迪功韻  其二','呂頤浩','宋','宋诗','song-poetry','','[]','丹丘無限好山川，疊翠峰巒插暝煙。',64,'全唐诗/poet.song.77000.json','["丹丘無限好山川，疊翠峰巒插暝煙。", "郊外幽居三歲換，天邊明月幾回圓。", "野堂半隱慵欹枕，健筆題詩思湧泉。", "小圃賸開桃李徑，飛觴同醉待來年。"]'),
('b2ee7776-e4d0-4c8a-a5d8-e1f6145bbf09','次洪成季韻  其一','呂頤浩','宋','宋诗','song-poetry','','[]','壯歲勤勞不自量，退居栽植復何忙。',64,'全唐诗/poet.song.77000.json','["壯歲勤勞不自量，退居栽植復何忙。", "靜思身外功名誤，老覺閑中氣味長。", "雨後羣山千疊翠，春回幽圃百花香。", "農人不識歸休客，載酒相邀入醉鄉。"]'),
('4bc0e395-953c-4a4d-bf63-946db61be048','次洪成季韻  其二','呂頤浩','宋','宋诗','song-poetry','','[]','聖運中興偶幸逢，經邦曾乏古人風。',64,'全唐诗/poet.song.77000.json','["聖運中興偶幸逢，經邦曾乏古人風。", "閉關退處喧囂外，撫劍行吟感慨中。", "尚有素懷思報國，可憐幽夢欲平戎。", "新詩增重林泉價，倍見交情我與公。"]'),
('186398c6-e980-4207-9d14-79ea3a4c213f','次潭州通判范寅秩韻  其一','呂頤浩','宋','宋诗','song-poetry','','[]','胡塵一動隔吾鄉，旋向丹丘筑草堂。',64,'全唐诗/poet.song.77000.json','["胡塵一動隔吾鄉，旋向丹丘筑草堂。", "方效潛魚游河渚，忽隨飛雁到衡陽。", "雨餘南陌千峰翠，春日東郊百草香。", "身在湖湘歸未得，夢魂時到舊居傍。"]'),
('2701f18c-611b-40de-a570-d8c009272f69','次潭州通判范寅秩韻  其二','呂頤浩','宋','宋诗','song-poetry','','[]','經綸無術致時康，何事連年住廟堂。',64,'全唐诗/poet.song.77000.json','["經綸無術致時康，何事連年住廟堂。", "退伴農夫耕曉月，閑陪漁父釣滄浪。", "壯懷衰謝休鳴劍，舊學荒蕪恥面牆。", "別乘意勤貽雅什，續貂深愧不成章。"]'),
('517a3166-bb35-45c8-9bf7-1b1cd08a0fad','次李泰發韻','呂頤浩','宋','宋诗','song-poetry','','[]','東郊半隱繞羣峰，門外涓涓一水通。',64,'全唐诗/poet.song.77000.json','["東郊半隱繞羣峰，門外涓涓一水通。", "再歲依棲忻有幸，十年遭際嘆無功。", "閑心不厭耕南畝，清夢猶思殄北戎。", "看去中原恢復後，麒麟圖畫首膚公。"]'),
('8fe9594f-4351-4040-b421-8662a804b245','次張全真參政韻  其一','呂頤浩','宋','宋诗','song-poetry','','[]','垂老歸休荷聖恩，栽花種竹引兒孫。',64,'全唐诗/poet.song.77000.json','["垂老歸休荷聖恩，栽花種竹引兒孫。", "向來豪健風檣勇，老去光陰渴驥奔。", "往事不勞空咄咄，素懷猶欲濟元元。", "天台山下柴荆路，白首棲遲學灌園。"]'),
('2e8e326f-e550-4bed-8735-b7ab83de68ad','次張全真參政韻  其二','呂頤浩','宋','宋诗','song-poetry','','[]','青郊卜筑傍溪流，菡萏香中繫小舟。',64,'全唐诗/poet.song.77000.json','["青郊卜筑傍溪流，菡萏香中繫小舟。", "脫去簪紳歸畎畝，悟來□釣勝公侯。", "青雲舊好何相厚，白雪新詩爲寵留。", "又指湘潭問行路，一堂風月阻同遊。"]'),
('3a4f8c20-ed0b-41c4-84b2-90de914e73f9','次朱通判敦儒韻  其一','呂頤浩','宋','宋诗','song-poetry','','[]','腐儒奮跡自耕耘，冒玷台衡力不任。',64,'全唐诗/poet.song.77000.json','["腐儒奮跡自耕耘，冒玷台衡力不任。", "版筑作霖乖素願，山雲出岫本無心。", "衰遲向老開三徑，豪邁平時惜寸陰。", "蚤伏詩名壓元白，細看佳句用工深。"]'),
('5211d580-c81c-4b90-ad93-9268dba9e841','次朱通判敦儒韻  其二','呂頤浩','宋','宋诗','song-poetry','','[]','天台山下草堂深，罇酒時倍釣叟傾。',64,'全唐诗/poet.song.77000.json','["天台山下草堂深，罇酒時倍釣叟傾。", "屏跡分甘歸畎畝，放懷誰復羨公卿。", "幽棲幸免牽榮辱，高遁何須隱姓名。", "洛浿詞人通顯後，願來相訪伴山行。"]'),
('2a6190f5-8a41-45a1-ac98-3fd1bb6e60d6','次仇待制韻  其一','呂頤浩','宋','宋诗','song-poetry','','[]','腐儒奮跡自山東，強欲區區效小忠。',64,'全唐诗/poet.song.77000.json','["腐儒奮跡自山東，強欲區區效小忠。", "恢復中原雖有意，翼扶興運悵無功。", "辭榮歸去營三徑，念昔何顔總百工。", "海不揚波邊堠嘯，竚聞飛牘奏膚功。"]'),
('fa92a2ad-03b6-4329-8442-3dad9335ae63','次仇待制韻  其二','呂頤浩','宋','宋诗','song-poetry','','[]','韮違軒陛歸臨海，頗幸棲身田畝間。',64,'全唐诗/poet.song.77000.json','["韮違軒陛歸臨海，頗幸棲身田畝間。", "混跡每尋樵叟伴，放懷常羨釣翁閑。", "君恩深厚司留鑰，野性彷徨戀故山。", "異日公成勳業後，巾車無惜過柴關。"]'),
('cdd92a6e-fe45-4c93-9b51-560707c2261e','次鄭顧道韻  其一','呂頤浩','宋','宋诗','song-poetry','','[]','南郊同賦出郊篇，二紀光陰速箭傳。',64,'全唐诗/poet.song.77000.json','["南郊同賦出郊篇，二紀光陰速箭傳。", "祠館退歸乖素志，帥藩承乏愧前賢。", "羸驅豈願留湖外，清夢時驚到海壖。", "待得秋風歸舊隱，黄雞白酒養衰年。"]'),
('2d08e758-dabc-4107-978e-3b485df9ede5','次鄭顧道韻  其二','呂頤浩','宋','宋诗','song-poetry','','[]','不讀離騷不著書，竹籬環合野人居。',64,'全唐诗/poet.song.77000.json','["不讀離騷不著書，竹籬環合野人居。", "開罇細酌山中酒，掛壁閑看臥雪圖。", "出處似非還似是，宦名如有亦如無。", "故人意厚題佳句，豈爲疏狂鄙接輿。"]'),
('83f56b48-ba4b-4e98-948f-718cbd4c01cd','次韻郭思得之歸德鋪留題  其一','呂頤浩','宋','宋诗','song-poetry','','[]','馬前山色入吟鞭，馬上行人思湧泉。',32,'全唐诗/poet.song.77000.json','["馬前山色入吟鞭，馬上行人思湧泉。", "楓落吳江何足道，好詩今擬謝臨川。"]'),
('d0881d43-e569-47f8-8e69-23f54ef6832c','次韻郭思得之歸德鋪留題  其二','呂頤浩','宋','宋诗','song-poetry','','[]','妙年題筆吐英辭，壯歲該當高度色絲。',33,'全唐诗/poet.song.77000.json','["妙年題筆吐英辭，壯歲該當高度色絲。", "五字七言嫌淺俗，揮毫新製六言詩。"]'),
('e17b4ea4-6df4-4fab-a91a-3bbf9c618e44','次韻郭思得之歸德鋪留題  其三','呂頤浩','宋','宋诗','song-poetry','','[]','故園一別四經秋，倦宦東歸念昔游。',32,'全唐诗/poet.song.77000.json','["故園一別四經秋，倦宦東歸念昔游。", "下馬郵亭開病目，壁間依舊見銀鈎。"]'),
('6a892762-b5a9-49bb-8298-2bf39e96386e','句','呂頤浩','宋','宋诗','song-poetry','','[]','草履便將爲幸舄。',8,'全唐诗/poet.song.77000.json','["草履便將爲幸舄。"]'),
('9058e68b-a409-4e32-adf4-c6658fea82e6','次韻彦平叔見贈','廖剛','宋','宋诗','song-poetry','','[]','千年東序愧囊錐，浪學何生且一歸。',64,'全唐诗/poet.song.77000.json','["千年東序愧囊錐，浪學何生且一歸。", "遠道幾煩黄耳走，故山今謝白雲飛。", "燕游未許安仁里，夢想頻驚在禮闈。", "爭似釣臺飽風月，一谿桃李自霏霏。"]'),
('73bf2787-dfa3-461e-a8a9-02d64d115f38','大學送余適正往洛中就館','廖剛','宋','宋诗','song-poetry','','[]','少小各西東，天涯會兩蓬。',48,'全唐诗/poet.song.77000.json','["少小各西東，天涯會兩蓬。", "相看身未了，欲别意無竆。", "歲晚嵩山雪，天寒洛浦風。", "寂寥倚孤劍，應憶笑言同。"]'),
('a3266844-8d26-4df3-a873-b3bf65b536a5','代祖父次韻酬羅君寶見贈','廖剛','宋','宋诗','song-poetry','','[]','蕭條門巷陋於顔，老去青春僅得閑。',64,'全唐诗/poet.song.77000.json','["蕭條門巷陋於顔，老去青春僅得閑。", "心畫傳家無計筞，手談留客謾機關。", "靜思往事千年上，俯歎勞生一夢間。", "多謝光臨無别意，爲聞流水與高山。"]'),
('8c93cbe9-978b-44ed-a47d-5c016ecc3843','次韻陳無傷春日書事','廖剛','宋','宋诗','song-poetry','','[]','百草千花巧趁春，愛春何獨水邊人。',64,'全唐诗/poet.song.77000.json','["百草千花巧趁春，愛春何獨水邊人。", "青門紫陌酒旗颺，麗日和風天氣新。", "白玉少年長带珮，紅蕖遊女小腰身。", "自憐慣作金明客，坐對閑窗滿席塵。"]'),
('d10e9501-283a-4e4e-85e1-90c0cce6d5e6','次韻張敏叔江南僧舍送春之什','廖剛','宋','宋诗','song-poetry','','[]','使華綵旆明春江，江邊佛國遊清涼。',64,'全唐诗/poet.song.77000.json','["使華綵旆明春江，江邊佛國遊清涼。", "柔桑菀菀絲成蔭，落花寂寂紅餘香。", "人間節物易流轉，獨有日月壺中長。", "高懽應笑杜陵客，典衣沽酒留風光。"]'),
('936735d0-b5c0-495b-b733-040eca8711f1','題丁樂道分翠軒','廖剛','宋','宋诗','song-poetry','','[]','十畝清陰隔短牆，幽香端許借餘光。',64,'全唐诗/poet.song.77000.json','["十畝清陰隔短牆，幽香端許借餘光。", "脩篁戛玉亂垂影，佳木屯雲巧著行。", "隱几助成春草夢，卷簾饒占比窗涼。", "誰知靖節心源冷，獨眄庭柯興味長。"]'),
('ab12a298-7393-4d9d-afde-a717d3b813e4','題諸宫  其一','廖剛','宋','宋诗','song-poetry','','[]','燕子無情語亦稀，春風池沼自漣漪。',32,'全唐诗/poet.song.77000.json','["燕子無情語亦稀，春風池沼自漣漪。", "當年勝事歸何許，苔沒龜趺有舊碑。"]'),
('825172bb-3efb-4bb2-bb73-26f0fc8a1f14','題諸宫  其二','廖剛','宋','宋诗','song-poetry','','[]','畫橋紅去卷蛾眉，臺榭遺蹤草樹迷。',32,'全唐诗/poet.song.77000.json','["畫橋紅去卷蛾眉，臺榭遺蹤草樹迷。", "猶有天然無限意，一池春水浴鳬鷖。"]'),
('48aee0ac-0a0f-438a-bf90-d4cb3d5e329e','題諸宫  其三','廖剛','宋','宋诗','song-poetry','','[]','蔓草春深綠更齊，玉鞭何處選芳菲。',32,'全唐诗/poet.song.77000.json','["蔓草春深綠更齊，玉鞭何處選芳菲。", "舊時錦綉叢中蜨，却傍疏籬野菜飛。"]'),
('74778d43-8247-4377-afe3-2d88cca513e4','次韻和陳幾叟苦雨','廖剛','宋','宋诗','song-poetry','','[]','雲霧陰陰閣太虚，雨餘蛙蚓上階除。',32,'全唐诗/poet.song.77000.json','["雲霧陰陰閣太虚，雨餘蛙蚓上階除。", "山頽井塌應無奈，大有人愁化作魚。"]'),
('d392ba04-56cc-4bea-9f26-ec6342769d56','題楊子光雙溪閣','廖剛','宋','宋诗','song-poetry','','[]','倚天華棟俯長洲，渺渺雙溪一檻秋。',64,'全唐诗/poet.song.77000.json','["倚天華棟俯長洲，渺渺雙溪一檻秋。", "匹馬問津迷去客，亂帆分港競歸舟。", "花飄兩洞紅交浪，影落三山翠合流。", "清夜鳴榔何處曲，冷光平泛玉簾鈎。"]'),
('42ebcc33-9d70-4b9f-9125-19ec21264f14','題胡器之鐔溪閣','廖剛','宋','宋诗','song-poetry','','[]','龍津劍窟古南州，閣勢横空占上流。',64,'全唐诗/poet.song.77000.json','["龍津劍窟古南州，閣勢横空占上流。", "山色鎮留春色在，水光長带寶光浮。", "風檐綠篠寒珠箔，雨岸紅蕖隱釣舟。", "祗恐楓宸促歸覲，未容瀟灑老滄洲。"]'),
('13451f67-e262-4ce6-88af-2cbfc273ad29','題賢女鋪','廖剛','宋','宋诗','song-poetry','','[]','世上男兒半可羞，貞姿誰欲遣隨流。',64,'全唐诗/poet.song.77000.json','["世上男兒半可羞，貞姿誰欲遣隨流。", "百年負愧生何益，一諾難酬死即休。", "明月碧溪長共潔，孤雲落日自含愁。", "懸知萬古悲行客，不待亭皋木葉秋。"]'),
('c8f253e8-2bdb-4a99-aef6-6c45464ded43','次韻侯思孺席間作','廖剛','宋','宋诗','song-poetry','','[]','微雲過疏雨，一洗塵土昏。',96,'全唐诗/poet.song.77000.json','["微雲過疏雨，一洗塵土昏。", "潛行德幽寓，隱約桃源村。", "須臾勝士集，氣類非權門。", "圖史恣娛目，琴碁聊侑樽。", "豈無肴炙珍，憶鱸偏薦蓴。", "大笑屋瓦震，雄辨江濤翻。", "却愁賢主人，早晚東南奔。", "誰與識我輩，咄哉非汝髠。"]'),
('7ad31fee-8b0c-48d0-9a02-c63ff8e0f6b8','次韻酬王元衷相過夜話次日見寄','廖剛','宋','宋诗','song-poetry','','[]','短檠移爝光，敗席掃蠆蜇。',48,'全唐诗/poet.song.77000.json','["短檠移爝光，敗席掃蠆蜇。", "軒昂僅容膝，良媿生事拙。", "妙語契深心，澄渾皎寒月。", "何當日相尋，尚陋温伯雪。"]'),
('4671922c-2bf5-44f1-a0d3-50e388ac954b','虔州送知府石舜弼吏部二首  其一','廖剛','宋','宋诗','song-poetry','','[]','風流萬石有孫傳，偉望孤標拔俊躔。',64,'全唐诗/poet.song.77000.json','["風流萬石有孫傳，偉望孤標拔俊躔。", "鳯闕翺翔綿二紀，虎城留滯肯三年。", "龔黄術業今誰比，皋呂章程舊獨賢。", "政恐君王念耆碩，未教長作洞中仙。"]'),
('106d6065-7ef5-4dfe-9e4e-aee6675bb628','虔州送知府石舜弼吏部二首  其二','廖剛','宋','宋诗','song-poetry','','[]','朅來臨撫未朞年，五袴讙謡已藹然。',64,'全唐诗/poet.song.77000.json','["朅來臨撫未朞年，五袴讙謡已藹然。", "公道直堪平贑石，清風那用挹廉泉。", "飛帆便恐迷三島，緩轡聊須選一錢。", "最有後車湖上客，夢隨旌旆作神仙。"]'),
('cd46095e-5be4-4f2d-80a4-7544c63448ef','月波樓上呈知府檢討','廖剛','宋','宋诗','song-poetry','','[]','月波自昔騰佳名，練光一带縈寒城。',326,'全唐诗/poet.song.77000.json','["月波自昔騰佳名，練光一带縈寒城。", "摧風剥雨歲月古，拊檻足慄憂頽傾。", "恍然宏麗驚幻化，雲舒霞爛飛雕甍。", "烟收霧歛霽色净，菱花玉女新粧成。", "瑠璃萬傾浸蟾腹，星河帖底游魚明。", "榮光爽氣長不夜，但覺零露涓涓清。", "彩虹飛跨度别島，縹緲嬉笑歸蓬瀛。", "紅蕖照水翠蓋合，往往輝映雙華旌。", "廣寒宫闕倘未到，絕致惟欲輕題評。", "君不見錢塘有美東南冠，覆壓湖山美輪奐。", "海門日日子胥潮，百里青烟付朝爨。", "又不見松江起尺跨垂虹，騎鯨直下窺龍宫。", "危欄欲憑駭神觀，萬葉出沒風濤中。", "月波境對了無此，一色涵空天共水。", "圓明湛靜趣已高，不與二景爭雄豪。", "猗歟興廢物有數，高韻庾公今日遇。", "治荒斥陋意所便，荷鍤去趨舞襦袴。", "西園花木頓生春，結客從今朝與暮。", "嘉禾爲郡亦云久，壯觀從來未曾有。", "月波解與去思長，千古風流端不朽。"]'),
('cea944af-b3c7-4f03-b27b-59888a82584c','送黄秀實著作赴單父任','廖剛','宋','宋诗','song-poetry','','[]','憶昔負笈遊虞庠，三千縫掖紛袍霜。',368,'全唐诗/poet.song.77000.json','["憶昔負笈遊虞庠，三千縫掖紛袍霜。", "英姿鋭氣磨干將，凌雲薄漢爭翺翔。", "君時捧書自閩鄉，賈生十八驚洛陽。", "南宫我適同廣場，邂逅愚智俱忘羊。", "低回十載燈燭光，纖鱗壁水追洋洋。", "憐君兄弟雙鳯皇，鄧林秀出凡楩樟。", "才名籍籍日以香，誰者不識江夏黄。", "登籍還許聯龍章，米糠初未精簸揚。", "須臾綠驥馳康莊，瑤池下澤殊行藏。", "西清椽筆金玉相，揚鞭緩珮鵷鷺行。", "丘明遷固與頡頏，汗流曄壽走且僵。", "文奎忽度南斗傍，江湖洗耳聽鳴榔。", "相逢一笑百念亡，玉自輝潔蘭仍芳。", "元經寂寞誰問楊，逃空我幸論肺腸。", "蛟龍蟠蜇豈可常，賜環長恐成參商。", "春風三月鶯燕忙，橋飛柳絮隨風狂。", "修補冉冉將征艎，别離安得情無傷。", "如君知音滿廟堂，塵沙肯使埋珪璋。", "鵬程九萬詎易量，從今拭目看騰驤。", "我慚百事無一長，獨有疏懶勝嵇康。", "功名老大空激昂，那能俯仰巡門牆。", "艱難辛苦亦備嘗，濯纓早晚尋滄浪。", "與君後會何渺茫，江魚塞鴈無相忘。"]'),
('5ef5953b-923f-4544-9055-6f558014a279','次韻劉天常赴郡會有作  其一','廖剛','宋','宋诗','song-poetry','','[]','雨蕚煙梢恰半春，九華峰翠綺筵陳。',64,'全唐诗/poet.song.77000.json','["雨蕚煙梢恰半春，九華峰翠綺筵陳。", "花香暗逐金蓮步，燭影潛交玉兔輪。", "青鳥不傳言外意，紫雲應識醉中真。", "鳴珂擁戶蓬壺夜，想見愁看撤舞茵。"]'),
('0a9023d8-d52d-41fa-8736-f3a257b273ca','次韻劉天常赴郡會有作  其二','廖剛','宋','宋诗','song-poetry','','[]','百草千花巧趁春，曲欄幽徑總鋪陳。',64,'全唐诗/poet.song.77000.json','["百草千花巧趁春，曲欄幽徑總鋪陳。", "舞腰盡欲看回雪，詩匠誰當斷斵輪。", "難把星波渾作事，須知簧語有非真。", "何如玉鐙歸來晚，紅袖爭扶入錦茵。"]'),
('41e6f71b-629d-4412-a6e0-4a0926ec4274','次韻酬羅嚴秀才見贈','廖剛','宋','宋诗','song-poetry','','[]','漫士誰當識姓名，朅來微宦稱單平。',64,'全唐诗/poet.song.77000.json','["漫士誰當識姓名，朅來微宦稱單平。", "卑栖已分軒無過，高誼良慙蓋始傾。", "負米未容辭五斗，屠羊安得羡三旌。", "夫君信欲光蓬陋，浪擲新詩一羽輕。"]'),
('b3e4e6f9-97af-43dd-bbe6-0d4d0bd660d0','題朱池驛','廖剛','宋','宋诗','song-poetry','','[]','道行妻子爾胡顔，閭巷封侯亦不難。',32,'全唐诗/poet.song.77000.json','["道行妻子爾胡顔，閭巷封侯亦不難。", "直使榮華傾後世，朱池終媿近嚴灘。"]'),
('40956774-169f-44cb-a716-bd64003386b2','别本覺老凈悟大師偈','廖剛','宋','宋诗','song-poetry','','[]','過客小長盧，馨香滿道途。',24,'全唐诗/poet.song.77000.json','["過客小長盧，馨香滿道途。", "我來聞好語，歸棹舞新蒲。"]'),
('20fe5f93-4ee9-4a8e-8ae1-8dfc031a77a3','道源朝奉重陽後以詩招賞菊走筆答之','廖剛','宋','宋诗','song-poetry','','[]','欲摘金英露濕衣，暗香還逐曉風微。',32,'全唐诗/poet.song.77000.json','["欲摘金英露濕衣，暗香還逐曉風微。", "仙翁可解追時節，心想何妨舉世非。"]'),
('25b7cda8-bf05-4f58-a3d0-5fe101f41d99','送敏叔祠部赴廬州','廖剛','宋','宋诗','song-poetry','','[]','平生才業笑時髦，唾手功名晚未遭。',64,'全唐诗/poet.song.77000.json','["平生才業笑時髦，唾手功名晚未遭。", "白髪早憐西日遠，紅旗還值北風高。", "定知國士逢青眼，會遣鄉儇賣寶刀。", "獨有失依門下客，夢隨仙舸泛江濤。"]'),
('3f864246-9552-47ff-9bb6-e7d9e3c2caa6','鄭彦敏以詩惠小女作紅黄雪牡丹次韻答之','廖剛','宋','宋诗','song-poetry','','[]','玉色誰將巧染丹，粧成嬌脆學應難。',32,'全唐诗/poet.song.77000.json','["玉色誰將巧染丹，粧成嬌脆學應難。", "謝家兒女空才思，不似枝頭許細看。"]'),
('d0f8fe18-5943-464e-bf49-946c5933720d','舟次嚴子陵釣臺當時出舟中所作一篇依韻和之','廖剛','宋','宋诗','song-poetry','','[]','彌月鏁蕭寺，百念損心曲。',96,'全唐诗/poet.song.77000.json','["彌月鏁蕭寺，百念損心曲。", "開門春山青，舟備春漲綠。", "回首戲事空，白黑掃枰局。", "却憐剔銀燈，手纖腰素束。", "勸我金屈巵，陽春詞非俗。", "歸心千里馳，客飲一笑足。", "况我富朋簪，連檣泛寒玉。", "夜泊子陵灘，清輝耿相燭。"]'),
('f76e8de0-4504-49b0-82de-35b785dd1c11','用當時韻題釣臺呈諸友','廖剛','宋','宋诗','song-poetry','','[]','釣臺兀層巔，釣鈎應不曲。',96,'全唐诗/poet.song.77000.json','["釣臺兀層巔，釣鈎應不曲。", "豈曰真釣魚，愛此千頃淥。", "戰爭如奕棋，光武偶贏局。", "先生靜觀之，未肯带一束。", "紛紛揔兒戲，齪齪付鄙俗。", "萬乘等故人，醉臥加以足。", "誰能棄天真，俯仰矜執玉。", "亘古纔一人，卓哉理深燭。"]'),
('40c5e975-4725-43f6-8162-fa35f23be6a7','衢州試院次韻盛當時官長寵示二絕句  其一','廖剛','宋','宋诗','song-poetry','','[]','洗眼貪看幼婦詞，玉人空遣暗相思。',32,'全唐诗/poet.song.77000.json','["洗眼貪看幼婦詞，玉人空遣暗相思。", "憑誰爲報歸期近，趁得桃花爛熳時。"]'),
('ba69339d-8293-45b5-9fba-48afed2e1f79','衢州試院次韻盛當時官長寵示二絕句  其二','廖剛','宋','宋诗','song-poetry','','["\u897f\u6e56"]','揮麈論天幸此同，酒盃共笑夜爐紅。',32,'全唐诗/poet.song.77000.json','["揮麈論天幸此同，酒盃共笑夜爐紅。", "共須速了公家事，相逐西湖泛暖風。"]'),
('05d51cc0-26c8-483f-a16e-e788ab6234e0','次韻當時官長院中三絕句  其一','廖剛','宋','宋诗','song-poetry','','[]','柳嫩風摧綠，花嬌雨妬香。',24,'全唐诗/poet.song.77000.json','["柳嫩風摧綠，花嬌雨妬香。", "欲憑羲馭緩，莫遣負韶光。"]'),
('c7d57067-f943-4696-a757-655f379eb865','次韻當時官長院中三絕句  其二','廖剛','宋','宋诗','song-poetry','','[]','檐鵲矜巢噪，桑鳩喚婦鳴。',24,'全唐诗/poet.song.77000.json','["檐鵲矜巢噪，桑鳩喚婦鳴。", "客愁饒餖飣，牆外賣花聲。"]'),
('e805d78e-f2a2-48ea-aa76-e48e79548b3d','次韻當時官長院中三絕句  其三','廖剛','宋','宋诗','song-poetry','','[]','畫舸便春漲，驕驄惜障泥。',24,'全唐诗/poet.song.77000.json','["畫舸便春漲，驕驄惜障泥。", "歸歟何所愜，烟柳子陵溪。"]'),
('5a65b40f-c52b-4926-9a1f-fa044e7982f8','戲呈吳江令張明達','廖剛','宋','宋诗','song-poetry','','[]','陸羽甘泉冷似冰，松江因向令賢明。',32,'全唐诗/poet.song.77000.json','["陸羽甘泉冷似冰，松江因向令賢明。", "要須更取中橋水，欲看三君子鬭清。"]'),
('aa7d7642-46e0-4b24-af6e-9b0268aac63a','丙申春貼子八首  其一','廖剛','宋','宋诗','song-poetry','','[]','北斗寅初建，東郊氣乍迎。',24,'全唐诗/poet.song.77000.json','["北斗寅初建，東郊氣乍迎。", "土牛敦歲事，綵燕動春情。"]'),
('62e0d853-7ce0-4873-a0e2-572fcf8d19f4','丙申春貼子八首  其二','廖剛','宋','宋诗','song-poetry','','[]','簫皷迎春至，烟雰向曉開。',24,'全唐诗/poet.song.77000.json','["簫皷迎春至，烟雰向曉開。", "棠陰聽訟罷，菖葉勸畊來。"]'),
('d42a999c-fa53-42d4-94e0-4186d371f78d','丙申春貼子八首  其三','廖剛','宋','宋诗','song-poetry','','[]','令節年光換，和風春令行。',24,'全唐诗/poet.song.77000.json','["令節年光換，和風春令行。", "野塘初變柳，幽谷未遷鶯。"]'),
('64ccc146-2f3f-4d84-9f80-3e8246ec26ee','丙申春貼子八首  其四','廖剛','宋','宋诗','song-poetry','','[]','土牛分盡綵泥香，動地歡聲入壽觴。',32,'全唐诗/poet.song.77000.json','["土牛分盡綵泥香，動地歡聲入壽觴。", "倍覺今年春意好，上元燈火鬭風光。"]'),
('6e1d881e-e4e3-4e0d-b880-5f70edfa9b65','丙申春貼子八首  其五','廖剛','宋','宋诗','song-poetry','','[]','碧波樓下銀塘晚，麗日亭前瑤草新。',32,'全唐诗/poet.song.77000.json','["碧波樓下銀塘晚，麗日亭前瑤草新。", "和氣滿城催燕樂，風流太守最宜春。"]'),
('0fcfa7e1-6492-4d4b-a051-0f51d533776f','丙申春貼子八首  其六','廖剛','宋','宋诗','song-poetry','','[]','暖風漸綠池塘面，和氣先薫花草心。',32,'全唐诗/poet.song.77000.json','["暖風漸綠池塘面，和氣先薫花草心。", "欲識春來何處好，曲屏新稱畫堂深。"]'),
('a7b18684-aada-4237-8f1e-857a5c1cbbe6','丙申春貼子八首  其七','廖剛','宋','宋诗','song-poetry','','[]','繡閣佳人拂曉粧，爭持春酒賀春陽。',32,'全唐诗/poet.song.77000.json','["繡閣佳人拂曉粧，爭持春酒賀春陽。", "鬂雲總把梅花插，簾幙春風一種香。"]'),
('a69c5b69-fb6d-461b-8911-c9cd786ccbc8','丙申春貼子八首  其八','廖剛','宋','宋诗','song-poetry','','[]','金裁寶勝翻珠髻，雲染華箋貼繡楣。',32,'全唐诗/poet.song.77000.json','["金裁寶勝翻珠髻，雲染華箋貼繡楣。", "庭户春歸何所覺，暖風吹雪下瓊枝。"]'),
('b1c5a799-a63c-4c15-a12e-434ac9b7c52b','賀知府毛檢討生辰','廖剛','宋','宋诗','song-poetry','','[]','祥光曾射斗牛墟，想見當年吉慶符。',128,'全唐诗/poet.song.77000.json','["祥光曾射斗牛墟，想見當年吉慶符。", "天遣麒麟來玉户，史占昴宿下雲衢。", "揚鞭禁省聲華籍，擁旆侯籓治狀殊。", "妙世文章燕大手，致君才業魯真儒。", "英姿冠玉使揮麈，雅座生風謝舞雩。", "寒士幾人懷衍律，窮民比屋頌廉襦。", "寶燻共獻詩千首，煩暑潛消酒百壺。", "珍重公歸廟堂後，老人長照帝王都。"]'),
('e590c514-2d89-4c40-843b-8ae150a57c9c','賀王通判生辰','廖剛','宋','宋诗','song-poetry','','[]','銀河光動昴星躔，妙歲聲華已赫然。',64,'全唐诗/poet.song.77000.json','["銀河光動昴星躔，妙歲聲華已赫然。", "青璅雄文天外鳳，白虹豪氣飲中仙。", "難攀驥足騰千里，曾許驪珠探九淵。", "會看黑頭丹衮貴，伊周勳業老彭年。"]'),
('f067b348-76ea-4ac6-b4b8-ecabb31e49ce','送毛擇民','廖剛','宋','宋诗','song-poetry','','[]','霧纏曉色風冷冷，滄波漾縠旌旗明。',192,'全唐诗/poet.song.77000.json','["霧纏曉色風冷冷，滄波漾縠旌旗明。", "畫舩疊皷不可挽，一城攘攘心爲傾。", "城中老人爲余語，我公道來能幾許。", "朝家借不恤吾人，以我公歸欲焉處。", "惟公立德清而通，惟公御下嚴而容。", "文章光彩瑩萬古，二十八宿羅心胸。", "高標不受俗塵涴，唾手功名猶坎軻。", "恩深謾結千里愁，見晚端聞九重賀。", "官僚有士轅下駒，感激剪拂銘肌膚。", "瑤池一夕看奔逸，惆悵未易追亨途。", "雲龍風虎倐際會，回首可須論治最。", "要將椽筆壓西清，不負聲名燕許大。"]');
